// In a real app, this would use paper.js or maker.js.
// Here we simulate the logic for calculating bender paths and perimeters.

import { FONT_LIBRARY } from '../data/fonts/index';
import { FontData } from '../data/fonts/types';

// New Helper: Get character width ratio
const getCharWidthRatio = (char: string, font: FontData): number => {
  const upperChar = char.toUpperCase();
  // Check specific table, then fallback
  return font.metrics.chars[upperChar] || font.metrics.defaultRatio;
};

// Helper: robustly get font or default
const getFontOrFallback = (fontName: string): FontData => {
    return FONT_LIBRARY[fontName] || Object.values(FONT_LIBRARY)[0];
};

export const calculatePreciseLineWidth = (line: string, height: number, fontName: string): number => {
    const font = getFontOrFallback(fontName);
    let width = 0;
    for (let i = 0; i < line.length; i++) {
        width += height * getCharWidthRatio(line[i], font);
    }
    // Add simple kerning estimate (5% of height per character gap)
    if (line.length > 1) {
        width += (line.length - 1) * (height * 0.05); 
    }
    return width;
};

// Calculate width based on font and text content
export const calculateTotalWidth = (lines: string[], height: number, fontName: string): number => {
  let maxWidth = 0;
  lines.forEach(line => {
    if(!line) return;
    const lineWidth = calculatePreciseLineWidth(line, height, fontName);
    if (lineWidth > maxWidth) maxWidth = lineWidth;
  });
  return Math.ceil(maxWidth);
};

// New Helper: Calculate Raceway Length based on Tuck
// Raceway should start at the horizontal CENTER of the first letter
// And end at the horizontal CENTER of the last letter
export const calculateRacewayTuckLength = (line: string, height: number, fontName: string): number => {
    if (line.length === 0) return 0;
    const font = getFontOrFallback(fontName);

    // 1. Calculate Full Visual Width
    const totalWidth = calculatePreciseLineWidth(line, height, fontName);

    // 2. Get Width of First and Last characters
    const firstCharW = height * getCharWidthRatio(line[0], font);
    const lastCharW = height * getCharWidthRatio(line[line.length-1], font);

    // 3. Raceway Length = Total Width - Half First - Half Last
    // This effectively places the start point at center of First, and end point at center of Last
    const rwLen = totalWidth - (firstCharW / 2) - (lastCharW / 2);

    return Math.max(height, rwLen); // Ensure it's at least as wide as height (sanity check)
};

export const generateBenderPath = (text: string, height: number): string => {
  return `M0,0 L${height * 0.2},${height} L${height * 0.5},0 L${height * 0.8},${height} L${height},0 (Path for ${text})`;
};

export const calculatePerimeter = (lines: string[], height: number): number => {
  const charWidth = height * 0.6;
  const estimatedPerChar = (height * 2) + (charWidth * 2);
  let totalChars = 0;
  lines.forEach(l => totalChars += l.length);
  return totalChars * estimatedPerChar;
};

export const calculateSheetsNeeded = (lines: string[], height: number): number => {
  // 4x8 Sheet = 4608 sq inches
  const sheetArea = 48 * 96;

  // Estimate nesting area (box bounding + 10% waste)
  const areaPerChar = (height * (height * 0.75)) * 1.1;
  let totalChars = 0;
  lines.forEach(l => totalChars += l.length);

  const totalArea = totalChars * areaPerChar;
  return Math.max(1, Math.ceil(totalArea / sheetArea));
};

export const calculateLEDModules = (lines: string[], height: number): number => {
  // Logic: Minimum 2 modules. Add 1 module for every 6" over 12" height.
  // Base: 12" height = 2 modules. 18" = 3 modules. 24" = 4 modules.
  const extraHeight = Math.max(0, height - 12);
  const additionalModules = Math.ceil(extraHeight / 6);
  const modulesPerLetter = 2 + additionalModules;

  let totalChars = 0;
  lines.forEach(l => totalChars += l.length);

  return totalChars * modulesPerLetter;
};

export const checkSeamRequired = (width: number, height: number): string | null => {
  if (width > 120) {
    return "WARNING: Raceway exceeds 120\". Splicing required.";
  }
  return null;
};

import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  // Robust Fallback: If config.fontFamily is not found, use the first available font in the library
  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];

  // Pass the raw font object (or URL) to Text3D
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  // Use Custom Hook for Base Materials
  const materials = useSignMaterials(config, ledIntensity, shadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  let mountZ = 0; 
  if (config.mount === MountType.RACEWAY) {
    mountZ = racewayD; 
  } else if (config.mount === MountType.DIRECT) {
    mountZ = config.dimensions.standoff || 0;
  }

  // Glow Logic (Local to Renderer as it depends on geometry)
  const baseGlowOpacity = (ledIntensity / 5) * 0.5;
  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  const params1 = getGlowParams(config.mount === MountType.RACEWAY ? 0.2 : mountZ);
  const params2 = getGlowParams(mountZ);

  // Memoize glow mats
  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, stencilRef: 1, stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, stencilZFail: THREE.KeepStencilOp, stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const zOffset1 = config.mount === MountType.RACEWAY ? -mountZ + racewayD + 0.05 : -mountZ + 0.05; 
  const zOffset2 = -mountZ + 0.05;

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            // Pass fontSource (which can be JSON object) instead of fontUrl
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={0}
            isHalo={isHalo}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={shadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};

import React from 'react';
import { SignConfig, MountType, IlluminationType } from '../../types';
import { TRIM_CAP_COLORS, RETURN_COLORS, PAINT_COLORS, VINYL_SERIES, FONT_LIBRARY } from '../../constants';
import { generateBlueprintSVG } from '../../services/blueprintExporter'; // Import the exporter
import { Printer } from 'lucide-react';

// Light Blue Technical Color
const DIM_COLOR = "#3b82f6";

// Helper to look up Hex codes for swatches
const getHex = (name: string, collection: {name: string, hex: string}[]) => {
  const found = collection.find(c => c.name === name);
  return found ? found.hex : '#cccccc';
};
const getVinylHex = (series: string, name: string) => {
  const collection = VINYL_SERIES[series as keyof typeof VINYL_SERIES];
  if(!collection) return '#cccccc';
  return getHex(name, collection);
};

// Compact Color Swatch
const ColorSwatch = ({ label, color, subText }: { label: string, color: string, subText: string }) => (
  <div className="flex flex-col w-20">
    <div className="w-full h-6 border border-slate-300 shadow-sm mb-1" style={{ backgroundColor: color }}></div>
    <div className="text-[9px] font-bold text-slate-900 uppercase leading-none truncate">{label}</div>
    <div className="text-[8px] text-slate-500 leading-none truncate" title={subText}>{subText}</div>
  </div>
);

// Professional Drafting Dimension Line Component
const DimensionLine: React.FC<{
  x1: number; y1: number;
  x2: number; y2: number;
  offset: number; // Distance from object line to dimension line
  label: string;
  color?: string;
  fontSize?: number;
  scale?: number; // Scaling factor for visual consistency across different views
  textOffset?: number; // Perpendicular offset for text from the dimension line
}> = ({ 
  x1, y1, x2, y2, 
  offset, label, 
  color = DIM_COLOR, 
  fontSize = 12, 
  scale = 1,
  textOffset = 0 
}) => { 

  const sFontSize = fontSize * scale;
  const sStroke = 1 * scale; 
  const sGap = 5 * scale;
  const sExt = 8 * scale;
  const sTextOffset = textOffset * scale;

  // Determine if vertical or horizontal based on coordinates
  const isVertical = Math.abs(x1 - x2) < 0.1;

  // Calculate Start/End of Extension Lines
  const ex1_start_x = isVertical ? x1 + (offset > 0 ? sGap : -sGap) : x1;
  const ex1_start_y = isVertical ? y1 : y1 + (offset > 0 ? sGap : -sGap);

  const dim_x1 = isVertical ? x1 + offset : x1;
  const dim_y1 = isVertical ? y1 : y1 + offset;
  const dim_x2 = isVertical ? x2 + offset : x2;
  const dim_y2 = isVertical ? y2 : y2 + offset;

  const ex1_end_x = isVertical ? dim_x1 + (offset > 0 ? sExt : -sExt) : x1;
  const ex1_end_y = isVertical ? y1 : dim_y1 + (offset > 0 ? sExt : -sExt);

  const ex2_start_x = isVertical ? x2 + (offset > 0 ? sGap : -sGap) : x2;
  const ex2_start_y = isVertical ? y2 : y2 + (offset > 0 ? sGap : -sGap);

  const ex2_end_x = isVertical ? dim_x2 + (offset > 0 ? sExt : -sExt) : x2;
  const ex2_end_y = isVertical ? y2 : dim_y2 + (offset > 0 ? sExt : -sExt);

  // Text Placement
  const midX = (dim_x1 + dim_x2) / 2;
  const midY = (dim_y1 + dim_y2) / 2;

  let tX, tY;

  if (isVertical) {
      const dir = offset >= 0 ? 1 : -1;
      tX = midX + (sTextOffset * dir);
      tY = midY;
  } else {
      const dir = offset >= 0 ? 1 : -1;
      tX = midX;
      tY = midY + (sTextOffset * dir);
  }

  const rotation = isVertical ? -90 : 0;

  return (
    <g>
       {/* Extension Lines */}
       <line x1={ex1_start_x} y1={ex1_start_y} x2={ex1_end_x} y2={ex1_end_y} stroke={color} strokeWidth={sStroke} />
       <line x1={ex2_start_x} y1={ex2_start_y} x2={ex2_end_x} y2={ex2_end_y} stroke={color} strokeWidth={sStroke} />

       {/* Main Dimension Line */}
       <line 
          x1={dim_x1} y1={dim_y1} x2={dim_x2} y2={dim_y2} 
          stroke={color} 
          strokeWidth={sStroke} 
          markerStart={`url(#arrow-start-blue)`} 
          markerEnd={`url(#arrow-end-blue)`} 
        />

       {/* Text background for readability */}
       <rect 
          x={tX - (label.length * sFontSize * 0.3)} 
          y={tY - (sFontSize * 0.6)} 
          width={label.length * sFontSize * 0.6} 
          height={sFontSize * 1.2} 
          fill="white" 
          opacity="0.9"
          transform={`rotate(${rotation}, ${tX}, ${tY})`}
       />

       <text 
          x={tX} 
          y={tY}
          dy="0.32em"
          transform={`rotate(${rotation}, ${tX}, ${tY})`}
          textAnchor="middle"
          dominantBaseline="middle"
          fontSize={sFontSize}
          fill={color}
          fontWeight="normal"
          fontFamily="ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif"
       >
         {label}
       </text>
    </g>
  );
};

// --- Helper for Text Wrapping ---
const wrapText = (text: string, maxWidth: number, fontSize: number): string[] => {
    const words = text.split(' ');
    const lines: string[] = [];
    let currentLine = words[0];

    // Approx char width ~0.6em
    const charWidth = fontSize * 0.6;

    for (let i = 1; i < words.length; i++) {
        const word = words[i];
        const width = (currentLine.length + 1 + word.length) * charWidth;
        if (width < maxWidth) {
            currentLine += " " + word;
        } else {
            lines.push(currentLine);
            currentLine = word;
        }
    }
    lines.push(currentLine);
    return lines;
};

export const BlueprintView: React.FC<{ config: SignConfig }> = ({ config }) => {

  // Robust Fallback
  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const widthFactor = selectedFont.widthFactor;
  const cssFamily = selectedFont.cssFamily || "sans-serif";
  const cssWeight = selectedFont.cssWeight || "normal";

  const letterHeight = config.dimensions.height;
  const letterDepth = config.dimensions.depth;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);

  // --- WIDTH CALCULATION (Text vs Raceway) ---
  let maxLineWidth = 0;

  config.lines.forEach((line, idx) => {
    if (!line) return;
    const textW = line.length * (letterHeight * widthFactor);
    let rowW = textW;

    // Check Raceway Length if applicable
    if (config.mount === MountType.RACEWAY) {
        // Since we are syncing 3D measurements back to config, we trust the array value
        const rwLen = config.dimensions.racewayLengths[idx] || textW;
        // If raceway is wider than text, the dimension line should span the raceway
        if (rwLen > rowW) rowW = rwLen;
    }
    if (rowW > maxLineWidth) maxLineWidth = rowW;
  });

  const drawingTotalWidth = Math.max(maxLineWidth, config.dimensions.calculatedWidth);
  const numLines = config.lines.filter(l => l).length;
  // Total Height of Sign Assembly
  const signAssemblyHeight = (numLines * letterHeight) + ((numLines - 1) * rowGap); 

  const racewayHeight = 6;
  const racewayDepth = 4;

  const viewportPadding = 48;
  const viewBoxWidth = drawingTotalWidth + (viewportPadding * 2);
  const dimScale = viewBoxWidth / 625;

  // --- DESCRIPTION TEXT GENERATION & WRAPPING ---
  const standardRaceway = PAINT_COLORS.find(c => c.name === config.colors.raceway);
  const racewayName = standardRaceway ? standardRaceway.name : config.colors.raceway;

  let descriptionLines: string[] = [];
  const descFontSize = 12 * dimScale;

  config.lines.forEach((line, idx) => {
      if(!line) return;
      const count = line.replace(/\s/g, '').length;

      let rwText = '';
      if (config.mount === MountType.RACEWAY) {
         const rwLen = config.dimensions.racewayLengths[idx] || (line.length * letterHeight * widthFactor);
         rwText = `, and ${Math.round(rwLen)}" raceway painted ${racewayName}`;
      }

      const desc = `(Line ${idx+1}: x${count}) ${letterHeight}" ${config.illumination} Channel Letters with ${config.colors.face} faces, ${config.colors.return} ${letterDepth}" returns, ${config.colors.trimCap.replace('1" ', '')} trim${rwText}.`;

      // Wrap this line
      const wrapped = wrapText(desc, drawingTotalWidth, descFontSize);
      descriptionLines = [...descriptionLines, ...wrapped];
  });

  // Calculate height needed for description
  const lineHeightMult = 1.4;
  const descriptionBlockHeight = descriptionLines.length * (descFontSize * lineHeightMult) + (24 * dimScale); // + padding

  // Total Content Height
  const totalContentHeight = signAssemblyHeight + descriptionBlockHeight;

  // Adjust ViewBox Height based on Aspect Ratio or Content?
  // We want 11x8.5 ratio usually, but SVG viewBox can expand. 
  // Let's set height to fit content + padding, then the container CSS enforces aspect ratio.
  const viewBoxHeight = Math.max(totalContentHeight + (viewportPadding * 2), viewBoxWidth * 0.75); 

  // Center the Group Vertically
  const groupYOffset = (viewBoxHeight - totalContentHeight) / 2;

  // Colors
  const faceColor = getVinylHex(config.colors.vinylSeries, config.colors.face);
  const returnColor = getHex(config.colors.return, RETURN_COLORS);
  const trimColor = getHex(config.colors.trimCap, TRIM_CAP_COLORS);
  const racewayColor = standardRaceway ? standardRaceway.hex : (config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333');

  const clientName = config.lines[0] || "Client Name";
  const dateStr = new Date().toLocaleDateString();

  // New Print Handler: Reuses the reliable generateBlueprintSVG service + Popup
  const handlePrint = () => {
    const svgString = generateBlueprintSVG(config);
    const printWindow = window.open('', '_blank', 'width=1100,height=850');
    if (!printWindow) return;

    printWindow.document.write(`
      <html>
        <head>
          <title>${clientName} - Blueprint</title>
          <style>
             body { margin: 0; display: flex; justify-content: center; align-items: center; height: 100vh; }
             @media print { 
               @page { size: landscape; margin: 0; }
               body { -webkit-print-color-adjust: exact; }
             }
