import { SignConfig, MountType, IlluminationType } from '../types';
import { TRIM_CAP_COLORS, RETURN_COLORS, PAINT_COLORS, VINYL_SERIES, FONT_LIBRARY } from '../constants';

const DIM_COLOR = "#3b82f6";

// Helper to look up Hex codes
const getHex = (name: string, collection: {name: string, hex: string}[]) => {
  const found = collection.find(c => c.name === name);
  return found ? found.hex : '#cccccc';
};
const getVinylHex = (series: string, name: string) => {
  const collection = VINYL_SERIES[series as keyof typeof VINYL_SERIES];
  if(!collection) return '#cccccc';
  return getHex(name, collection);
};

// SVG String Generators
const svgLine = (x1: number, y1: number, x2: number, y2: number, color: string, width: number, markerStart?: string, markerEnd?: string) => {
  const mStart = markerStart ? `marker-start="${markerStart}"` : '';
  const mEnd = markerEnd ? `marker-end="${markerEnd}"` : '';
  return `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${color}" stroke-width="${width}" ${mStart} ${mEnd} />`;
};

const svgRect = (x: number, y: number, w: number, h: number, fill: string, stroke: string, strokeWidth: number = 0) => {
  return `<rect x="${x}" y="${y}" width="${w}" height="${h}" fill="${fill}" stroke="${stroke}" stroke-width="${strokeWidth}" />`;
};

const svgText = (x: number, y: number, text: string, fontSize: number, fontFamily: string, fontWeight: string, color: string, anchor: string = "middle", baseline: string = "middle", length?: number, rotation: number = 0, stroke: string = "none", strokeWidth: number = 0) => {
  const transform = rotation ? `transform="rotate(${rotation}, ${x}, ${y})"` : '';
  const lenAttr = length ? `textLength="${length}" lengthAdjust="spacingAndGlyphs"` : '';
  const strokeAttr = stroke !== 'none' ? `stroke="${stroke}" stroke-width="${strokeWidth}"` : '';

  return `<text x="${x}" y="${y}" ${lenAttr} ${transform} dy="${baseline === 'middle' ? '0.32em' : '0'}" text-anchor="${anchor}" dominant-baseline="${baseline}" font-size="${fontSize}" font-family="${fontFamily}" font-weight="${fontWeight}" fill="${color}" ${strokeAttr}>${text}</text>`;
};

const svgDimensionLine = (
  x1: number, y1: number, 
  x2: number, y2: number, 
  offset: number, 
  label: string, 
  scale: number,
  textOffsetBase: number
) => {
  const fontSize = 12;
  const sFontSize = fontSize * scale;
  const sStroke = 1 * scale; 
  const sGap = 5 * scale;
  const sExt = 8 * scale;
  const sTextOffset = textOffsetBase * scale;

  const isVertical = Math.abs(x1 - x2) < 0.1;

  const ex1_start_x = isVertical ? x1 + (offset > 0 ? sGap : -sGap) : x1;
  const ex1_start_y = isVertical ? y1 : y1 + (offset > 0 ? sGap : -sGap);

  const dim_x1 = isVertical ? x1 + offset : x1;
  const dim_y1 = isVertical ? y1 : y1 + offset;
  const dim_x2 = isVertical ? x2 + offset : x2;
  const dim_y2 = isVertical ? y2 : y2 + offset;

  const ex1_end_x = isVertical ? dim_x1 + (offset > 0 ? sExt : -sExt) : x1;
  const ex1_end_y = isVertical ? y1 : dim_y1 + (offset > 0 ? sExt : -sExt);

  const ex2_start_x = isVertical ? x2 + (offset > 0 ? sGap : -sGap) : x2;
  const ex2_start_y = isVertical ? y2 : y2 + (offset > 0 ? sGap : -sGap);

  const ex2_end_x = isVertical ? dim_x2 + (offset > 0 ? sExt : -sExt) : x2;
  const ex2_end_y = isVertical ? y2 : dim_y2 + (offset > 0 ? sExt : -sExt);

  const midX = (dim_x1 + dim_x2) / 2;
  const midY = (dim_y1 + dim_y2) / 2;
  let tX, tY;

  if (isVertical) {
      const dir = offset >= 0 ? 1 : -1;
      tX = midX + (sTextOffset * dir);
      tY = midY;
  } else {
      const dir = offset >= 0 ? 1 : -1;
      tX = midX;
      tY = midY + (sTextOffset * dir);
  }

  const rotation = isVertical ? -90 : 0;

  // Background Rect for Text
  const textWidth = label.length * sFontSize * 0.6;
  const rectH = sFontSize * 1.2;

  // Calculate rect position based on rotation
  let rx = tX - (textWidth/2);
  let ry = tY - (rectH/2);

  const rectTransform = `transform="rotate(${rotation}, ${tX}, ${tY})"`;
  const bgRect = `<rect x="${rx}" y="${ry}" width="${textWidth}" height="${rectH}" fill="white" opacity="0.9" ${rectTransform} />`;

  return `
    ${svgLine(ex1_start_x, ex1_start_y, ex1_end_x, ex1_end_y, DIM_COLOR, sStroke)}
    ${svgLine(ex2_start_x, ex2_start_y, ex2_end_x, ex2_end_y, DIM_COLOR, sStroke)}
    ${svgLine(dim_x1, dim_y1, dim_x2, dim_y2, DIM_COLOR, sStroke, 'url(#arrow-start-blue)', 'url(#arrow-end-blue)')}
    ${bgRect}
    ${svgText(tX, tY, label, sFontSize, "sans-serif", "normal", DIM_COLOR, "middle", "middle", undefined, rotation)}
  `;
};

// Helper for Text Wrapping (SVG Export)
const wrapText = (text: string, maxWidth: number, fontSize: number): string[] => {
    const words = text.split(' ');
    const lines: string[] = [];
    let currentLine = words[0];

    // Approx char width ~0.6em
    const charWidth = fontSize * 0.6;

    for (let i = 1; i < words.length; i++) {
        const word = words[i];
        const width = (currentLine.length + 1 + word.length) * charWidth;
        if (width < maxWidth) {
            currentLine += " " + word;
        } else {
            lines.push(currentLine);
            currentLine = word;
        }
    }
    lines.push(currentLine);
    return lines;
};

export const generateBlueprintSVG = (config: SignConfig): string => {
  // Logic Parity with BlueprintView.tsx
  // Robust fallback
  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const widthFactor = selectedFont.widthFactor;
  const cssFamily = selectedFont.cssFamily || "sans-serif";
  const cssWeight = selectedFont.cssWeight || "normal";

  const letterHeight = config.dimensions.height;
  const letterDepth = config.dimensions.depth;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);

  // --- WIDTH CALCULATION (Text vs Raceway) ---
  let maxLineWidth = 0;

  config.lines.forEach((line, idx) => {
    if (!line) return;
    const textW = line.length * (letterHeight * widthFactor);
    let rowW = textW;

    // Check Raceway Length if applicable
    if (config.mount === MountType.RACEWAY) {
        // Use synced config value
        const rwLen = config.dimensions.racewayLengths[idx] || textW;
        if (rwLen > rowW) rowW = rwLen;
    }
    if (rowW > maxLineWidth) maxLineWidth = rowW;
  });

  const drawingTotalWidth = Math.max(maxLineWidth, config.dimensions.calculatedWidth);
  const numLines = config.lines.filter(l => l).length;
  // Total Height = (Lines * Height) + (Gaps * GapSize)
  const signAssemblyHeight = (numLines * letterHeight) + ((numLines - 1) * rowGap); 

  const racewayHeight = 6;
  const viewportPadding = 48;
  const viewBoxWidth = drawingTotalWidth + (viewportPadding * 2);
  const dimScale = viewBoxWidth / 625;

  // --- DESCRIPTION TEXT GENERATION & WRAPPING ---
  const standardRaceway = PAINT_COLORS.find(c => c.name === config.colors.raceway);
  const racewayName = standardRaceway ? standardRaceway.name : config.colors.raceway;

  let descriptionLines: string[] = [];
  const descFontSize = 12 * dimScale;

  config.lines.forEach((line, idx) => {
      if(!line) return;
      const count = line.replace(/\s/g, '').length;

      let rwText = '';
      if (config.mount === MountType.RACEWAY) {
         const rwLen = config.dimensions.racewayLengths[idx] || (line.length * letterHeight * widthFactor);
         rwText = `, and ${Math.round(rwLen)}" raceway painted ${racewayName}`;
      }

      const desc = `(Line ${idx+1}: x${count}) ${letterHeight}" ${config.illumination} Channel Letters with ${config.colors.face} faces, ${config.colors.return} ${letterDepth}" returns, ${config.colors.trimCap.replace('1" ', '')} trim${rwText}.`;

      // Wrap this line
      const wrapped = wrapText(desc, drawingTotalWidth, descFontSize);
      descriptionLines = [...descriptionLines, ...wrapped];
  });

  // Calculate height needed for description
  const lineHeightMult = 1.4;
  const descriptionBlockHeight = descriptionLines.length * (descFontSize * lineHeightMult) + (24 * dimScale); 

  // Total Content Height
  const totalContentHeight = signAssemblyHeight + descriptionBlockHeight;
  const viewBoxHeight = Math.max(totalContentHeight + (viewportPadding * 2), viewBoxWidth * 0.75); 

  // Center the Group Vertically
  const groupYOffset = (viewBoxHeight - totalContentHeight) / 2;
  const groupXOffset = viewportPadding;

  const faceColor = getVinylHex(config.colors.vinylSeries, config.colors.face);
  const trimColor = getHex(config.colors.trimCap, TRIM_CAP_COLORS);

  // Construct SVG Content
  let svgContent = '';

  // 1. Grid (Optional Background)
  svgContent += `<rect x="0" y="0" width="${viewBoxWidth}" height="${viewBoxHeight}" fill="#f8fafc" />`;
  svgContent += `<path d="M 0 0 L ${viewBoxWidth} 0 L ${viewBoxWidth} ${viewBoxHeight} L 0 ${viewBoxHeight} Z" fill="none" stroke="#e2e8f0" stroke-width="2" />`;

  // 2. Geometry & Description
  let geometryHtml = '';

  config.lines.forEach((line, i) => {
    if(!line) return;

    const lineHeight = letterHeight + rowGap; 
    const y = i * lineHeight;
    const calculatedWidth = Math.max(0.1, line.length * (letterHeight * widthFactor));

    const x = (drawingTotalWidth - calculatedWidth) / 2;

    // Use synced config value
    const rwLen = config.dimensions.racewayLengths[i] || calculatedWidth;
    const rwX = (drawingTotalWidth - rwLen) / 2;

    const visualFontSize = letterHeight * 1.35; 

    // Raceway
    if (config.mount === MountType.RACEWAY) {
       const ry = y + (letterHeight/2) - (racewayHeight/2) + (config.dimensions.racewayOffset || 0);
       geometryHtml += svgRect(rwX, ry, rwLen, racewayHeight, "#f1f5f9", "#94a3b8", 0.5);
    }

    // Text
    const tx = x + (calculatedWidth/2);
    const ty = y + (letterHeight/2);

    const strokeW = config.illumination === IlluminationType.HALO_LIT ? 0 : (letterHeight * 0.02);

    geometryHtml += svgText(
        tx, ty, line, visualFontSize, cssFamily, cssWeight, faceColor, 
        "middle", "middle", undefined, 0, trimColor, strokeW
    );
  });

  // Description HTML
  let descriptionHtml = '';
  descriptionLines.forEach((textLine, idx) => {
     descriptionHtml += svgText(
       drawingTotalWidth/2, 
       signAssemblyHeight + (48 * dimScale) + (idx * descFontSize * 1.4), 
       textLine, 
       descFontSize, 
       "monospace", "normal", "#334155"
     );
  });

  // 3. Dimensions
  let dimensionsHtml = '';

  // Width
  dimensionsHtml += svgDimensionLine(
    0, 0, 
    drawingTotalWidth, 0, 
    -24 * dimScale, 
    `${Math.round(drawingTotalWidth)}" (${Math.floor(drawingTotalWidth/12)}'-${Math.round(drawingTotalWidth%12)}")`, 
    dimScale, 20
  );

  // Height
  dimensionsHtml += svgDimensionLine(
    0, 0, 
    0, signAssemblyHeight, 
    -24 * dimScale, 
    `${Math.round(signAssemblyHeight)}" (${Math.floor(signAssemblyHeight/12)}'-${Math.round(signAssemblyHeight%12)}")`, 
    dimScale, 20
  );

  return `
    <svg width="100%" viewBox="0 0 ${viewBoxWidth} ${viewBoxHeight}" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <marker id="arrow-end-blue" markerWidth="4" markerHeight="4" refX="4" refY="2" orient="auto" markerUnits="strokeWidth">
            <path d="M0,0 L4,2 L0,4 z" fill="${DIM_COLOR}" />
        </marker>
        <marker id="arrow-start-blue" markerWidth="4" markerHeight="4" refX="0" refY="2" orient="auto" markerUnits="strokeWidth">
            <path d="M4,0 L0,2 L4,4 z" fill="${DIM_COLOR}" />
        </marker>
      </defs>
      <rect x="0" y="0" width="${viewBoxWidth} height="${viewBoxHeight}" fill="#f8fafc"/>

      <g transform="translate(${groupXOffset}, ${viewportPadding})">
         <g transform="translate(0, ${groupYOffset})">
            ${geometryHtml}
            ${dimensionsHtml}
            ${descriptionHtml}
         </g>
      </g>
    </svg>
  `;
};

import {
  SignConfig,
  ManufacturingPacket,
  Department,
  SignType,
  MountType,
  BOMItem,
  IlluminationType,
  BackerMaterial
} from '../types';
import { 
  calculatePerimeter, 
  generateBenderPath, 
  calculateTotalWidth,
  calculateSheetsNeeded,
  calculateLEDModules
} from './vectorUtils';
import { FONT_LIBRARY } from '../constants';

export const calculateSignRequirements = (config: SignConfig): ManufacturingPacket => {
  const tasks = [];
  const bom: BOMItem[] = [];
  const warnings = [];

  // Robust Fallback for Engine
  const fontData = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];

  // Update calculated width if not present (although UI usually handles this, we double check here)
  const calcWidth = calculateTotalWidth(config.lines, config.dimensions.height, config.fontFamily);
  const effectiveConfig = { ...config, dimensions: { ...config.dimensions, calculatedWidth: calcWidth }};

  // 1. Engineering Checks
  // Raceway Splicing Check - Check if ANY section exceeds 120"
  if (effectiveConfig.mount === MountType.RACEWAY) {
    let spliceNeeded = false;
    const widthFactor = fontData.widthFactor;

    config.lines.forEach((line, idx) => {
      // Use the accurate length stored in config (which comes from 3D measure), fallback to estimation
      const len = config.dimensions.racewayLengths[idx] || (line.length * (config.dimensions.height * widthFactor));

      if(len > 120) spliceNeeded = true;
    });

    if (spliceNeeded) {
      warnings.push(`Raceway length exceeds 10ft on one or more lines. Will be built in sections with splice plates.`);
    }
  }

  // 2. Core Logic Branching (Strategy Pattern)
  if (effectiveConfig.type === SignType.CHANNEL_LETTER) {

    // --- CNC Router Logic ---
    const facesNeeded = calculateSheetsNeeded(config.lines, config.dimensions.height);
    const backsNeeded = facesNeeded; // Usually same amount for backs

    // Face Material BOM
    const faceMatName = `${config.faceMaterial} ${config.faceThickness}" - Translucent White`;
    bom.push({ sku: `SHEET-${config.faceMaterial.substring(0,3).toUpperCase()}`, name: faceMatName, quantity: facesNeeded, unit: 'sheet', department: Department.ROUTER });

    // Backer Material BOM
    let backMatName = "3mm ACM - White";
    let backSku = "ACM-WHT";

    if (config.illumination === IlluminationType.HALO_LIT) {
        // Use user selected backer for Halo
        const bThickness = config.backerThickness || 0.1875;
        backMatName = `${config.backerMaterial} ${bThickness}"`;
        backSku = `SHEET-${config.backerMaterial.substring(0,3).toUpperCase()}`;
    } else {
        // Force ACM for front lit usually, unless overridden, but here we respect config if user selected
        // In Controls we enforce BackerMaterial.ACM for Front Lit, so this is safe
        backMatName = `${config.backerMaterial}`;
    }

    bom.push({ sku: backSku, name: backMatName, quantity: backsNeeded, unit: 'sheet', department: Department.ROUTER });

    tasks.push({ department: Department.ROUTER, description: `Route ${facesNeeded} sheets of Faces`, status: 'Pending', estimatedHours: facesNeeded * 0.75 });
    tasks.push({ department: Department.ROUTER, description: `Route ${backsNeeded} sheets of Backers`, status: 'Pending', estimatedHours: backsNeeded * 0.5 });

    // --- Vinyl Logic ---
    // User selected Series + Color. In production, we assume we wrap the face.
    tasks.push({ department: Department.VINYL, description: `Apply ${config.colors.vinylSeries} (${config.colors.face}) to faces`, status: 'Pending', estimatedHours: 1.5 });
    bom.push({ sku: 'VNY-TRN', name: `${config.colors.vinylSeries} - ${config.colors.face}`, quantity: facesNeeded * 32, unit: 'sqft', department: Department.VINYL });

    // --- Coil & Trim Logic ---
    const totalPerimeterInches = calculatePerimeter(config.lines, config.dimensions.height);
    bom.push({ sku: 'COIL-5', name: `Return Coil 5" - ${config.colors.return}`, quantity: Math.ceil(totalPerimeterInches / 12), unit: 'ft', department: Department.CHANNEL_BENDER });
    bom.push({ sku: 'TRIM-1', name: `Trim Cap 1" - ${config.colors.trimCap}`, quantity: Math.ceil(totalPerimeterInches / 12), unit: 'ft', department: Department.ASSEMBLY });

    tasks.push({ department: Department.CHANNEL_BENDER, description: `Bend Returns (Total: ${Math.ceil(totalPerimeterInches/12)} ft)`, status: 'Pending', estimatedHours: 2 });
    tasks.push({ department: Department.ASSEMBLY, description: `Bond Trim Cap to Faces`, status: 'Pending', estimatedHours: 2.5 });

    // --- Illumination Logic (LED & PSU) ---
    if (config.illumination !== IlluminationType.NON_ILLUMINATED) {
      const totalModules = calculateLEDModules(config.lines, config.dimensions.height);
      const totalWatts = totalModules * 0.45;

      bom.push({ sku: `LED-${config.ledColor.toUpperCase()}`, name: `LED Module (${config.ledColor})`, quantity: totalModules, unit: 'module', department: Department.ASSEMBLY });

      // PSU Calculation
      if (totalWatts <= 60) {
        bom.push({ sku: 'PSU-60W', name: 'Power Supply 60W 12V', quantity: 1, unit: 'ea', department: Department.ASSEMBLY });
      } else if (totalWatts <= 120) {
        bom.push({ sku: 'PSU-120W', name: 'Power Supply 120W 12V', quantity: 1, unit: 'ea', department: Department.ASSEMBLY });
      } else {
        const psuCount = Math.ceil(totalWatts / 120);
        bom.push({ sku: 'PSU-120W', name: 'Power Supply 120W 12V', quantity: psuCount, unit: 'ea', department: Department.ASSEMBLY });
      }

      tasks.push({ department: Department.ASSEMBLY, description: `Install ${totalModules} LEDs & Wiring`, status: 'Pending', estimatedHours: 2 });
    }

    // --- Mounting Logic (Raceway vs Direct) ---
    if (config.mount === MountType.RACEWAY) {
      // Calculate total raceway length by summing individual line widths based on configuration
      let totalRwLen = 0;
      const widthFactor = fontData.widthFactor;

      config.lines.forEach((line, idx) => {
         if(line.length > 0) {
            // Priority: Config Value (Synced from 3D) > Estimation
            const len = config.dimensions.racewayLengths[idx] || (line.length * (config.dimensions.height * widthFactor));
            totalRwLen += len;
         }
      });

      const numLines = config.lines.filter(l => l.length > 0).length;

      // Metal Fab
      tasks.push({ department: Department.METAL_FAB, description: `Fabricate ${numLines}x Raceway Runs (Total: ${Math.ceil(totalRwLen)}") w/ End Caps & Clips`, status: 'Pending', estimatedHours: 3 });
      // STRICT: 6x4 Extrusion
      bom.push({ sku: 'RAC-EXT-64', name: `Raceway Extrusion 6"x4" - ${Math.ceil(totalRwLen)}" total`, quantity: Math.ceil(totalRwLen / 120), unit: 'ea', department: Department.METAL_FAB });
      bom.push({ sku: 'RAC-CLIP', name: 'Mounting Clips', quantity: (Math.ceil(totalRwLen / 48) + 1) * numLines, unit: 'ea', department: Department.METAL_FAB });
      bom.push({ sku: 'RAC-CAP', name: 'Raceway End Caps', quantity: 2 * numLines, unit: 'ea', department: Department.METAL_FAB });

      // Paint
      tasks.push({ department: Department.PAINT, description: `Paint Raceways (${config.colors.raceway})`, status: 'Pending', estimatedHours: 3 });
      bom.push({ sku: 'PNT-EXT', name: `Paint - ${config.colors.raceway}`, quantity: 1, unit: 'ea', department: Department.PAINT });

      // Assembly
      tasks.push({ department: Department.ASSEMBLY, description: 'Mount Letters to Raceway', status: 'Pending', estimatedHours: 2 });
    } else {
      // Direct Mount
      tasks.push({ department: Department.DESIGN, description: 'Plot Installation Pattern', status: 'Pending', estimatedHours: 0.5 });
      bom.push({ sku: 'PAT-PAPER', name: 'Pattern Paper', quantity: Math.ceil(calcWidth / 12), unit: 'ft', department: Department.DESIGN });
    }

  } else if (config.type === SignType.CABINET) {
    // Cabinet Logic (Simplified for this update, maintaining basic calculation)
    tasks.push({ department: Department.METAL_FAB, description: "Weld Cabinet Frame", status: 'Pending', estimatedHours: 4 });
    bom.push({ sku: 'ALU-EXT-CAB', name: 'Cabinet Extrusion', quantity: (config.dimensions.height + calcWidth) * 2 / 12, unit: 'ft', department: Department.METAL_FAB });
  }

  return {
    id: `WO-${Math.floor(Math.random() * 90000) + 10000}`,
    generatedAt: new Date().toISOString(),
    config: effectiveConfig,
    warnings,
    tasks,
    bom,
    vectorFiles: {
      routerFace: `face_cut_file.svg`,
      routerBack: `back_cut_file.svg`,
      benderPath: `bender_data.dxf`,
      pattern: config.mount === MountType.DIRECT ? `install_pattern.svg` : 'N/A',
    }
  };
};

