import React, { useRef, useLayoutEffect } from 'react';
import { Text3D } from '@react-three/drei';
import * as THREE from 'three';
import { PartVisibility } from './utils';

// Add global intrinsic elements for Three.js to satisfy TypeScript
declare global {
  namespace JSX {
    interface IntrinsicElements {
      group: any;
      mesh: any;
      boxGeometry: any;
      meshStandardMaterial: any;
      meshBasicMaterial: any;
      planeGeometry: any;
      ambientLight: any;
      directionalLight: any;
      color: any;
    }
  }
}

interface LetterGroupProps {
    line: string;
    fontUrl: string;
    letterHeight: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    isHalo: boolean;
    isLit: boolean;
    isRaceway: boolean;
    racewayFaceZ: number;
    wallFaceZ: number;
    visibility: PartVisibility;
    onMeasure?: (width: number) => void;
}

export const LetterGroup: React.FC<LetterGroupProps> = ({ 
    line, fontUrl, letterHeight, depth, faceThickness, trimDepth, 
    returnMaterial, faceMaterial, trimCapMaterial, haloBackerMaterial, canMaterial,
    invisibleMaterial,
    glowMats1, glowMats2, glowParams1, glowParams2, shadowMats,
    zOffset1, zOffset2, mountZ, backerZ, backerThickness,
    isHalo, isLit, isRaceway, racewayFaceZ, wallFaceZ,
    visibility,
    onMeasure
}) => {

    // Ref to measure the geometry
    const meshRef = useRef<THREE.Mesh>(null);

    useLayoutEffect(() => {
        if (meshRef.current && onMeasure) {
            // Ensure geometry is computed
            meshRef.current.geometry.computeBoundingBox();
            const box = meshRef.current.geometry.boundingBox;
            if (box) {
                const width = box.max.x - box.min.x;
                onMeasure(width);
            }
        }
    }, [line, fontUrl, letterHeight, onMeasure]);

    const shadowZ1 = racewayFaceZ - mountZ + 0.1;
    const shadowZ2 = wallFaceZ - mountZ + 0.05;

    // PHYSICAL LAYERING STRATEGY
    const faceRecess = 0.05;
    const faceZ = depth - faceThickness - faceRecess; 
    const canHeight = Math.max(0.1, depth - faceThickness - faceRecess); 
    const trimLipZ = depth; 
    const trimSideZ = depth - 0.75; 

    const trimStrokeWidth = 0.25; // 1/4" Stroke Inward
    const trimInwardSize = -trimStrokeWidth;
    const trimSideExpansion = 0.03; // Approx 1/32" - 1/16" thickness

    return (
        <group position={[0, 0, mountZ]} castShadow>

            {/* 0. SIMULATED SHADOWS */}
            <group>
                {/* Wall Shadow Only */}
                <group position={[0.3, -1.5, shadowZ2]}>
                    <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.15} material={shadowMats.wallCore}>{line}</Text3D>
                    <Text3D font={fontUrl} size={letterHeight} height={0} position={[0, 0, 0.01]} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.4} material={shadowMats.wallMid}>{line}</Text3D>
                    <Text3D font={fontUrl} size={letterHeight} height={0} position={[0, 0, 0.02]} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.8} material={shadowMats.wallOuter}>{line}</Text3D>
                </group>
            </group>

            {/* 1. THE CAN (Returns) */}
            <Text3D
              ref={meshRef}
              font={fontUrl}
              size={letterHeight}
              height={canHeight}
              curveSegments={12}
              bevelEnabled={true}
              bevelThickness={0} 
              bevelSize={0}
              material={canMaterial}
              visible={visibility.returns}
              renderOrder={10}
            >
              {line}
            </Text3D>

            {/* 1b. THE BACKER (Structure) */}
            {!isHalo && (
                <Text3D
                    font={fontUrl}
                    size={letterHeight}
                    height={0.118} // 3mm ACM
                    position={[0, 0, 0]}
                    curveSegments={12}
                    bevelEnabled={true}
                    bevelThickness={0}
                    bevelSize={-0.05} 
                    material={returnMaterial} 
                    visible={visibility.backers}
                    renderOrder={10}
                >
                    {line}
                </Text3D>
            )}

            {/* 2. FACE ASSEMBLY (Front Lit) */}
            {!isHalo && (
                <group>
                    {/* A. ACRYLIC FACE */}
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={faceThickness}
                        position={[0, 0, faceZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0} 
                        bevelSize={-0.23} 
                        material={faceMaterial} 
                        visible={visibility.faces}
                        renderOrder={15}
                    >
                        {line}
                    </Text3D>

                    {/* B. TRIM CAP LIP (The Stroke) */}
                    <group visible={visibility.trimCapFaces}>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimInwardSize}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimSideExpansion}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                    </group>

                    {/* C. TRIM CAP SIDES (Returns of the cap) */}
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={0.75} 
                        position={[0, 0, trimSideZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0}
                        bevelSize={trimSideExpansion}
                        material={[invisibleMaterial, trimCapMaterial]}
                        visible={visibility.trimCapSides}
                        renderOrder={25}
                    >
                        {line}
                    </Text3D>
                </group>
            )}

            {/* 3. HALO LIT FACE (Single piece) */}
            {isHalo && (
                <Text3D
                    font={fontUrl}
                    size={letterHeight}
                    height={faceThickness} 
                    position={[0, 0, faceZ]} 
                    curveSegments={12}
                    bevelEnabled={true}
                    bevelThickness={0} 
                    bevelSize={0}
                    material={[faceMaterial, returnMaterial]} 
                    visible={visibility.faces}
                    renderOrder={50}
                >
                    {line}
                </Text3D>
            )}

            {/* 4. HALO BACKERS & GLOW */}
            {isHalo && (
            <group>
                <Text3D
                  font={fontUrl}
                  size={letterHeight}
                  height={backerThickness}
                  position={[0, 0, backerZ]} 
                  curveSegments={12}
                  bevelEnabled={true} 
                  bevelThickness={0}
                  bevelSize={-0.05} 
                  material={haloBackerMaterial}
                  visible={visibility.backers}
                >
                  {line}
                </Text3D>

                {isLit && (
                  <>
                    <group position={[0, 0, zOffset1]}>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.core} material={glowMats1.core}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.mid} material={glowMats1.mid}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.outer} material={glowMats1.outer}>{line}</Text3D>
                    </group>

                    {isRaceway && (
                       <group position={[0, 0, zOffset2]}>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.core} material={glowMats2.core}>{line}</Text3D>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.mid} material={glowMats2.mid}>{line}</Text3D>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.outer} material={glowMats2.outer}>{line}</Text3D>
                       </group>
                    )}
                  </>
                )}
            </group>
            )}
        </group>
    )
}

import React, { useState, useEffect } from 'react';
import { Center } from '@react-three/drei';
import * as THREE from 'three';
import { SignConfig, MountType } from '../../types';
import { calculateRacewayTuckLength } from '../../services/vectorUtils';
import { LetterGroup } from './LetterGroup';
import { PartVisibility } from './utils';

// Add global intrinsic elements for Three.js to satisfy TypeScript
declare global {
  namespace JSX {
    interface IntrinsicElements {
      group: any;
      mesh: any;
      boxGeometry: any;
      meshStandardMaterial: any;
      meshBasicMaterial: any;
      planeGeometry: any;
      ambientLight: any;
      directionalLight: any;
