// Helper component to handle camera movements
const CameraController = ({ 
  triggerFit, 
  onFitComplete, 
  signWidth, 
  signHeight 
}: { 
  triggerFit: number, 
  onFitComplete: () => void, 
  signWidth: number, 
  signHeight: number 
}) => {
  const { camera, controls } = useThree((state) => ({ camera: state.camera, controls: state.controls }));

  useEffect(() => {
    if (triggerFit > 0) {
      const fov = 45 * (Math.PI / 180);
      const padding = 1.5; 

      const distH = (signHeight / 2) / Math.tan(fov / 2);
      const distW = (signWidth / 2) / Math.tan(fov / 2) / (window.innerWidth / window.innerHeight); 

      const targetZ = Math.max(distH, distW, 48) * padding;

      const startPos = camera.position.clone();
      const endPos = new THREE.Vector3(0, 0, targetZ);

      camera.position.copy(endPos);
      camera.lookAt(0,0,0);

      if (controls) {
        // @ts-ignore
        controls.target.set(0, 0, 0);
        // @ts-ignore
        controls.update();
      }

      onFitComplete();
    }
  }, [triggerFit, camera, controls, signWidth, signHeight, onFitComplete]);

  return null;
};

// Advanced Screensaver Animation Controller
const CinematicController = ({ 
    active, 
    speed,
    signWidth, 
    signHeight 
}: { 
    active: boolean, 
    speed: number,
    signWidth: number, 
    signHeight: number 
}) => {
    const { camera, controls } = useThree((state) => ({ camera: state.camera, controls: state.controls }));
    const stageRef = useRef(0);
    const timeRef = useRef(0);

    useFrame((state, delta) => {
        if (!active) return;

        const d = delta * speed * 0.4;
        timeRef.current += d;
        const t = timeRef.current;
        const w = signWidth;
        const h = signHeight;

        if (controls) {
             // @ts-ignore
            controls.enabled = false;
        }

        if (t < 8) {
            const pct = t / 8;
            const angle = Math.PI * 0.2 * pct;
            const z = 120 - (40 * pct);
            camera.position.x = Math.sin(angle) * z;
            camera.position.z = Math.cos(angle) * z;
            camera.position.y = 0;
            camera.lookAt(0,0,0);
        }
        else if (t < 20) {
            const pct = (t - 8) / 12; 
            const x = (w * 0.6) - ((w * 1.2) * pct); 
            camera.position.x = x;
            camera.position.z = 40; 
            camera.position.y = 0;
            camera.lookAt(x - 10, 0, 0); 
        }
        else if (t < 26) {
            const pct = (t - 20) / 6;
            const startX = -w * 0.6;
            const endX = -w * 0.8;
            camera.position.x = THREE.MathUtils.lerp(startX, endX, pct);
            camera.position.y = THREE.MathUtils.lerp(0, -h * 1.5, pct); 
            camera.position.z = THREE.MathUtils.lerp(40, 60, pct); 
            camera.lookAt(0, 0, 0); 
        }
        else if (t < 36) {
            const pct = (t - 26) / 10;
            const x = (-w * 0.8) + ((w * 1.6) * pct);
            camera.position.x = x;
            camera.position.y = -h * 1.5;
            camera.position.z = 60;
            camera.lookAt(x, 0, 0);
        }
        else if (t < 40) {
            const pct = (t - 36) / 4;
            const currentX = (w * 0.8);
            camera.position.x = THREE.MathUtils.lerp(currentX, 0, pct);
            camera.position.y = THREE.MathUtils.lerp(-h * 1.5, 0, pct);
            camera.position.z = THREE.MathUtils.lerp(60, 120, pct);
            camera.lookAt(0,0,0);
        }
        else {
            timeRef.current = 0;
        }
    });

    useEffect(() => {
        if (!active && controls) {
            // @ts-ignore
            controls.enabled = true;
        }
    }, [active, controls]);

    return null;
};

// Helper component to handle screenshots
const ScreenshotManager = ({ trigger }: { trigger: number }) => {
  const { gl, scene, camera } = useThree((state) => ({ gl: state.gl, scene: state.scene, camera: state.camera }));
  useEffect(() => {
    if (trigger > 0) {
      gl.render(scene, camera);
      const dataURL = gl.domElement.toDataURL('image/png');
      const link = document.createElement('a');
      const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
      link.setAttribute('download', `sign-design-${timestamp}.png`);
      link.setAttribute('href', dataURL);
      link.click();
    }
  }, [trigger, gl, scene, camera]);

  return null;
};

// Stats Reporter - Runs inside Canvas, updates a Mutable Ref shared with App
const StatsReporter = ({ statsRef, active }: { statsRef: React.MutableRefObject<any>, active: boolean }) => {
  const { gl, camera } = useThree((state) => ({ gl: state.gl, camera: state.camera }));
  useFrame(() => {
    if (!active || !statsRef) return;
    statsRef.current = {
      calls: gl.info.render.calls,
      triangles: gl.info.render.triangles,
      textures: gl.info.memory.textures,
      geometries: gl.info.memory.geometries,
      camPos: camera.position.clone()
    };
  });
  return null;
};

// Debug Overlay UI - Runs outside Canvas, reads from Mutable Ref
const DebugOverlayUI = ({ active, statsRef }: { active: boolean, statsRef: React.MutableRefObject<any> }) => {
  const ref = useRef<HTMLPreElement>(null);
  const animationRef = useRef<number | undefined>(undefined);

  useEffect(() => {
    if (!active) return;
    const loop = () => {
      if (ref.current && statsRef.current) {
        const s = statsRef.current;
        const camPos = s.camPos || new THREE.Vector3();
        const dist = camPos.distanceTo(new THREE.Vector3(0,0,0));
        const zoomPct = Math.round((120 / Math.max(dist, 1)) * 100);

        ref.current.textContent = `CAM : ${camPos.x.toFixed(1)}, ${camPos.y.toFixed(1)}, ${camPos.z.toFixed(1)}
DIST: ${dist.toFixed(1)}u
ZOOM: ${zoomPct}%
DRAW: ${s.calls} calls
TRIS: ${s.triangles}
TEX : ${s.textures}
GEO : ${s.geometries}`;
      }
      animationRef.current = requestAnimationFrame(loop);
    };
    loop();
    return () => {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
    };
  }, [active, statsRef]);

  if (!active) return null;

  return (
    <div className="absolute bottom-6 left-6 p-4 bg-slate-950/90 border border-slate-800 rounded-lg shadow-2xl backdrop-blur-md min-w-[160px] pointer-events-none z-50">
       <h4 className="flex items-center gap-2 text-[10px] font-bold text-slate-500 mb-2 uppercase tracking-widest border-b border-slate-800 pb-1">
         <Info size={12} className="text-emerald-500"/> Viewport Stats
       </h4>
       <pre ref={ref} className="font-mono text-[11px] text-emerald-400 leading-relaxed whitespace-pre"></pre>
    </div>
  );
};

export default function App() {
  const [activeTab, setActiveTab] = useState<'design' | 'blueprint' | 'fabrication'>('design');
  const [config, setConfig] = useState<SignConfig>(DEFAULT_CONFIG);
  const [survey] = useState<SiteSurveyData>(SAMPLE_SURVEY);

  // View State
  const [ambientIntensity, setAmbientIntensity] = useState(1.5); // Default 50% (Range 0-3)
  const [ledIntensity, setLedIntensity] = useState(3.0); 
  const [lightsActive, setLightsActive] = useState(false); // Default OFF
  const [shadowIntensity, setShadowIntensity] = useState(0.9); // Default 90% for Front Lit Off

  // Camera & Animation Control State
  const [fitTrigger, setFitTrigger] = useState(0);
  const [isCinematic, setIsCinematic] = useState(false);
  const [cinematicSpeed, setCinematicSpeed] = useState(0.5);
  const [screenshotTrigger, setScreenshotTrigger] = useState(0);
  const [cameraLocked, setCameraLocked] = useState(true); // Lock rotation to front by default
  const [showDebug, setShowDebug] = useState(false);

  // Tools
  const [showCalibrator, setShowCalibrator] = useState(false);

  // Mutable Ref for Stats (Performance Optimization)
  const statsRef = useRef<any>(null);

  // Debug Visibility State
  const [partVisibility, setPartVisibility] = useState<PartVisibility>({
    faces: true,
    trimCapSides: true,
    trimCapFaces: true,
    returns: true,
    backers: true,
    raceway: true
  });

  // Wall Textures State
  const [wallTextures, setWallTextures] = useState<{map: THREE.Texture | null, normalMap: THREE.Texture | null}>({ map: null, normalMap: null });

  // Auto-fit when entering design view
  useEffect(() => {
    if (activeTab === 'design') {
      const timer = setTimeout(() => {
        setFitTrigger(prev => prev + 1);
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [activeTab]);

  // Regenerate textures when wall config changes
  useEffect(() => {
    const tex = generateTexture(config.wallTexture, config.wallColor);
    setWallTextures(tex);
  }, [config.wallTexture, config.wallColor]);

  // Callback to sync measured raceway length from 3D view back to Config state
  const handleRacewayLengthUpdate = useCallback((index: number, length: number) => {
    setConfig(prev => {
        const currentLen = prev.dimensions.racewayLengths[index];
        const isAuto = prev.dimensions.racewayLengthsAuto[index];
        if (!isAuto) return prev;
        if (Math.abs(currentLen - length) < 0.1) return prev;

        const newLengths = [...prev.dimensions.racewayLengths];
        newLengths[index] = Math.round(length * 100) / 100; 

        return {
          ...prev,
          dimensions: { ...prev.dimensions, racewayLengths: newLengths }
        };
    });
  }, []);

  const togglePart = (part: keyof PartVisibility) => {
    setPartVisibility(prev => ({ ...prev, [part]: !prev[part] }));
  };

  // Memoize engineering calculations
  const manufacturingPacket: ManufacturingPacket = useMemo(() => {
    return calculateSignRequirements(config);
  }, [config]);

  // Callback stub for fit to prevent re-renders
  const handleFitComplete = useCallback(() => {}, []);

  return (
    <div className="flex h-screen w-screen bg-slate-950 text-slate-100 overflow-hidden relative">

      {/* Tool Modals */}
      {showCalibrator && (
         <FontCalibratorModal 
           fontName={config.fontFamily} 
           onClose={() => setShowCalibrator(false)} 
         />
      )}

      {/* LEFT SIDEBAR - Configuration */}
      <aside className="w-96 flex flex-col border-r border-slate-800 bg-slate-900 z-20 shadow-xl">
        <div className="p-5 border-b border-slate-800 flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-lg flex items-center justify-center font-bold text-xl shadow-lg">SF</div>
          <div>
             <span className="font-bold text-lg tracking-tight block">SignFabricator OS</span>
             <span className="text-xs text-slate-500 uppercase tracking-widest">Enterprise Edition</span>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-5 custom-scrollbar">
          <Controls 
            config={config} 
            onChange={setConfig} 
            viewSettings={{ ambientIntensity, ledIntensity, lightsActive, shadowIntensity }}
            onViewChange={(s) => {
              if(s.ambientIntensity !== undefined) setAmbientIntensity(s.ambientIntensity);
              if(s.ledIntensity !== undefined) setLedIntensity(s.ledIntensity);
              if(s.lightsActive !== undefined) setLightsActive(s.lightsActive);
              if(s.shadowIntensity !== undefined) setShadowIntensity(s.shadowIntensity);
            }}
            onCalibrate={() => setShowCalibrator(true)}
          />
        </div>

        <div className="p-3 bg-slate-950 border-t border-slate-800 text-[10px] text-slate-600 text-center">
          © 2025 SignFabricator Inc. | v3.0.2 Stable
        </div>
      </aside>

      {/* CENTER - Viewport Area */}
      <main className="flex-1 relative flex flex-col">

        {/* Top Navigation */}
        <div className="absolute top-6 left-1/2 -translate-x-1/2 z-30 flex gap-2 p-1.5 bg-slate-900/80 backdrop-blur-md rounded-full border border-slate-700/50 shadow-2xl">
          <button 
            onClick={() => setActiveTab('design')}
            className={`px-5 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'design' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            <Box size={16} /> 3D Model
          </button>
          <button 
            onClick={() => setActiveTab('blueprint')}
            className={`px-5 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'blueprint' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            <FileText size={16} /> Blueprint
          </button>
          <button 
             onClick={() => setActiveTab('fabrication')}
             className={`px-5 py-2 rounded-full text-sm font-medium transition-all flex items-center gap-2 ${activeTab === 'fabrication' ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-900/50' : 'text-slate-400 hover:text-white hover:bg-slate-800'}`}
          >
            <Printer size={16} /> Engineering
          </button>
        </div>

        {/* Viewport Content */}
        <div className="flex-1 bg-gradient-to-b from-slate-900 via-slate-900 to-slate-950 relative overflow-hidden">

          {activeTab === 'design' && (
            <>
              {/* Debug Tools Panel (Floating) */}
              {showDebug && (
                  <div className="absolute left-6 top-6 z-40 w-64 bg-slate-950/90 backdrop-blur-md border border-slate-800 rounded-lg shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                      <div className="p-3 bg-slate-900/50 border-b border-slate-800 flex justify-between items-center">
                          <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                             <Layers size={14} className="text-blue-500" /> Debug Layers
                          </h4>
                          <button onClick={() => setShowDebug(false)} className="text-slate-500 hover:text-white">
                             <EyeOff size={14} />
                          </button>
                      </div>
                      <div className="p-2 space-y-1">
                          {Object.entries(partVisibility).map(([key, val]) => (
                              <button 
                                key={key}
                                onClick={() => togglePart(key as keyof PartVisibility)}
                                className={`w-full flex items-center justify-between p-2 rounded text-xs transition-colors ${val ? 'bg-blue-900/30 text-blue-200 hover:bg-blue-900/50' : 'bg-slate-900/30 text-slate-600 hover:bg-slate-900/50'}`}
                              >
                                  <span className="capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}</span>
                                  {val ? <Eye size={14} /> : <EyeOff size={14} />}
                              </button>
                          ))}
                      </div>
                  </div>
              )}

              {/* Debug Overlay (Fixed Position UI) */}
              <DebugOverlayUI active={showDebug} statsRef={statsRef} />

              {/* 3D View Controls Toolbar */}
              <div className="absolute top-6 right-6 z-30 flex items-center gap-2">

                {isCinematic && (
                   <div className="mr-2 px-3 py-2 bg-slate-900/80 backdrop-blur rounded-lg border border-slate-700 flex items-center gap-2 animate-in slide-in-from-right-4 fade-in duration-300">
                      <Gauge size={14} className="text-indigo-400" />
                      <input 
                        type="range" 
                        min="0.1" 
                        max="2.0" 
                        step="0.1"
                        value={cinematicSpeed}
                        onChange={(e) => setCinematicSpeed(parseFloat(e.target.value))}
                        className="w-24 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-500"
                      />
                      <span className="text-[10px] text-slate-400 w-6 text-right">{cinematicSpeed}x</span>
                   </div>
                )}

                <button 
                   onClick={() => setCameraLocked(!cameraLocked)}
                   className={`p-2 rounded-lg border shadow-lg backdrop-blur transition-all ${cameraLocked ? 'bg-amber-600 text-white border-amber-500' : 'bg-slate-800/80 text-white border-slate-600 hover:bg-slate-700'}`}
                   title={cameraLocked ? "Unlock Camera Rotation" : "Restrict Camera to Front"}
                >
                   {cameraLocked ? <Lock size={20} /> : <Unlock size={20} />}
                </button>
                <div className="w-px bg-slate-600 mx-1 opacity-50 h-6"></div>
                <button 
                  onClick={() => setIsCinematic(!isCinematic)}
                  className={`p-2 rounded-lg border shadow-lg backdrop-blur transition-all ${isCinematic ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-800/80 text-white border-slate-600 hover:bg-slate-700'}`}
                  title={isCinematic ? "Stop Animation" : "Start Cinematic Preview"}
                >
                  {isCinematic ? <Pause size={20} /> : <Play size={20} />}
                </button>

                <button 
                  onClick={() => setShowDebug(!showDebug)}
                  className={`p-2 rounded-lg border shadow-lg backdrop-blur transition-all ${showDebug ? 'bg-blue-600 text-white border-blue-500' : 'bg-slate-800/80 text-white border-slate-600 hover:bg-slate-700'}`}
                  title="Toggle Debug Tools"
                >
                  {showDebug ? <Layers size={20} /> : <Info size={20} />}
                </button>

                <button 
                  onClick={() => setScreenshotTrigger(prev => prev + 1)}
                  className="bg-slate-800/80 hover:bg-slate-700 text-white p-2 rounded-lg border border-slate-600 shadow-lg backdrop-blur"
                  title="Take Screenshot"
                >
                  <Camera size={20} />
                </button>
                <button 
                  onClick={() => setFitTrigger(prev => prev + 1)}
                  className="bg-slate-800/80 hover:bg-slate-700 text-white p-2 rounded-lg border border-slate-600 shadow-lg backdrop-blur"
                  title="Fit Sign to View"
                >
                  <Maximize size={20} />
                </button>
              </div>

              <Canvas 
                shadows 
                dpr={[1, 2]} 
                camera={{ position: [0, 0, 120], fov: 45 }}
                gl={{ preserveDrawingBuffer: true, stencil: true }} 
              >
                <color attach="background" args={['#0f172a']} />

                <StatsReporter active={showDebug} statsRef={statsRef} />

                <CameraController 
                  triggerFit={fitTrigger} 
                  onFitComplete={handleFitComplete} 
                  signWidth={Math.max(config.dimensions.calculatedWidth, 48)} 
                  signHeight={config.dimensions.height * config.lines.length}
                />

                <CinematicController 
                   active={isCinematic} 
                   speed={cinematicSpeed}
                   signWidth={Math.max(config.dimensions.calculatedWidth, 60)} 
                   signHeight={config.dimensions.height * config.lines.length} 
                />

                <ScreenshotManager trigger={screenshotTrigger} />

                {/* Environment & Ambient Light */}
                <Environment 
                  preset="city" 
                  background 
                  blur={0.6}
                  environmentIntensity={ambientIntensity} 
                />
                <ambientLight intensity={0.3 * ambientIntensity} />

                {/* Directional Light for Shine (No Shadows) */}
                <directionalLight 
                  position={[20, 50, 50]} 
                  intensity={1.5 * ambientIntensity} 
                  castShadow={false} 
                />

                {/* THE WALL (Z = 0) */}
                <mesh position={[0, 0, -0.5]} receiveShadow={false}>
                   <planeGeometry args={[1200, 600]} />
                   <meshStandardMaterial 
                     color={config.wallTexture === WallTexture.NONE ? config.wallColor : '#ffffff'} 
                     map={wallTextures.map}
                     normalMap={wallTextures.normalMap}
                     roughness={0.8} 
                     metalness={0.0}
                   />
                </mesh>

                {/* SIGN GEOMETRY */}
                <SignRenderer 
                   config={config} 
                   ledIntensity={lightsActive ? ledIntensity : 0} 
                   shadowIntensity={shadowIntensity}
                   partVisibility={partVisibility}
                   onUpdateLength={handleRacewayLengthUpdate}
                />

                {/* Camera Controls */}
                <OrbitControls 
                  makeDefault
                  target={[0, 0, 0]}
                  minPolarAngle={0} 
                  maxPolarAngle={Math.PI}
                  minAzimuthAngle={cameraLocked ? -Math.PI / 2 : -Infinity}
                  maxAzimuthAngle={cameraLocked ? Math.PI / 2 : Infinity}
                  minDistance={20}
                  maxDistance={1200}
                  enableRotate={!isCinematic} 
                />

                <EffectComposer enableNormalPass={false} stencilBuffer={true}>
                  <Bloom luminanceThreshold={1.0} mipmapBlur intensity={lightsActive ? 0.8 : 0} radius={0.6} levels={9} />
                </EffectComposer>
              </Canvas>
            </>
          )}

          {activeTab === 'blueprint' && (
             <div className="w-full h-full bg-slate-200">
                <BlueprintView config={config} />
             </div>
          )}

          {activeTab === 'fabrication' && (
            <div className="w-full h-full p-8 pt-24 overflow-hidden">
               <div className="max-w-6xl mx-auto h-full flex flex-col gap-6">

                 {/* Header Stats */}
                 <div className="flex items-center justify-between">
                   <div>
                      <h1 className="text-3xl font-bold text-white tracking-tight">Production Order #{manufacturingPacket.id.replace('WO-', '')}</h1>
                      <p className="text-slate-400 mt-1">Status: <span className="text-yellow-500 font-medium">Pre-Production Analysis</span></p>
                   </div>
                   <div className="flex gap-4">
                     <div className="bg-slate-800/50 border border-slate-700 px-6 py-3 rounded-lg flex flex-col items-center justify-center">
                       <span className="text-2xl font-bold text-white leading-none">{manufacturingPacket.tasks.length}</span>
                       <span className="text-xs text-slate-500 uppercase mt-1">Tasks</span>
                     </div>
                     <div className="bg-slate-800/50 border border-slate-700 px-6 py-3 rounded-lg flex flex-col items-center justify-center">
                       <span className="text-2xl font-bold text-white leading-none">{manufacturingPacket.bom.length}</span>
                       <span className="text-xs text-slate-500 uppercase mt-1">SKUs</span>
                     </div>
                   </div>
                 </div>

                 {/* Main Content */}
                 <div className="flex-1 min-h-0 bg-slate-900 rounded-xl border border-slate-800 overflow-hidden shadow-2xl">
                   <ManufacturingView packet={manufacturingPacket} survey={survey} />
                 </div>

               </div>
            </div>
          )}

        </div>
      </main>
    </div>
  );
}

import React, { useRef, useLayoutEffect } from 'react';
import { Text3D } from '@react-three/drei';
import * as THREE from 'three';
import { PartVisibility } from './utils';

interface LetterGroupProps {
    line: string;
    fontUrl: string;
    letterHeight: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    isHalo: boolean;
    isLit: boolean;
    isRaceway: boolean;
    racewayFaceZ: number;
    wallFaceZ: number;
    visibility: PartVisibility;
    onMeasure?: (width: number) => void;
}

export const LetterGroup: React.FC<LetterGroupProps> = ({ 
    line, fontUrl, letterHeight, depth, faceThickness, trimDepth, 
    returnMaterial, faceMaterial, trimCapMaterial, haloBackerMaterial, canMaterial,
    invisibleMaterial,
    glowMats1, glowMats2, glowParams1, glowParams2, shadowMats,
    zOffset1, zOffset2, mountZ, backerZ, backerThickness,
    isHalo, isLit, isRaceway, racewayFaceZ, wallFaceZ,
    visibility,
    onMeasure
}) => {

    // Ref to measure the geometry
    const meshRef = useRef<THREE.Mesh>(null);

    useLayoutEffect(() => {
        if (meshRef.current && onMeasure) {
            // Ensure geometry is computed
            meshRef.current.geometry.computeBoundingBox();
            const box = meshRef.current.geometry.boundingBox;
            if (box) {
                const width = box.max.x - box.min.x;
                onMeasure(width);
            }
        }
    }, [line, fontUrl, letterHeight, onMeasure]);

    const shadowZ1 = racewayFaceZ - mountZ + 0.1;
    const shadowZ2 = wallFaceZ - mountZ + 0.05;

    // PHYSICAL LAYERING STRATEGY
    const faceRecess = 0.05;
    const faceZ = depth - faceThickness - faceRecess; 
    const canHeight = Math.max(0.1, depth - faceThickness - faceRecess); 
    const trimLipZ = depth; 
    const trimSideZ = depth - 0.75; 

    const trimStrokeWidth = 0.25; // 1/4" Stroke Inward
    const trimInwardSize = -trimStrokeWidth;
    const trimSideExpansion = 0.03; // Approx 1/32" - 1/16" thickness

    return (
        <group position={[0, 0, mountZ]} castShadow>

            {/* 0. SIMULATED SHADOWS */}
            <group>
                {/* Wall Shadow Only */}
                <group position={[0.3, -1.5, shadowZ2]}>
                    <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.15} material={shadowMats.wallCore}>{line}</Text3D>
                    <Text3D font={fontUrl} size={letterHeight} height={0} position={[0, 0, 0.01]} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.4} material={shadowMats.wallMid}>{line}</Text3D>
                    <Text3D font={fontUrl} size={letterHeight} height={0} position={[0, 0, 0.02]} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.8} material={shadowMats.wallOuter}>{line}</Text3D>
                </group>
            </group>

            {/* 1. THE CAN (Returns) */}
            <Text3D
              ref={meshRef}
              font={fontUrl}
              size={letterHeight}
              height={canHeight}
              curveSegments={12}
              bevelEnabled={true}
              bevelThickness={0} 
              bevelSize={0}
              material={canMaterial}
              visible={visibility.returns}
              renderOrder={10}
            >
              {line}
            </Text3D>

            {/* 1b. THE BACKER (Structure) */}
            {!isHalo && (
                <Text3D
                    font={fontUrl}
                    size={letterHeight}
                    height={0.118} // 3mm ACM
                    position={[0, 0, 0]}
                    curveSegments={12}
                    bevelEnabled={true}
                    bevelThickness={0}
                    bevelSize={-0.05} 
                    material={returnMaterial} 
                    visible={visibility.backers}
                    renderOrder={10}
                >
                    {line}
                </Text3D>
            )}

            {/* 2. FACE ASSEMBLY (Front Lit) */}
            {!isHalo && (
                <group>
                    {/* A. ACRYLIC FACE */}
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={faceThickness}
                        position={[0, 0, faceZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0} 
                        bevelSize={-0.23} 
                        material={faceMaterial} 
                        visible={visibility.faces}
                        renderOrder={15}
                    >
                        {line}
                    </Text3D>

                    {/* B. TRIM CAP LIP (The Stroke) */}
                    <group visible={visibility.trimCapFaces}>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimInwardSize}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimSideExpansion}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                    </group>

                    {/* C. TRIM CAP SIDES (Returns of the cap) */}
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={0.75} 
                        position={[0, 0, trimSideZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0}
                        bevelSize={trimSideExpansion}
                        material={[invisibleMaterial, trimCapMaterial]}
                        visible={visibility.trimCapSides}
                        renderOrder={25}
                    >
                        {line}
                    </Text3D>
                </group>
            )}

            {/* 3. HALO LIT FACE (Single piece) */}
            {isHalo && (
                <Text3D
                    font={fontUrl}
                    size={letterHeight}
                    height={faceThickness} 
                    position={[0, 0, faceZ]} 
                    curveSegments={12}
                    bevelEnabled={true}
                    bevelThickness={0} 
                    bevelSize={0}
                    material={[faceMaterial, returnMaterial]} 
                    visible={visibility.faces}
                    renderOrder={50}
                >
                    {line}
                </Text3D>
            )}

            {/* 4. HALO BACKERS & GLOW */}
            {isHalo && (
            <group>
                <Text3D
                  font={fontUrl}
                  size={letterHeight}
                  height={backerThickness}
                  position={[0, 0, backerZ]} 
                  curveSegments={12}
                  bevelEnabled={true} 
                  bevelThickness={0}
                  bevelSize={-0.20} 
                  material={haloBackerMaterial}
                  visible={visibility.backers}
                >
                  {line}
                </Text3D>

                {isLit && (
                  <>
                    <group position={[0, 0, zOffset1]}>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.core} material={glowMats1.core}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.mid} material={glowMats1.mid}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.outer} material={glowMats1.outer}>{line}</Text3D>
                    </group>

                    {isRaceway && (
                       <group position={[0, 0, zOffset2]}>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.core} material={glowMats2.core}>{line}</Text3D>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.mid} material={glowMats2.mid}>{line}</Text3D>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.outer} material={glowMats2.outer}>{line}</Text3D>
                       </group>
                    )}
                  </>
                )}
            </group>
            )}
        </group>
    )
}

import React, { useState, useEffect } from 'react';
import { Center } from '@react-three/drei';
import * as THREE from 'three';
import { SignConfig, MountType } from '../../types';
import { calculateRacewayTuckLength } from '../../services/vectorUtils';
import { LetterGroup } from './LetterGroup';
import { PartVisibility } from './utils';

interface SignLineProps {
    line: string;
    index: number;
    config: SignConfig;
    yPosition: number;
    fontUrl: string;
    letterHeight: number;
    widthFactor: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    racewayFaceZ: number;
    wallFaceZ: number;
    isHalo: boolean;
    isLit: boolean;
    isRaceway: boolean;
    racewayColor: string;
    racewayOffset: number;
    racewayH: number;
    racewayD: number;
    shadowIntensity: number;
    visibility: PartVisibility;
    onUpdateLength?: (index: number, length: number) => void;
}

export const SignLine: React.FC<SignLineProps> = ({ 
    line, index, config, yPosition, letterHeight, widthFactor, 
    racewayOffset, racewayH, racewayD, racewayColor, shadowIntensity,
    visibility,
    onUpdateLength,
    ...props 
}) => {

    // State to hold the TRUE geometry width of this line (from 3D bounding box)
    const [measuredWidth, setMeasuredWidth] = useState(0);

    // NEW LOGIC: Calculate precise tuck based on specific characters
    const preciseRacewayLength = calculateRacewayTuckLength(line, letterHeight, config.fontFamily);

    useEffect(() => {
        if (config.dimensions.racewayLengthsAuto[index] && onUpdateLength) {
            // Update parent config if auto mode is on and difference is significant
            if (Math.abs(config.dimensions.racewayLengths[index] - preciseRacewayLength) > 0.1) {
                onUpdateLength(index, preciseRacewayLength);
            }
        }
    }, [preciseRacewayLength, config.dimensions.racewayLengthsAuto, config.dimensions.racewayLengths, index, onUpdateLength]);

    const rwLength = config.dimensions.racewayLengthsAuto[index] 
      ? preciseRacewayLength
      : config.dimensions.racewayLengths[index];

    const racewayXPos = 0;
    const racewayYPos = (letterHeight * 0.5) + racewayOffset;
    const componentKey = `${line}-${config.fontFamily}-${letterHeight}`;
    const SHADOW_OFFSET_X = 0.3;
    const SHADOW_OFFSET_Y = -1.5;

    return (
        <group position={[0, yPosition, 0]}>
             <Center top disableY disableZ cacheKey={componentKey}>
                <LetterGroup 
                    line={line} 
                    letterHeight={letterHeight} 
                    visibility={visibility}
                    onMeasure={(w) => {
                        if (Math.abs(w - measuredWidth) > 0.05) setMeasuredWidth(w);
                    }}
                    {...props} 
                />
             </Center>

             {config.mount === MountType.RACEWAY && (
                <>
                  <mesh 
                      position={[racewayXPos, racewayYPos, racewayD / 2]}
                      visible={visibility.raceway}
                  > 
                      <boxGeometry args={[rwLength, racewayH, racewayD]} /> 
                      <meshStandardMaterial 
                        color={racewayColor} 
                        roughness={0.6} 
                        metalness={0.05} 
                      />
                  </mesh>

                  <group position={[racewayXPos + SHADOW_OFFSET_X, racewayYPos + SHADOW_OFFSET_Y, 0.02]}>
                      <mesh>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.5} depthWrite={false} />
                      </mesh>
                      <mesh position={[0,0,-0.001]} scale={[1.01, 1.1, 1]}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.25} depthWrite={false} />
                      </mesh>
                  </group>
                </>
              )}
        </group>
    );
};

import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  // Robust Fallback: If config.fontFamily is not found, use the first available font in the library
  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];

  // Pass the raw font object (or URL) to Text3D
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  // Use Custom Hook for Base Materials
  const materials = useSignMaterials(config, ledIntensity, shadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  let mountZ = 0; 
  if (config.mount === MountType.RACEWAY) {
    mountZ = racewayD; 
  } else if (config.mount === MountType.DIRECT) {
    mountZ = config.dimensions.standoff || 0;
  }

  // Glow Logic (Local to Renderer as it depends on geometry)
  const baseGlowOpacity = (ledIntensity / 5) * 0.5;
  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  const params1 = getGlowParams(config.mount === MountType.RACEWAY ? 0.2 : mountZ);
  const params2 = getGlowParams(mountZ);

  // Memoize glow mats
  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, stencilRef: 1, stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, stencilZFail: THREE.KeepStencilOp, stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const zOffset1 = config.mount === MountType.RACEWAY ? -mountZ + racewayD + 0.05 : -mountZ + 0.05; 
  const zOffset2 = -mountZ + 0.05;

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            // Pass fontSource (which can be JSON object) instead of fontUrl
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={0}
            isHalo={isHalo}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={shadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};

import React, { useRef, useLayoutEffect } from 'react';
import { Text3D } from '@react-three/drei';
import * as THREE from 'three';
import { PartVisibility } from './utils';

interface LetterGroupProps {
    line: string;
    fontUrl: string;
    letterHeight: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    isHalo: boolean;
    isLit: boolean;
    isRaceway: boolean;
    racewayFaceZ: number;
    wallFaceZ: number;
    visibility: PartVisibility;
    onMeasure?: (width: number) => void;
}

export const LetterGroup: React.FC<LetterGroupProps> = ({ 
    line, fontUrl, letterHeight, depth, faceThickness, trimDepth, 
    returnMaterial, faceMaterial, trimCapMaterial, haloBackerMaterial, canMaterial,
    invisibleMaterial,
    glowMats1, glowMats2, glowParams1, glowParams2, shadowMats,
    zOffset1, zOffset2, mountZ, backerZ, backerThickness,
    isHalo, isLit, isRaceway, racewayFaceZ, wallFaceZ,
    visibility,
    onMeasure
}) => {

    // Ref to measure the geometry
    const meshRef = useRef<THREE.Mesh>(null);

    useLayoutEffect(() => {
        if (meshRef.current && onMeasure) {
            // Ensure geometry is computed
            meshRef.current.geometry.computeBoundingBox();
            const box = meshRef.current.geometry.boundingBox;
            if (box) {
                const width = box.max.x - box.min.x;
                onMeasure(width);
            }
        }
    }, [line, fontUrl, letterHeight, onMeasure]);

    const shadowZ1 = racewayFaceZ - mountZ + 0.1;
    const shadowZ2 = wallFaceZ - mountZ + 0.05;

    // PHYSICAL LAYERING STRATEGY
    const faceRecess = 0.05;
    const faceZ = depth - faceThickness - faceRecess; 
    const canHeight = Math.max(0.1, depth - faceThickness - faceRecess); 
    const trimLipZ = depth; 
    const trimSideZ = depth - 0.75; 

    const trimStrokeWidth = 0.25; // 1/4" Stroke Inward
    const trimInwardSize = -trimStrokeWidth;
    const trimSideExpansion = 0.03; // Approx 1/32" - 1/16" thickness

    return (
        <group position={[0, 0, mountZ]} castShadow>

            {/* 0. SIMULATED SHADOWS */}
            <group>
                {/* Wall Shadow Only */}
                <group position={[0.3, -1.5, shadowZ2]}>
                    <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.15} material={shadowMats.wallCore}>{line}</Text3D>
                    <Text3D font={fontUrl} size={letterHeight} height={0} position={[0, 0, 0.01]} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.4} material={shadowMats.wallMid}>{line}</Text3D>
                    <Text3D font={fontUrl} size={letterHeight} height={0} position={[0, 0, 0.02]} curveSegments={8} bevelEnabled bevelThickness={0} bevelSize={0.8} material={shadowMats.wallOuter}>{line}</Text3D>
                </group>
            </group>

            {/* 1. THE CAN (Returns) */}
            <Text3D
              ref={meshRef}
              font={fontUrl}
              size={letterHeight}
              height={canHeight}
              curveSegments={12}
              bevelEnabled={true}
              bevelThickness={0} 
              bevelSize={0}
              material={canMaterial}
              visible={visibility.returns}
              renderOrder={10}
            >
              {line}
            </Text3D>

            {/* 1b. THE BACKER (Structure) */}
            {!isHalo && (
                <Text3D
                    font={fontUrl}
                    size={letterHeight}
                    height={0.118} // 3mm ACM
                    position={[0, 0, 0]}
                    curveSegments={12}
                    bevelEnabled={true}
                    bevelThickness={0}
                    bevelSize={-0.05} 
                    material={returnMaterial} 
                    visible={visibility.backers}
                    renderOrder={10}
                >
                    {line}
                </Text3D>
            )}

            {/* 2. FACE ASSEMBLY (Front Lit) */}
            {!isHalo && (
                <group>
                    {/* A. ACRYLIC FACE */}
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={faceThickness}
                        position={[0, 0, faceZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0} 
                        bevelSize={-0.23} 
                        material={faceMaterial} 
                        visible={visibility.faces}
                        renderOrder={15}
                    >
                        {line}
                    </Text3D>

                    {/* B. TRIM CAP LIP (The Stroke) */}
                    <group visible={visibility.trimCapFaces}>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimInwardSize}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimSideExpansion}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                    </group>

                    {/* C. TRIM CAP SIDES (Returns of the cap) */}
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={0.75} 
                        position={[0, 0, trimSideZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0}
                        bevelSize={trimSideExpansion}
                        material={[invisibleMaterial, trimCapMaterial]}
                        visible={visibility.trimCapSides}
                        renderOrder={25}
                    >
                        {line}
                    </Text3D>
                </group>
            )}

            {/* 3. HALO LIT FACE (Single piece) */}
            {isHalo && (
                <Text3D
                    font={fontUrl}
                    size={letterHeight}
                    height={faceThickness} 
                    position={[0, 0, faceZ]} 
                    curveSegments={12}
                    bevelEnabled={true}
                    bevelThickness={0} 
                    bevelSize={0}
                    material={[faceMaterial, returnMaterial]} 
                    visible={visibility.faces}
                    renderOrder={50}
                >
                    {line}
                </Text3D>
            )}

            {/* 4. HALO BACKERS & GLOW */}
            {isHalo && (
            <group>
                <Text3D
                  font={fontUrl}
                  size={letterHeight}
                  height={backerThickness}
                  position={[0, 0, backerZ]} 
                  curveSegments={12}
                  bevelEnabled={true} 
                  bevelThickness={0}
                  bevelSize={-0.40} 
                  material={haloBackerMaterial}
                  visible={visibility.backers}
                >
                  {line}
                </Text3D>

                {isLit && (
                  <>
                    <group position={[0, 0, zOffset1]}>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.core} material={glowMats1.core}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.mid} material={glowMats1.mid}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.outer} material={glowMats1.outer}>{line}</Text3D>
                    </group>

                    {isRaceway && (
                       <group position={[0, 0, zOffset2]}>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.core} material={glowMats2.core}>{line}</Text3D>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.mid} material={glowMats2.mid}>{line}</Text3D>
                          <Text3D font={fontUrl} size={letterHeight} height={0} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.outer} material={glowMats2.outer}>{line}</Text3D>
                       </group>
                    )}
                  </>
                )}
            </group>
            )}
        </group>
    )
}

