          {/* Only show wall color picker if no texture is selected, otherwise texture dominates */}
          {config.wallTexture === WallTexture.NONE && (
            <div>
              <label className="block text-xs text-slate-500 mb-1">Color</label>
              <div className="flex items-center gap-2">
                <input 
                  type="color" 
                  value={config.wallColor}
                  onChange={(e) => update('wallColor', e.target.value)}
                  className="w-8 h-8 rounded bg-transparent cursor-pointer border-none"
                />
                <span className="text-xs text-slate-400">{config.wallColor}</span>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* 2. Layout */}
      <div className="space-y-3">
        <h3 className="font-semibold text-slate-200 border-b border-slate-700 pb-2 flex items-center gap-2">
          <LayoutGrid size={14}/> Layout
        </h3>

        <div className="grid grid-cols-2 gap-2">
          <div>
             <label className="block text-xs text-slate-500 mb-1">Type</label>
             <select 
               value={config.type} 
               onChange={(e) => update('type', e.target.value)}
               className="w-full bg-slate-800 border border-slate-700 rounded p-1.5 text-slate-200"
             >
               {Object.values(SignType).map(t => <option key={t} value={t}>{t}</option>)}
             </select>
          </div>
          <div>
            <label className="block text-xs text-slate-500 mb-1">Mount</label>
            <select 
               value={config.mount} 
               onChange={(e) => update('mount', e.target.value)}
               className="w-full bg-slate-800 border border-slate-700 rounded p-1.5 text-slate-200"
             >
               {Object.values(MountType).map(t => <option key={t} value={t}>{t}</option>)}
             </select>
          </div>
        </div>

        {/* Font Selector */}
        <div className="mt-2">
            <div className="flex justify-between items-center mb-1">
                <label className="block text-xs text-slate-500 flex items-center gap-1"><Type size={12}/> Typography</label>
                {onCalibrate && (
                   <button 
                     onClick={onCalibrate}
                     className="text-[10px] text-blue-400 hover:text-blue-300 flex items-center gap-1 bg-blue-900/30 px-1.5 py-0.5 rounded border border-blue-800/50"
                     title="Calibrate HxW Ratios"
                   >
                     <Ruler size={10} /> Calibrate Metrics
                   </button>
                )}
            </div>
            <select 
              value={config.fontFamily} 
              onChange={(e) => update('fontFamily', e.target.value)}
              className="w-full bg-slate-800 border border-slate-700 rounded p-1.5 text-slate-200"
            >
              {Object.keys(FONT_LIBRARY).map(fontName => (
                <option key={fontName} value={fontName}>{FONT_LIBRARY[fontName as keyof typeof FONT_LIBRARY].name}</option>
              ))}
            </select>
        </div>

        <div className="space-y-2 mt-4">
           <div className="flex justify-between items-center">
             <label className="block text-xs text-slate-500">Text Content</label>
             <div className="flex bg-slate-800 rounded border border-slate-700">
               <button onClick={() => update('alignment', TextAlignment.LEFT)} className={`p-1 ${config.alignment === TextAlignment.LEFT ? 'bg-blue-600 text-white' : 'text-slate-400'}`}><AlignLeft size={12}/></button>
               <button onClick={() => update('alignment', TextAlignment.CENTER)} className={`p-1 ${config.alignment === TextAlignment.CENTER ? 'bg-blue-600 text-white' : 'text-slate-400'}`}><AlignCenter size={12}/></button>
               <button onClick={() => update('alignment', TextAlignment.RIGHT)} className={`p-1 ${config.alignment === TextAlignment.RIGHT ? 'bg-blue-600 text-white' : 'text-slate-400'}`}><AlignRight size={12}/></button>
             </div>
           </div>
           {[0, 1, 2].map(i => (
             <input 
               key={i}
               type="text" 
               placeholder={`Line ${i + 1}`}
               value={config.lines[i] || ''}
               onChange={(e) => handleLineChange(i, e.target.value)}
               className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-slate-200 text-center font-bold tracking-widest"
             />
           ))}
        </div>
      </div>

      {/* 3. Dimensions */}
      <div className="space-y-3">
        <h3 className="font-semibold text-slate-200 border-b border-slate-700 pb-2">Dimensions</h3>
        <div className="grid grid-cols-2 gap-2">
          <div>
            <label className="block text-xs text-slate-500 mb-1">Letter Height (in)</label>
            <input type="number" value={config.dimensions.height} onChange={(e) => updateDim('height', Number(e.target.value))} className="w-full bg-slate-900 border border-slate-700 rounded p-1.5" />
          </div>
          <div>
            <label className="block text-xs text-slate-500 mb-1">Letter Depth (in)</label>
            <select 
              value={config.dimensions.depth} 
              onChange={(e) => updateDim('depth', Number(e.target.value))} 
              className="w-full bg-slate-900 border border-slate-700 rounded p-1.5 text-xs text-slate-200"
            >
              <option value={3}>3"</option>
              <option value={5}>5"</option>
            </select>
          </div>
        </div>

        {/* Row Spacing */}
        <div className="mb-2">
            <label className="block text-xs text-slate-500 mb-1 flex items-center gap-1"><ArrowDownUp size={10}/> Row Spacing (in)</label>
            <div className="flex items-center gap-2">
               <input 
                 type="range" min="0" max="24" step="0.5" 
                 value={config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (config.dimensions.height * 0.2)} 
                 onChange={(e) => updateDim('lineSpacing', Number(e.target.value))} 
                 className="flex-1 h-1 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-500"
               />
               <span className="text-xs w-8 text-right">{config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : Math.round(config.dimensions.height * 0.2)}"</span>
            </div>
        </div>

        {/* Raceway Dimensions Manual Override (Per Line) */}
        {config.mount === MountType.RACEWAY && (
          <div className="mt-2 space-y-2">
            <label className="text-xs text-slate-400 flex items-center gap-1 border-b border-slate-700 pb-1"><Ruler size={12}/> Raceway Lengths</label>
            {config.lines.map((line, idx) => {
              if (!line) return null;
              return (
                <div key={idx} className="bg-slate-800/30 p-2 rounded border border-slate-800">
                    <div className="flex justify-between items-center mb-1">
                      <span className="text-[10px] text-slate-500 uppercase font-bold">Line {idx + 1}</span>
                      <div className="flex items-center gap-2">
                          <span className="text-[10px] text-slate-500 uppercase">Auto</span>
                          <button 
                            onClick={() => toggleRacewayAuto(idx)}
                            className={`text-lg transition-colors ${config.dimensions.racewayLengthsAuto[idx] ? 'text-blue-400' : 'text-slate-600'}`}
                          >
                            {config.dimensions.racewayLengthsAuto[idx] ? <ToggleRight size={16} /> : <ToggleLeft size={16} />}
                          </button>
                      </div>
                    </div>
                    <input 
                        type="number" 
                        disabled={config.dimensions.racewayLengthsAuto[idx]}
                        value={config.dimensions.racewayLengths[idx]} 
                        onChange={(e) => updateRacewayLength(idx, Number(e.target.value))}
                        className={`w-full bg-slate-900 border border-slate-700 rounded p-1.5 text-xs ${config.dimensions.racewayLengthsAuto[idx] ? 'opacity-50 cursor-not-allowed' : ''}`}
                    />
                </div>
              );
            })}
          </div>
        )}

      </div>

      {/* 4. Materials & Construction */}
      <div className="space-y-3">
         <h3 className="font-semibold text-slate-200 border-b border-slate-700 pb-2 flex items-center gap-2">
            <Layers size={14}/> Construction
         </h3>

         {/* Face Configuration */}
         <div className="grid grid-cols-2 gap-2">
            <div>
               <label className="block text-xs text-slate-500 mb-1">Face Material</label>
               <select 
                 value={config.faceMaterial} 
                 onChange={(e) => update('faceMaterial', e.target.value)}
                 className="w-full bg-slate-800 border border-slate-700 rounded p-1.5 text-slate-200 text-xs"
               >
                 {Object.values(FaceMaterial).map(t => <option key={t} value={t}>{t}</option>)}
               </select>
            </div>
            <div>
               <label className="block text-xs text-slate-500 mb-1">Thickness</label>
               <select 
                 value={config.faceThickness} 
                 onChange={(e) => update('faceThickness', Number(e.target.value))}
                 className="w-full bg-slate-800 border border-slate-700 rounded p-1.5 text-slate-200 text-xs"
               >
                 <option value={0.1875}>3/16"</option>
                 <option value={0.25}>1/4"</option>
               </select>
            </div>
         </div>
      </div>

      {/* 5. Finishes */}
      <div className="space-y-4">
        <h3 className="font-semibold text-slate-200 border-b border-slate-700 pb-2">Finishes</h3>

        {/* Vinyl */}
        <div>
           <label className="block text-xs text-slate-500 mb-1">Face Vinyl Series</label>
           <select 
             value={config.colors.vinylSeries} 
             onChange={(e) => {
                updateColor('vinylSeries', e.target.value);
                const newSeries = VINYL_SERIES[e.target.value as keyof typeof VINYL_SERIES];
                if(newSeries && newSeries.length > 0) updateColor('face', newSeries[0].name);
             }}
             className="w-full bg-slate-800 border border-slate-700 rounded p-1.5 text-slate-200 mb-2"
           >
             {Object.keys(VINYL_SERIES).map(k => <option key={k} value={k}>{k}</option>)}
           </select>

           <label className="block text-xs text-slate-500 mb-2">Vinyl Color</label>
           <div className="grid grid-cols-5 gap-2 mb-4">
             {currentVinylOptions.map((c) => (
                <button
                  key={c.name}
                  onClick={() => updateColor('face', c.name)}
                  className={`w-8 h-8 rounded-full border-2 transition-all relative group ${config.colors.face === c.name ? 'border-white scale-110' : 'border-slate-600 hover:border-slate-400'}`}
                  style={{ backgroundColor: c.hex }}
                >
                   <span className="absolute bottom-full mb-2 left-1/2 -translate-x-1/2 w-max bg-black text-white text-[10px] px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-10">{c.name}</span>
                </button>
             ))}
           </div>
        </div>

        <ColorGridPicker 
          label="Return (Coil)" 
          options={RETURN_COLORS} 
          selected={config.colors.return} 
          onSelect={(v) => updateColor('return', v)} 
        />

        <ColorGridPicker 
          label="Trim Cap" 
          options={TRIM_CAP_COLORS} 
          selected={config.colors.trimCap} 
          onSelect={(v) => updateColor('trimCap', v)} 
        />

        {/* Backer Paint Selection */}
        {config.mount === MountType.BACKER && (
          <div className="space-y-2 border-t border-slate-800 pt-2 mt-2">
             <ColorGridPicker 
               label="Backer Panel Paint" 
               options={PAINT_COLORS} 
               selected={config.colors.backer} 
               onSelect={(v) => updateColor('backer', v)} 
             />
          </div>
        )}

        {config.mount === MountType.RACEWAY && (
          <div className="space-y-2">
            <ColorGridPicker 
              label="Raceway Paint" 
              options={PAINT_COLORS} 
              selected={config.colors.raceway} 
              onSelect={(v) => updateColor('raceway', v)} 
            />
          </div>
        )}

      </div>
    </div>
  );
};

import { useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, IlluminationType } from '../../types';
import { RETURN_COLORS, TRIM_CAP_COLORS, PAINT_COLORS } from '../../constants';
import { getHex, getVinylHex, getMaterialProps, LED_HEX_MAP } from './utils';

export const useSignMaterials = (config: SignConfig, ledIntensity: number, shadowIntensity: number) => {
    return useMemo(() => {
        const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
        const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;

        const faceColorHex = getVinylHex(config.colors.vinylSeries, config.colors.face);
        const returnColorHex = getHex(config.colors.return, RETURN_COLORS);
        const trimCapColorHex = getHex(config.colors.trimCap, TRIM_CAP_COLORS);
        const ledHex = LED_HEX_MAP[config.ledColor] || '#FFFFFF';

        // Lookup Backer Paint Color
        const backerPaintObj = PAINT_COLORS.find(c => c.name === config.colors.backer);
        const backerColorHex = backerPaintObj ? backerPaintObj.hex : '#ffffff';

        const faceColorThree = new THREE.Color(faceColorHex);
        const ledColorThree = new THREE.Color(ledHex);

        // BLACK VINYL LOGIC
        const isBlackVinyl = config.colors.face.includes('Black');

        let finalEmissiveColor: THREE.Color;
        let boostFactor = 1.0;

        if (isBlackVinyl) {
            finalEmissiveColor = ledColorThree.clone();
        } else {
            const maxComponent = Math.max(faceColorThree.r, faceColorThree.g, faceColorThree.b);
            const normalizedBase = faceColorThree.clone();
            if (maxComponent > 0.01) {
                normalizedBase.multiplyScalar(1 / maxComponent);
            }
            finalEmissiveColor = normalizedBase.clone().multiply(ledColorThree);
            const luminance = 0.2126 * finalEmissiveColor.r + 0.7152 * finalEmissiveColor.g + 0.0722 * finalEmissiveColor.b;
            boostFactor = 1.0 + ((1.0 - Math.min(1.0, Math.sqrt(luminance))) * 3.5);
        }

        let finalIntensity = 0;
        if (isFrontLit) {
            if (isBlackVinyl) {
                finalIntensity = ledIntensity * 0.01;
            } else {
                finalIntensity = ledIntensity * 1.5 * boostFactor;
            }
        }

        const returnMatProps = getMaterialProps(config.colors.return);

        const returnMaterial = new THREE.MeshStandardMaterial({
          color: returnColorHex,
          roughness: returnMatProps.roughness,
          metalness: returnMatProps.metalness, 
        });

        const invisibleMaterial = new THREE.MeshBasicMaterial({ visible: false });
        const canMaterial = [invisibleMaterial, returnMaterial];

        let faceMaterial: THREE.MeshStandardMaterial;

        // If Dual Lit, face is lit. If Just Halo, face is opaque (usually return color or vinyl color but opaque).
        if (!isFrontLit) {
            // Halo Only or Non-Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: isHalo ? returnColorHex : faceColorHex, // If Halo, usually face matches can, else vinyl
              roughness: returnMatProps.roughness,
              metalness: returnMatProps.metalness,
            });
        } else {
            // Front Lit or Dual Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: faceColorHex,
              roughness: 0.1, 
              metalness: 0.0,
              envMapIntensity: 1.5,
              emissive: finalEmissiveColor,
              emissiveIntensity: finalIntensity,
              toneMapped: false, 
              transparent: false,
              opacity: 1.0, 
            });
        }

        const trimCapMaterial = new THREE.MeshStandardMaterial({
          color: trimCapColorHex,
          roughness: 0.5,
          metalness: 0.1,
        });

        // Material for the clear polycarb back of the LETTER (for halo)
        const haloBackerMaterial = new THREE.MeshStandardMaterial({
          color: '#ffffff',
          emissive: ledHex,
          emissiveIntensity: ledIntensity * 3,
          toneMapped: false, 
          roughness: 0.2,
          metalness: 0.0,
          side: THREE.DoubleSide,
          transparent: true,
          opacity: 0.9
        });

        // Material for the Mounting Backer Panel (ACM)
        const mountingBackerMaterial = new THREE.MeshStandardMaterial({
            color: backerColorHex,
            roughness: 0.6,
            metalness: 0.1,
        });

        const shadowMats = {
          raceway: new THREE.MeshBasicMaterial({ color: '#000000', transparent: true, opacity: shadowIntensity, side: THREE.FrontSide, depthWrite: false }),
          wallCore: new THREE.MeshBasicMaterial({ color: '#000000', transparent: true, opacity: shadowIntensity * 0.6, side: THREE.FrontSide, depthWrite: false }),
          wallMid: new THREE.MeshBasicMaterial({ color: '#000000', transparent: true, opacity: shadowIntensity * 0.3, side: THREE.FrontSide, depthWrite: false }),
          wallOuter: new THREE.MeshBasicMaterial({ color: '#000000', transparent: true, opacity: shadowIntensity * 0.2, side: THREE.FrontSide, depthWrite: false })
        };

        return { 
            faceMaterial, returnMaterial, canMaterial, 
            trimCapMaterial, invisibleMaterial,
            haloBackerMaterial, mountingBackerMaterial, 
            shadowMats, ledHex 
        };

    }, [config.colors, config.ledColor, config.illumination, ledIntensity, shadowIntensity]);
};

import React, { useRef, useLayoutEffect } from 'react';
import { Text3D } from '@react-three/drei';
import * as THREE from 'three';
import { PartVisibility } from './utils';

interface LetterGroupProps {
    line: string;
    fontUrl: string;
    letterHeight: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material; // New material
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number; // This is the base Z for the letter group
    backerZ: number;
    backerThickness: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    racewayFaceZ: number;
    wallFaceZ: number;
    visibility: PartVisibility;
    onMeasure?: (width: number) => void;
}

export const LetterGroup: React.FC<LetterGroupProps> = ({ 
    line, fontUrl, letterHeight, depth, faceThickness, trimDepth, 
    returnMaterial, faceMaterial, trimCapMaterial, haloBackerMaterial, mountingBackerMaterial, canMaterial,
    invisibleMaterial,
    glowMats1, glowMats2, glowParams1, glowParams2, shadowMats,
    zOffset1, zOffset2, mountZ, backerZ, backerThickness,
    isHalo, isFrontLit, isLit, isRaceway, isBackerMount, backerLit, racewayFaceZ, wallFaceZ,
    visibility,
    onMeasure
}) => {

    // Ref to measure the geometry
    const meshRef = useRef<THREE.Mesh>(null);

    useLayoutEffect(() => {
        if (meshRef.current && onMeasure) {
            // Ensure geometry is computed
            meshRef.current.geometry.computeBoundingBox();
            const box = meshRef.current.geometry.boundingBox;
            if (box) {
                const width = box.max.x - box.min.x;
                onMeasure(width);
            }
        }
    }, [line, fontUrl, letterHeight, onMeasure]);

    const shadowZ1 = racewayFaceZ - mountZ + 0.1;
    const shadowZ2 = wallFaceZ - mountZ + 0.05;

    // PHYSICAL LAYERING STRATEGY
    const faceRecess = 0.05;
    const faceZ = depth - faceThickness - faceRecess; 
    const canHeight = Math.max(0.1, depth - faceThickness - faceRecess); 
    const trimLipZ = depth; 
    const trimSideZ = depth - 0.75; 

    const trimStrokeWidth = 0.25; // 1/4" Stroke Inward
    const trimInwardSize = -trimStrokeWidth;
    const trimSideExpansion = 0.03; // Approx 1/32" - 1/16" thickness

    // OPTIMIZATION: Segment count for diffuse elements (shadows/glows)
    const LOW_RES_SEGMENTS = 32;

    // BACKER PANEL GEOMETRY ("The Cloud")
    // We use a large positive bevelSize to create the offset shape
    const backerOffset = 1.5; // 1.5 inches padding around letters
    const backerPanelThickness = 0.125; // 3mm ACM

    // If Backer Mount, the letters sit ON TOP of the backer.
    // mountZ passed in is: Wall -> Mount Standoff -> Backer (Front Face).
    // Actually, in ChannelLetterRenderer, mountZ is passed as the base for the LetterGroup.
    // If Backer Mount: mountZ = mountStandoff + letterStandoff. 
    // We need to render the Backer BEHIND the letters.
    // So relative to the LetterGroup (0,0,0), the Backer is at Z = -letterStandoff.
    // And the backer thickness expands backwards.

    return (
        <group position={[0, 0, mountZ]} castShadow>

            {/* 0. MOUNTING BACKER PANEL (Cloud Shape) */}
            {isBackerMount && (
                <group position={[0, 0, -0.5]}> {/* Hardcoded -0.5 is risky, should use config.letterStandoff passed in props. But mountZ handles the main offset. */}
                     {/* 
                        Actually, let's look at ChannelLetterRenderer logic.
                        It sets mountZ. If we render backer here, we need to know where it is relative to the letter.
                        Let's assume LetterGroup 0 is the BACK of the letter can.
                     */}
                     <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={backerPanelThickness}
                        position={[0, 0, -0.25]} // Slightly behind letter back
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0} 
                        bevelSize={backerOffset} 
                        material={mountingBackerMaterial} 
                        visible={visibility.backers}
                        renderOrder={5}
                     >
                        {line}
                     </Text3D>

                     {/* Backer Halo Glow (Washing Wall) */}
                     {backerLit && (
                        <group position={[0, 0, -0.5]}> 
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 0.5} material={glowMats2.core}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 2.0} material={glowMats2.mid}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 6.0} material={glowMats2.outer}>{line}</Text3D>
                        </group>
                     )}
                </group>
            )}

            {/* 1. THE CAN (Returns) */}
            <Text3D
              ref={meshRef}
              font={fontUrl}
              size={letterHeight}
              height={canHeight}
              curveSegments={12}
              bevelEnabled={true}
              bevelThickness={0} 
              bevelSize={0}
              material={canMaterial}
              visible={visibility.returns}
              renderOrder={10}
            >
              {line}
            </Text3D>

            {/* 2. FACE ASSEMBLY */}
            {isFrontLit && (
                <group>
                    {/* A. ACRYLIC FACE */}
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={faceThickness}
                        position={[0, 0, faceZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0} 
                        bevelSize={-0.23} 
                        material={faceMaterial} 
                        visible={visibility.faces}
                        renderOrder={15}
                    >
                        {line}
                    </Text3D>

                    {/* B. TRIM CAP */}
                    <group visible={visibility.trimCapFaces}>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimInwardSize}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                    </group>
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={0.75} 
                        position={[0, 0, trimSideZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0}
                        bevelSize={trimSideExpansion}
                        material={[invisibleMaterial, trimCapMaterial]}
                        visible={visibility.trimCapSides}
                        renderOrder={25}
                    >
                        {line}
                    </Text3D>
                </group>
            )}

            {/* 3. HALO LIT FACE (Rear Poly) & GLOW */}
            {isHalo && (
            <group>
                {/* Clear Back of Letter */}
                <Text3D
                  font={fontUrl}
                  size={letterHeight}
                  height={backerThickness}
                  position={[0, 0, backerZ]} 
                  curveSegments={12}
                  bevelEnabled={true} 
                  bevelThickness={0}
                  bevelSize={-0.05} // Slightly inset
                  material={haloBackerMaterial}
                  visible={visibility.backers}
                >
                  {line}
                </Text3D>

                {/* Glow Washing the Backer Panel (or Wall) */}
                {isLit && (
                  <group position={[0, 0, -0.1]}>
                      <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.core} material={glowMats1.core}>{line}</Text3D>
                      <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.mid} material={glowMats1.mid}>{line}</Text3D>
                      <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.outer} material={glowMats1.outer}>{line}</Text3D>
                  </group>
                )}
            </group>
            )}
        </group>
    )
}

import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  const materials = useSignMaterials(config, ledIntensity, shadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  let mountZ = 0; 
  if (config.mount === MountType.RACEWAY) {
    mountZ = racewayD; 
  } else if (config.mount === MountType.DIRECT) {
    mountZ = config.dimensions.standoff || 0;
  } else if (config.mount === MountType.BACKER) {
    // Wall -> Mount Standoff -> Backer (1/8") -> Letter Standoff -> Letter
    // This mountZ is where the LETTER starts (Back of can)
    // 0 = Wall
    mountZ = (config.dimensions.standoff || 0) + 0.125 + (config.dimensions.letterStandoff || 0);
  }

  // Glow Logic
  const baseGlowOpacity = (ledIntensity / 5) * 0.5;
  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  // Params1: Halo wash behind letter (hits backer or wall)
  // Params2: Halo wash behind backer (hits wall)
  const params1 = getGlowParams(config.mount === MountType.BACKER ? (config.dimensions.letterStandoff || 0) : mountZ);
  const params2 = getGlowParams(config.dimensions.standoff || 1.5);

  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, stencilRef: 1, stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, stencilZFail: THREE.KeepStencilOp, stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const zOffset1 = config.mount === MountType.RACEWAY ? -mountZ + racewayD + 0.05 : -mountZ + 0.05; 
  const zOffset2 = -mountZ + 0.05;

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            mountingBackerMaterial={materials.mountingBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={0}
            isHalo={isHalo}
            isFrontLit={isFrontLit}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            isBackerMount={config.mount === MountType.BACKER}
            backerLit={config.backerLit}
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={shadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};

import React, { useState, useEffect } from 'react';
import { Center } from '@react-three/drei';
import * as THREE from 'three';
import { SignConfig, MountType } from '../../types';
import { calculateRacewayTuckLength } from '../../services/vectorUtils';
import { LetterGroup } from './LetterGroup';
import { PartVisibility } from './utils';

interface SignLineProps {
    line: string;
    index: number;
    config: SignConfig;
    yPosition: number;
    fontUrl: string;
    letterHeight: number;
    widthFactor: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    racewayFaceZ: number;
    wallFaceZ: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    racewayColor: string;
    racewayOffset: number;
    racewayH: number;
    racewayD: number;
    shadowIntensity: number;
    visibility: PartVisibility;
    onUpdateLength?: (index: number, length: number) => void;
}

export const SignLine: React.FC<SignLineProps> = ({ 
    line, index, config, yPosition, letterHeight, widthFactor, 
    racewayOffset, racewayH, racewayD, racewayColor, shadowIntensity,
    visibility,
    onUpdateLength,
    ...props 
}) => {

    // State to hold the TRUE geometry width of this line (from 3D bounding box)
    const [measuredWidth, setMeasuredWidth] = useState(0);

    // NEW LOGIC: Calculate precise tuck based on specific characters
    const preciseRacewayLength = calculateRacewayTuckLength(line, letterHeight, config.fontFamily);

    useEffect(() => {
        if (config.dimensions.racewayLengthsAuto[index] && onUpdateLength) {
            // Update parent config if auto mode is on and difference is significant
            if (Math.abs(config.dimensions.racewayLengths[index] - preciseRacewayLength) > 0.1) {
                onUpdateLength(index, preciseRacewayLength);
            }
        }
    }, [preciseRacewayLength, config.dimensions.racewayLengthsAuto, config.dimensions.racewayLengths, index, onUpdateLength]);

    const rwLength = config.dimensions.racewayLengthsAuto[index] 
      ? preciseRacewayLength
      : config.dimensions.racewayLengths[index];

    const racewayXPos = 0;
    const racewayYPos = (letterHeight * 0.5) + racewayOffset;
    const componentKey = `${line}-${config.fontFamily}-${letterHeight}`;
    const SHADOW_OFFSET_X = 0.3;
    const SHADOW_OFFSET_Y = -1.5;

    return (
        <group position={[0, yPosition, 0]}>
             <Center top disableY disableZ cacheKey={componentKey}>
                <LetterGroup 
                    line={line} 
                    letterHeight={letterHeight} 
                    visibility={visibility}
                    onMeasure={(w) => {
                        if (Math.abs(w - measuredWidth) > 0.05) setMeasuredWidth(w);
                    }}
                    {...props} 
                />
             </Center>

             {config.mount === MountType.RACEWAY && (
                <>
                  <mesh 
                      position={[racewayXPos, racewayYPos, racewayD / 2]}
                      visible={visibility.raceway}
                  > 
                      <boxGeometry args={[rwLength, racewayH, racewayD]} /> 
                      <meshStandardMaterial 
                        color={racewayColor} 
                        roughness={0.6} 
                        metalness={0.05} 
                      />
                  </mesh>

                  <group position={[racewayXPos + SHADOW_OFFSET_X, racewayYPos + SHADOW_OFFSET_Y, 0.02]}>
                      <mesh>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.5} depthWrite={false} />
                      </mesh>
                      <mesh position={[0,0,-0.001]} scale={[1.01, 1.1, 1]}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.25} depthWrite={false} />
                      </mesh>
                  </group>
                </>
              )}
        </group>
    );
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Canvas, useThree, useFrame } from '@react-three/fiber';
