          <p style="margin: 5px 0;"><strong>Size:</strong> ${Math.round(packet.config.dimensions.calculatedWidth)}" W x ${packet.config.dimensions.height}" H</p>
          <p style="margin: 5px 0;"><strong>Mount:</strong> ${packet.config.mount}</p>
          <p style="margin: 5px 0;"><strong>Face:</strong> ${packet.config.colors.face}</p>
