        <div style="background: #f8fafc; padding: 15px; border: 1px solid #e2e8f0; border-radius: 4px;">
          <h3 style="margin: 0 0 10px 0; font-size: 14px; color: #475569; text-transform: uppercase;">Site Conditions</h3>
          <p style="margin: 5px 0;"><strong>Wall:</strong> ${survey.wallType}</p>
          <p style="margin: 5px 0;"><strong>Install Height:</strong> ${survey.installHeight} ft</p>
          <p style="margin: 5px 0;"><strong>Access:</strong> ${survey.accessType}</p>
          <p style="margin: 5px 0;"><strong>Power:</strong> ${survey.powerAccess}</p>
        </div>
      </div>

      <div style="margin-bottom: 30px;">
        <h3 style="margin: 0 0 10px 0; font-size: 16px; color: #1e293b;">AI Safety & Logistics Analysis</h3>
        <div style="background: #f1f5f9; padding: 20px; border-left: 4px solid #6366f1; white-space: pre-wrap; font-family: monospace; font-size: 13px; line-height: 1.5;">
          ${installTicket || 'No AI analysis generated yet.'}
        </div>
      </div>

      ${packet.warnings.length > 0 ? `
        <div style="border: 1px solid #fca5a5; background: #fef2f2; padding: 15px; border-radius: 4px;">
          <h3 style="margin: 0 0 10px 0; color: #991b1b; font-size: 14px;">Production Warnings</h3>
          <ul style="margin: 0; padding-left: 20px; color: #7f1d1d;">
            ${packet.warnings.map(w => `<li style="margin-bottom: 5px;">${w}</li>`).join('')}
          </ul>
        </div>
      ` : ''}
    `;
  };

  const handleExport = (type: 'bom' | 'ticket') => {
    const printWindow = window.open('', '_blank', 'width=800,height=900');
    if (!printWindow) return;

    // Generate Blueprint HTML (Full Layout)
    const blueprintHtml = generateBlueprintHTML(packet.config);

    const title = type === 'bom' ? 'Bill of Materials' : 'Production Ticket';
    const content = type === 'bom' ? generateBomHtml(blueprintHtml) : generateTicketHtml(blueprintHtml);

    printWindow.document.write(`
