            @media print { 
              body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
              .no-print { display: none; }
            }
          </style>
        </head>
        <body>
          <div style="display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 30px; border-bottom: 4px solid #0f172a; padding-bottom: 20px;">
            <div>
              <h1 style="margin: 0; font-size: 24px; text-transform: uppercase; letter-spacing: -0.5px;">SignFabricator</h1>
              <p style="margin: 5px 0 0 0; color: #64748b; font-size: 14px;">Enterprise Manufacturing Output</p>
            </div>
            <div style="text-align: right;">
              <div style="font-size: 18px; font-weight: bold; font-family: monospace;">Order #${packet.id}</div>
