import React, { useState, useEffect } from 'react';
import { Center } from '@react-three/drei';
import * as THREE from 'three';
import { SignConfig, MountType } from '../../types';
import { calculateRacewayTuckLength } from '../../services/vectorUtils';
import { LetterGroup } from './LetterGroup';
import { PartVisibility } from './utils';

interface SignLineProps {
    line: string;
    index: number;
    config: SignConfig;
    yPosition: number;
    fontUrl: string;
    letterHeight: number;
    widthFactor: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    racewayFaceZ: number;
    wallFaceZ: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    racewayColor: string;
    racewayOffset: number;
    racewayH: number;
    racewayD: number;
    shadowIntensity: number;
    visibility: PartVisibility;
    onUpdateLength?: (index: number, length: number) => void;
}

export const SignLine: React.FC<SignLineProps> = ({ 
    line, index, config, yPosition, letterHeight, widthFactor, 
    racewayOffset, racewayH, racewayD, racewayColor, shadowIntensity,
    visibility,
    wallFaceZ, // Destructured for access
    onUpdateLength,
    ...props 
}) => {

    // State to hold the TRUE geometry width of this line (from 3D bounding box)
    const [measuredWidth, setMeasuredWidth] = useState(0);

    // NEW LOGIC: Calculate precise tuck based on specific characters
    const preciseRacewayLength = calculateRacewayTuckLength(line, letterHeight, config.fontFamily);

    useEffect(() => {
        if (config.dimensions.racewayLengthsAuto[index] && onUpdateLength) {
            // Update parent config if auto mode is on and difference is significant
            if (Math.abs(config.dimensions.racewayLengths[index] - preciseRacewayLength) > 0.1) {
                onUpdateLength(index, preciseRacewayLength);
            }
        }
    }, [preciseRacewayLength, config.dimensions.racewayLengthsAuto, config.dimensions.racewayLengths, index, onUpdateLength]);

    const rwLength = config.dimensions.racewayLengthsAuto[index] 
      ? preciseRacewayLength
      : config.dimensions.racewayLengths[index];

    const racewayXPos = 0;
    const racewayYPos = (letterHeight * 0.5) + racewayOffset;
    const componentKey = `${line}-${config.fontFamily}-${letterHeight}`;
    const SHADOW_OFFSET_X = 0.3;
    const SHADOW_OFFSET_Y = -1.5;

    // Raceway Shadow Z Position logic:
    // This group is local to SignLine (which is at global Z=0, Y=yPosition).
    // The shadow needs to be at global Z = wallFaceZ.
    // So Local Z = wallFaceZ + small epsilon.
    const racewayShadowZ = wallFaceZ + 0.05;

    return (
        <group position={[0, yPosition, 0]}>
             <Center top disableY disableZ cacheKey={componentKey}>
                <LetterGroup 
                    line={line} 
                    letterHeight={letterHeight} 
                    visibility={visibility}
                    wallFaceZ={wallFaceZ}
                    onMeasure={(w) => {
                        if (Math.abs(w - measuredWidth) > 0.05) setMeasuredWidth(w);
                    }}
                    {...props} 
                />
             </Center>

             {config.mount === MountType.RACEWAY && (
                <>
                  <mesh 
                      position={[racewayXPos, racewayYPos, racewayD / 2]}
                      visible={visibility.raceway}
                  > 
                      <boxGeometry args={[rwLength, racewayH, racewayD]} /> 
                      <meshStandardMaterial 
                        color={racewayColor} 
                        roughness={0.6} 
                        metalness={0.05} 
                      />
                  </mesh>

                  <group position={[racewayXPos + SHADOW_OFFSET_X, racewayYPos + SHADOW_OFFSET_Y, racewayShadowZ]}>
                      <mesh>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.5} depthWrite={false} />
                      </mesh>
                      <mesh position={[0,0,-0.001]} scale={[1.01, 1.1, 1]}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.25} depthWrite={false} />
                      </mesh>
                  </group>
                </>
              )}
        </group>
    );
};

import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  const materials = useSignMaterials(config, ledIntensity, shadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  // --- Z-DEPTH CALCULATION ---
  // Scene Reference: Wall is at Z = -0.5
  const WALL_Z = -0.5;
  const BACKER_THICK = 0.125;

  let mountZ = 0; // Global Z position where the Letter Group (can back) starts
  let targetSurfaceZ = WALL_Z; // Global Z position of the surface behind the letter (for shadows/halo)

  if (config.mount === MountType.RACEWAY) {
      // Raceway Box: Z=0 to Z=4. Face is at Z=4.
      mountZ = racewayD; 
      targetSurfaceZ = racewayD; // Shadows fall on raceway face
  } 
  else if (config.mount === MountType.BACKER) {
      // Wall -> Standoff -> Backer -> LetterStandoff -> Letter
      const mStandoff = config.dimensions.standoff || 0;
      const lStandoff = config.dimensions.letterStandoff || 0;

      const backerFaceZ = WALL_Z + mStandoff + BACKER_THICK;
      mountZ = backerFaceZ + lStandoff;
      targetSurfaceZ = backerFaceZ; // Shadows fall on Backer
  } 
  else {
      // DIRECT MOUNT
      // Letter is offset from wall by 'standoff'
      const standoff = config.dimensions.standoff || 0;
      mountZ = WALL_Z + standoff;
      targetSurfaceZ = WALL_Z; // Shadows fall on Wall
  }

  // Calculate Local Offsets for LetterGroup (which is positioned at mountZ)
  // Offset = TargetGlobal - CurrentGlobal + Epsilon
  const zOffset1 = (targetSurfaceZ - mountZ) + 0.05; // Primary Shadow/Halo Plane
  const zOffset2 = (WALL_Z - mountZ) + 0.05; // Wall Plane (for Backer Halo)

  // Glow Logic - Intensity Boosted for visibility
  // Updated multiplier to 2.5 to restore Color Splash
  const baseGlowOpacity = (ledIntensity / 5) * 2.5;

  // Distance from Light Source (Letter Back) to Surface
  // If Raceway: Distance is 0 (flush). If Direct: Distance is Standoff.
  const distToSurface = Math.abs(mountZ - targetSurfaceZ);

  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  const params1 = getGlowParams(distToSurface);
  const params2 = getGlowParams(config.dimensions.standoff || 1.5);

  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, stencilRef: 1, stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, stencilZFail: THREE.KeepStencilOp, stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            mountingBackerMaterial={materials.mountingBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={WALL_Z}
            isHalo={isHalo}
            isFrontLit={isFrontLit}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            isBackerMount={config.mount === MountType.BACKER}
            backerLit={config.backerLit}
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={shadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};

import { useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, IlluminationType } from '../../types';
import { RETURN_COLORS, TRIM_CAP_COLORS, PAINT_COLORS } from '../../constants';
import { getHex, getVinylHex, getMaterialProps, LED_HEX_MAP } from './utils';

export const useSignMaterials = (config: SignConfig, ledIntensity: number, shadowIntensity: number) => {
    return useMemo(() => {
        const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
        const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;

        const faceColorHex = getVinylHex(config.colors.vinylSeries, config.colors.face);
        const returnColorHex = getHex(config.colors.return, RETURN_COLORS);
        const trimCapColorHex = getHex(config.colors.trimCap, TRIM_CAP_COLORS);
        const ledHex = LED_HEX_MAP[config.ledColor] || '#FFFFFF';

        // Lookup Backer Paint Color
        const backerPaintObj = PAINT_COLORS.find(c => c.name === config.colors.backer);
        const backerColorHex = backerPaintObj ? backerPaintObj.hex : '#ffffff';

        const faceColorThree = new THREE.Color(faceColorHex);
        const ledColorThree = new THREE.Color(ledHex);

        // BLACK VINYL LOGIC
        const isBlackVinyl = config.colors.face.includes('Black');

        let finalEmissiveColor: THREE.Color;
        let boostFactor = 1.0;

        if (isBlackVinyl) {
            finalEmissiveColor = ledColorThree.clone();
        } else {
            const maxComponent = Math.max(faceColorThree.r, faceColorThree.g, faceColorThree.b);
            const normalizedBase = faceColorThree.clone();
            if (maxComponent > 0.01) {
                normalizedBase.multiplyScalar(1 / maxComponent);
            }
            finalEmissiveColor = normalizedBase.clone().multiply(ledColorThree);
            const luminance = 0.2126 * finalEmissiveColor.r + 0.7152 * finalEmissiveColor.g + 0.0722 * finalEmissiveColor.b;
            boostFactor = 1.0 + ((1.0 - Math.min(1.0, Math.sqrt(luminance))) * 3.5);
        }

        let finalIntensity = 0;
        if (isFrontLit) {
            if (isBlackVinyl) {
                finalIntensity = ledIntensity * 0.01;
            } else {
                finalIntensity = ledIntensity * 1.5 * boostFactor;
            }
        }

        const returnMatProps = getMaterialProps(config.colors.return);

        const returnMaterial = new THREE.MeshStandardMaterial({
          color: returnColorHex,
          roughness: returnMatProps.roughness,
          metalness: returnMatProps.metalness, 
        });

        const invisibleMaterial = new THREE.MeshBasicMaterial({ visible: false });
        const canMaterial = [invisibleMaterial, returnMaterial];

        let faceMaterial: THREE.MeshStandardMaterial;

        if (!isFrontLit) {
            // Halo Only or Non-Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: isHalo ? returnColorHex : faceColorHex, 
              roughness: returnMatProps.roughness,
              metalness: returnMatProps.metalness,
            });
        } else {
            // Front Lit or Dual Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: faceColorHex,
              roughness: 0.1, 
              metalness: 0.0,
              envMapIntensity: 1.5,
              emissive: finalEmissiveColor,
              emissiveIntensity: finalIntensity,
              toneMapped: false, 
              transparent: false,
              opacity: 1.0, 
            });
        }

        const trimCapMaterial = new THREE.MeshStandardMaterial({
          color: trimCapColorHex,
          roughness: 0.5,
          metalness: 0.1,
        });

        const haloBackerMaterial = new THREE.MeshStandardMaterial({
          color: '#ffffff',
          emissive: ledHex,
          emissiveIntensity: ledIntensity * 3,
          toneMapped: false, 
          roughness: 0.2,
          metalness: 0.0,
          side: THREE.DoubleSide,
          transparent: true,
          opacity: 0.9
        });

        const mountingBackerMaterial = new THREE.MeshStandardMaterial({
            color: backerColorHex,
            roughness: 0.6,
            metalness: 0.1,
        });

        // Shadow Materials
        // Standard (Wall) Shadows
        const wallShadowBase = { color: '#000000', transparent: true, side: THREE.FrontSide, depthWrite: false };

        // Clipped (Raceway) Shadows - Uses Stencil to only draw ON the raceway
        const clippedShadowBase = { 
            ...wallShadowBase,
            stencilWrite: true,
            stencilRef: 1,
            stencilFunc: THREE.EqualStencilFunc
        };

        const shadowMats = {
          raceway: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity }),

          wallCore: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.6 }),
          wallMid: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.3 }),
          wallOuter: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.2 }),

          clippedCore: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.6 }),
          clippedMid: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.3 }),
          clippedOuter: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.2 }),
        };

        return { 
            faceMaterial, returnMaterial, canMaterial, 
            trimCapMaterial, invisibleMaterial,
            haloBackerMaterial, mountingBackerMaterial, 
            shadowMats, ledHex 
        };

    }, [config.colors, config.ledColor, config.illumination, ledIntensity, shadowIntensity]);
};

import React, { useState, useEffect } from 'react';
import { Center } from '@react-three/drei';
import * as THREE from 'three';
import { SignConfig, MountType } from '../../types';
import { calculateRacewayTuckLength } from '../../services/vectorUtils';
import { LetterGroup } from './LetterGroup';
import { PartVisibility } from './utils';

interface SignLineProps {
    line: string;
    index: number;
    config: SignConfig;
    yPosition: number;
    fontUrl: string;
    letterHeight: number;
    widthFactor: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    racewayFaceZ: number;
    wallFaceZ: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    racewayColor: string;
    racewayOffset: number;
    racewayH: number;
    racewayD: number;
    shadowIntensity: number;
    visibility: PartVisibility;
    onUpdateLength?: (index: number, length: number) => void;
}

export const SignLine: React.FC<SignLineProps> = ({ 
    line, index, config, yPosition, letterHeight, widthFactor, 
    racewayOffset, racewayH, racewayD, racewayColor, shadowIntensity,
    visibility,
    wallFaceZ,
    onUpdateLength,
    ...props 
}) => {

    const [measuredWidth, setMeasuredWidth] = useState(0);
    const preciseRacewayLength = calculateRacewayTuckLength(line, letterHeight, config.fontFamily);

    useEffect(() => {
        if (config.dimensions.racewayLengthsAuto[index] && onUpdateLength) {
            if (Math.abs(config.dimensions.racewayLengths[index] - preciseRacewayLength) > 0.1) {
                onUpdateLength(index, preciseRacewayLength);
            }
        }
    }, [preciseRacewayLength, config.dimensions.racewayLengthsAuto, config.dimensions.racewayLengths, index, onUpdateLength]);

    const rwLength = config.dimensions.racewayLengthsAuto[index] 
      ? preciseRacewayLength
      : config.dimensions.racewayLengths[index];

    const racewayXPos = 0;
    const racewayYPos = (letterHeight * 0.5) + racewayOffset;
    const componentKey = `${line}-${config.fontFamily}-${letterHeight}`;
    const SHADOW_OFFSET_X = 0.3;
    const SHADOW_OFFSET_Y = -1.5;

    // Raceway Shadow on Wall
    const racewayShadowZ = wallFaceZ + 0.05;

    return (
        <group position={[0, yPosition, 0]}>
             <Center top disableY disableZ cacheKey={componentKey}>
                <LetterGroup 
                    line={line} 
                    letterHeight={letterHeight} 
                    visibility={visibility}
                    wallFaceZ={wallFaceZ}
                    onMeasure={(w) => {
                        if (Math.abs(w - measuredWidth) > 0.05) setMeasuredWidth(w);
                    }}
                    {...props} 
                />
             </Center>

             {config.mount === MountType.RACEWAY && (
                <>
                  <mesh 
                      position={[racewayXPos, racewayYPos, racewayD / 2]}
                      visible={visibility.raceway}
                      renderOrder={0} // Ensure rendered before shadows
                  > 
                      <boxGeometry args={[rwLength, racewayH, racewayD]} /> 
                      <meshStandardMaterial 
                        color={racewayColor} 
                        roughness={0.6} 
                        metalness={0.05} 
                        stencilWrite={true}
                        stencilRef={1}
                        stencilFunc={THREE.AlwaysStencilFunc}
                        stencilZPass={THREE.ReplaceStencilOp}
                      />
                  </mesh>

                  {/* Raceway Drop Shadow on Wall */}
                  <group position={[racewayXPos + SHADOW_OFFSET_X, racewayYPos + SHADOW_OFFSET_Y, racewayShadowZ]}>
                      <mesh>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.5} depthWrite={false} />
                      </mesh>
                      <mesh position={[0,0,-0.001]} scale={[1.01, 1.1, 1]}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.25} depthWrite={false} />
                      </mesh>
                  </group>
                </>
              )}
        </group>
    );
};

import React, { useRef, useLayoutEffect } from 'react';
