import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  // New Logic: If lights are active and it involves Halo lighting, disable shadows to prevent visual conflict.
  const lightsOn = ledIntensity > 0.1;
  const effectiveShadowIntensity = (isHalo && lightsOn) ? 0 : shadowIntensity;

  const materials = useSignMaterials(config, ledIntensity, effectiveShadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  const WALL_Z = -0.5;
  const BACKER_THICK = 0.125;

  let mountZ = 0; 
  let targetSurfaceZ = WALL_Z; 

  if (config.mount === MountType.RACEWAY) {
      mountZ = racewayD; 
      targetSurfaceZ = racewayD; 
  } 
  else if (config.mount === MountType.BACKER) {
      const mStandoff = config.dimensions.standoff || 0;
      const lStandoff = config.dimensions.letterStandoff || 0;

      const backerFaceZ = WALL_Z + mStandoff + BACKER_THICK;
      mountZ = backerFaceZ + lStandoff;
      targetSurfaceZ = backerFaceZ;
  } 
  else {
      const standoff = config.dimensions.standoff || 0;
      mountZ = WALL_Z + standoff;
      targetSurfaceZ = WALL_Z; 
  }

  const zOffset1 = (targetSurfaceZ - mountZ) + 0.05; 
  const zOffset2 = (WALL_Z - mountZ) + 0.05; 

  // Glow Logic - Intensity Boosted for visibility
  const baseGlowOpacity = (ledIntensity / 5) * 2.5;

  // Distance from Light Source (Letter Back) to Target Surface
  const distToTarget1 = Math.abs(mountZ - targetSurfaceZ);

  // Distance from Light Source to Wall (For secondary glow in Raceway mode)
  const distToTarget2 = Math.abs(mountZ - WALL_Z);

  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  // Params 1: Primary Surface (Raceway or Backer or Wall)
  const params1 = getGlowParams(distToTarget1);
  // Params 2: Wall (Used for Secondary Glow in Raceway mode)
  const params2 = getGlowParams(distToTarget2);

  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, stencilRef: 1, stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, stencilZFail: THREE.KeepStencilOp, stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            mountingBackerMaterial={materials.mountingBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={WALL_Z}
            isHalo={isHalo}
            isFrontLit={isFrontLit}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            isBackerMount={config.mount === MountType.BACKER}
            backerLit={config.backerLit}
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={effectiveShadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};

import React, { useState, useEffect } from 'react';
import { Center } from '@react-three/drei';
import * as THREE from 'three';
import { SignConfig, MountType } from '../../types';
import { calculateRacewayTuckLength } from '../../services/vectorUtils';
import { LetterGroup } from './LetterGroup';
import { PartVisibility } from './utils';

interface SignLineProps {
    line: string;
    index: number;
    config: SignConfig;
    yPosition: number;
    fontUrl: string;
    letterHeight: number;
    widthFactor: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    racewayFaceZ: number;
    wallFaceZ: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    racewayColor: string;
    racewayOffset: number;
    racewayH: number;
    racewayD: number;
    shadowIntensity: number;
    visibility: PartVisibility;
    onUpdateLength?: (index: number, length: number) => void;
}

export const SignLine: React.FC<SignLineProps> = ({ 
    line, index, config, yPosition, letterHeight, widthFactor, 
    racewayOffset, racewayH, racewayD, racewayColor, shadowIntensity,
    visibility,
    wallFaceZ,
    onUpdateLength,
    ...props 
}) => {

    const [measuredWidth, setMeasuredWidth] = useState(0);
    const preciseRacewayLength = calculateRacewayTuckLength(line, letterHeight, config.fontFamily);

    useEffect(() => {
        if (config.dimensions.racewayLengthsAuto[index] && onUpdateLength) {
            if (Math.abs(config.dimensions.racewayLengths[index] - preciseRacewayLength) > 0.1) {
                onUpdateLength(index, preciseRacewayLength);
            }
        }
    }, [preciseRacewayLength, config.dimensions.racewayLengthsAuto, config.dimensions.racewayLengths, index, onUpdateLength]);

    const rwLength = config.dimensions.racewayLengthsAuto[index] 
      ? preciseRacewayLength
      : config.dimensions.racewayLengths[index];

    const racewayXPos = 0;
    const racewayYPos = (letterHeight * 0.5) + racewayOffset;
    const componentKey = `${line}-${config.fontFamily}-${letterHeight}`;
    const SHADOW_OFFSET_X = 0.3;
    const SHADOW_OFFSET_Y = -1.5;

    // Raceway Shadow on Wall
    const racewayShadowZ = wallFaceZ + 0.05;

    return (
        <group position={[0, yPosition, 0]}>
             <Center top disableY disableZ cacheKey={componentKey}>
                <LetterGroup 
                    line={line} 
                    letterHeight={letterHeight} 
                    visibility={visibility}
                    wallFaceZ={wallFaceZ}
                    onMeasure={(w) => {
                        if (Math.abs(w - measuredWidth) > 0.05) setMeasuredWidth(w);
                    }}
                    {...props} 
                />
             </Center>

             {config.mount === MountType.RACEWAY && (
                <>
                  {/* Raceway Box - Writes Stencil Ref 5 */}
                  <mesh 
                      position={[racewayXPos, racewayYPos, racewayD / 2]}
                      visible={visibility.raceway}
                      renderOrder={-1} 
                  > 
                      <boxGeometry args={[rwLength, racewayH, racewayD]} /> 
                      <meshStandardMaterial 
                        color={racewayColor} 
                        roughness={0.6} 
                        metalness={0.05} 
                        stencilWrite={true}
                        stencilRef={5}
                        stencilFunc={THREE.AlwaysStencilFunc}
                        stencilZPass={THREE.ReplaceStencilOp}
                      />
                  </mesh>

                  {/* Raceway Drop Shadow on Wall */}
                  <group position={[racewayXPos + SHADOW_OFFSET_X, racewayYPos + SHADOW_OFFSET_Y, racewayShadowZ]}>
                      <mesh renderOrder={-2}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.5} depthWrite={false} />
                      </mesh>
                      <mesh position={[0,0,-0.001]} scale={[1.01, 1.1, 1]} renderOrder={-2}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.25} depthWrite={false} />
                      </mesh>
                  </group>
                </>
              )}
        </group>
    );
};

import { useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, IlluminationType } from '../../types';
import { RETURN_COLORS, TRIM_CAP_COLORS, PAINT_COLORS } from '../../constants';
import { getHex, getVinylHex, getMaterialProps, LED_HEX_MAP } from './utils';

export const useSignMaterials = (config: SignConfig, ledIntensity: number, shadowIntensity: number) => {
    return useMemo(() => {
        const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
        const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;

        const faceColorHex = getVinylHex(config.colors.vinylSeries, config.colors.face);
        const returnColorHex = getHex(config.colors.return, RETURN_COLORS);
        const trimCapColorHex = getHex(config.colors.trimCap, TRIM_CAP_COLORS);
        const ledHex = LED_HEX_MAP[config.ledColor] || '#FFFFFF';

        // Lookup Backer Paint Color
        const backerPaintObj = PAINT_COLORS.find(c => c.name === config.colors.backer);
        const backerColorHex = backerPaintObj ? backerPaintObj.hex : '#ffffff';

        const faceColorThree = new THREE.Color(faceColorHex);
        const ledColorThree = new THREE.Color(ledHex);

        // BLACK VINYL LOGIC
        const isBlackVinyl = config.colors.face.includes('Black');

        let finalEmissiveColor: THREE.Color;
        let boostFactor = 1.0;

        if (isBlackVinyl) {
            finalEmissiveColor = ledColorThree.clone();
        } else {
            const maxComponent = Math.max(faceColorThree.r, faceColorThree.g, faceColorThree.b);
            const normalizedBase = faceColorThree.clone();
            if (maxComponent > 0.01) {
                normalizedBase.multiplyScalar(1 / maxComponent);
            }
            finalEmissiveColor = normalizedBase.clone().multiply(ledColorThree);
            const luminance = 0.2126 * finalEmissiveColor.r + 0.7152 * finalEmissiveColor.g + 0.0722 * finalEmissiveColor.b;
            boostFactor = 1.0 + ((1.0 - Math.min(1.0, Math.sqrt(luminance))) * 3.5);
        }

        let finalIntensity = 0;
        if (isFrontLit) {
            if (isBlackVinyl) {
                finalIntensity = ledIntensity * 0.01;
            } else {
                finalIntensity = ledIntensity * 1.5 * boostFactor;
            }
        }

        const returnMatProps = getMaterialProps(config.colors.return);

        const returnMaterial = new THREE.MeshStandardMaterial({
          color: returnColorHex,
          roughness: returnMatProps.roughness,
          metalness: returnMatProps.metalness, 
        });

        const invisibleMaterial = new THREE.MeshBasicMaterial({ visible: false });
        const canMaterial = [invisibleMaterial, returnMaterial];

        let faceMaterial: THREE.MeshStandardMaterial;

        if (!isFrontLit) {
            // Halo Only or Non-Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: isHalo ? returnColorHex : faceColorHex, 
              roughness: returnMatProps.roughness,
              metalness: returnMatProps.metalness,
            });
        } else {
            // Front Lit or Dual Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: faceColorHex,
              roughness: 0.1, 
              metalness: 0.0,
              envMapIntensity: 1.5,
              emissive: finalEmissiveColor,
              emissiveIntensity: finalIntensity,
              toneMapped: false, 
              transparent: false,
              opacity: 1.0, 
            });
        }

        const trimCapMaterial = new THREE.MeshStandardMaterial({
          color: trimCapColorHex,
          roughness: 0.5,
          metalness: 0.1,
        });

        const haloBackerMaterial = new THREE.MeshStandardMaterial({
          color: '#ffffff',
          emissive: ledHex,
          emissiveIntensity: ledIntensity * 3,
          toneMapped: false, 
          roughness: 0.2,
          metalness: 0.0,
          side: THREE.DoubleSide,
          transparent: true,
          opacity: 0.9
        });

        const mountingBackerMaterial = new THREE.MeshStandardMaterial({
            color: backerColorHex,
            roughness: 0.6,
            metalness: 0.1,
        });

        // Shadow Materials
        const wallShadowBase = { color: '#000000', transparent: true, side: THREE.FrontSide, depthWrite: false };

        // Clipped (Raceway) Materials - Uses Stencil Ref 5
        const clippedBase = { 
            stencilWrite: true,
            stencilRef: 5,
            stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, 
            stencilZFail: THREE.KeepStencilOp, 
            stencilZPass: THREE.KeepStencilOp,
        };

        const clippedShadowBase = { 
            ...wallShadowBase,
            ...clippedBase
        };

        const shadowMats = {
          raceway: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity }),

          wallCore: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.6 }),
          wallMid: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.3 }),
          wallOuter: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.2 }),

          clippedCore: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.6 }),
          clippedMid: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.3 }),
          clippedOuter: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.2 }),
        };

        // Glow Mats Helper
        const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
            const stencilProps = useStencil ? clippedBase : {};

            return {
                core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
                mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
                outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
            };
        };

        const mats = {
            mats1: createGlowMats(1.0, config.mount === MountType.RACEWAY), // Mats1 is Primary (can be clipped)
            mats2: createGlowMats(1.0, false) // Mats2 is always Wall (never clipped)
        };

        return { 
            faceMaterial, returnMaterial, canMaterial, 
            trimCapMaterial, invisibleMaterial,
            haloBackerMaterial, mountingBackerMaterial, 
            shadowMats, ledHex,
            ...mats
        };

    }, [config.colors, config.ledColor, config.illumination, ledIntensity, shadowIntensity, config.mount]); // Added config.mount dependency
};

import React, { useRef, useLayoutEffect } from 'react';
import { Text3D } from '@react-three/drei';
import * as THREE from 'three';
import { PartVisibility } from './utils';

interface LetterGroupProps {
    line: string;
    fontUrl: string;
    letterHeight: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number; 
    backerZ: number;
    backerThickness: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    racewayFaceZ: number;
    wallFaceZ: number;
    visibility: PartVisibility;
    onMeasure?: (width: number) => void;
}

export const LetterGroup: React.FC<LetterGroupProps> = ({ 
    line, fontUrl, letterHeight, depth, faceThickness, trimDepth, 
    returnMaterial, faceMaterial, trimCapMaterial, haloBackerMaterial, mountingBackerMaterial, canMaterial,
    invisibleMaterial,
    glowMats1, glowMats2, glowParams1, glowParams2, shadowMats,
    zOffset1, zOffset2, mountZ, backerZ, backerThickness,
    isHalo, isFrontLit, isLit, isRaceway, isBackerMount, backerLit, racewayFaceZ, wallFaceZ,
    visibility,
    onMeasure
}) => {

    const meshRef = useRef<THREE.Mesh>(null);

    useLayoutEffect(() => {
        if (meshRef.current && onMeasure) {
            meshRef.current.geometry.computeBoundingBox();
            const box = meshRef.current.geometry.boundingBox;
            if (box) {
                const width = box.max.x - box.min.x;
                onMeasure(width);
            }
        }
    }, [line, fontUrl, letterHeight, onMeasure]);

    const faceRecess = 0.05;
    const faceZ = depth - faceThickness - faceRecess; 
    const canHeight = Math.max(0.1, depth - faceThickness - faceRecess); 
    const trimLipZ = depth; 
    const trimSideZ = depth - 0.75; 

    const trimStrokeWidth = 0.25; 
    const trimInwardSize = -trimStrokeWidth;
    const trimSideExpansion = 0.03; 

    const LOW_RES_SEGMENTS = 24;
    const backerOffset = 1.5; 
    const backerPanelThickness = 0.125; 
    const SHADOW_X = 0.2;
    const SHADOW_Y = -0.3;

    // High render order for glows to ensure they draw after raceway writes stencil
    const GLOW_RENDER_ORDER = 100;
    const SHADOW_RENDER_ORDER = 90;

    return (
        <group position={[0, 0, mountZ]} castShadow>

            {/* 0. MOUNTING BACKER PANEL (Cloud Shape) */}
            {isBackerMount && (
                <group position={[0, 0, -0.5]}> 
                     <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={backerPanelThickness}
                        position={[0, 0, -0.25]}
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0} 
                        bevelSize={backerOffset} 
                        material={mountingBackerMaterial} 
                        visible={visibility.backers}
                        renderOrder={5}
                     >
                        {line}
                     </Text3D>

                     {backerLit && (
                        <group position={[0, 0, zOffset2]}> 
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 0.5} material={glowMats2.core} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 2.0} material={glowMats2.mid} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 6.0} material={glowMats2.outer} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                        </group>
                     )}
                </group>
            )}

            {/* 1. CAST SHADOWS */}
            {/* Primary Shadow (Clipped if Raceway, Normal if Wall) */}
            <group position={[SHADOW_X, SHADOW_Y, zOffset1]}>
               <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0} material={isRaceway ? shadowMats.clippedCore : shadowMats.wallCore} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
               <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.2} material={isRaceway ? shadowMats.clippedMid : shadowMats.wallMid} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
               <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.5} material={isRaceway ? shadowMats.clippedOuter : shadowMats.wallOuter} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
            </group>

            {/* Secondary Wall Shadow (Only if Raceway, to catch ascenders/descenders) */}
            {isRaceway && (
               <group position={[SHADOW_X, SHADOW_Y, zOffset2]}>
                  <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0} material={shadowMats.wallCore} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
                  <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.2} material={shadowMats.wallMid} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
                  <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.5} material={shadowMats.wallOuter} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
               </group>
            )}

            {/* 2. THE CAN (Returns) */}
            <Text3D
              ref={meshRef}
              font={fontUrl}
              size={letterHeight}
              height={canHeight}
              curveSegments={12}
              bevelEnabled={true}
              bevelThickness={0} 
              bevelSize={0}
              material={canMaterial}
              visible={visibility.returns}
              renderOrder={10}
            >
              {line}
            </Text3D>

            {/* 3. FACE ASSEMBLY */}
            <Text3D
                font={fontUrl}
                size={letterHeight}
                height={faceThickness}
                position={[0, 0, faceZ]} 
                curveSegments={12}
                bevelEnabled={true}
                bevelThickness={0} 
                bevelSize={isFrontLit ? -0.23 : 0} 
                material={faceMaterial} 
                visible={visibility.faces}
                renderOrder={15}
            >
                {line}
            </Text3D>

            {/* 4. TRIM CAP */}
            {isFrontLit && (
                <group>
                    <group visible={visibility.trimCapFaces}>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimInwardSize}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                    </group>
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={0.75} 
                        position={[0, 0, trimSideZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0}
                        bevelSize={trimSideExpansion}
                        material={[invisibleMaterial, trimCapMaterial]}
                        visible={visibility.trimCapSides}
                        renderOrder={25}
                    >
                        {line}
                    </Text3D>
                </group>
            )}

            {/* 5. HALO LIT FACE (Rear Poly) & GLOW */}
            {isHalo && (
            <group>
                <Text3D
                  font={fontUrl}
                  size={letterHeight}
                  height={backerThickness}
                  position={[0, 0, backerZ]} 
                  curveSegments={12}
                  bevelEnabled={true} 
                  bevelThickness={0}
                  bevelSize={-0.05} 
                  material={haloBackerMaterial}
                  visible={visibility.backers}
                >
                  {line}
                </Text3D>

                {isLit && (
                  <>
                    {/* Primary Glow (Raceway Clipped or Wall) */}
                    <group position={[0, 0, zOffset1 + 0.01]}>
                        <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.core} material={glowMats1.core} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.mid} material={glowMats1.mid} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.outer} material={glowMats1.outer} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                    </group>

                    {/* Secondary Wall Glow (If Raceway) */}
                    {isRaceway && (
                        <group position={[0, 0, zOffset2]}>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.core} material={glowMats2.core} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.mid} material={glowMats2.mid} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.outer} material={glowMats2.outer} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                        </group>
                    )}
                  </>
                )}
            </group>
            )}
        </group>
    )
}

import { useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, IlluminationType, MountType } from '../../types';
import { RETURN_COLORS, TRIM_CAP_COLORS, PAINT_COLORS } from '../../constants';
import { getHex, getVinylHex, getMaterialProps, LED_HEX_MAP } from './utils';

export const useSignMaterials = (config: SignConfig, ledIntensity: number, shadowIntensity: number) => {
    return useMemo(() => {
        const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
        const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;

        const faceColorHex = getVinylHex(config.colors.vinylSeries, config.colors.face);
        const returnColorHex = getHex(config.colors.return, RETURN_COLORS);
        const trimCapColorHex = getHex(config.colors.trimCap, TRIM_CAP_COLORS);
        const ledHex = LED_HEX_MAP[config.ledColor] || '#FFFFFF';

        // Lookup Backer Paint Color
        const backerPaintObj = PAINT_COLORS.find(c => c.name === config.colors.backer);
        const backerColorHex = backerPaintObj ? backerPaintObj.hex : '#ffffff';

        const faceColorThree = new THREE.Color(faceColorHex);
        const ledColorThree = new THREE.Color(ledHex);

        // BLACK VINYL LOGIC
        const isBlackVinyl = config.colors.face.includes('Black');

        let finalEmissiveColor: THREE.Color;
        let boostFactor = 1.0;

        if (isBlackVinyl) {
            finalEmissiveColor = ledColorThree.clone();
        } else {
            const maxComponent = Math.max(faceColorThree.r, faceColorThree.g, faceColorThree.b);
            const normalizedBase = faceColorThree.clone();
            if (maxComponent > 0.01) {
                normalizedBase.multiplyScalar(1 / maxComponent);
            }
            finalEmissiveColor = normalizedBase.clone().multiply(ledColorThree);
            const luminance = 0.2126 * finalEmissiveColor.r + 0.7152 * finalEmissiveColor.g + 0.0722 * finalEmissiveColor.b;
            boostFactor = 1.0 + ((1.0 - Math.min(1.0, Math.sqrt(luminance))) * 3.5);
        }

        let finalIntensity = 0;
        if (isFrontLit) {
            if (isBlackVinyl) {
                finalIntensity = ledIntensity * 0.01;
            } else {
                finalIntensity = ledIntensity * 1.5 * boostFactor;
            }
        }

        const returnMatProps = getMaterialProps(config.colors.return);

        const returnMaterial = new THREE.MeshStandardMaterial({
          color: returnColorHex,
          roughness: returnMatProps.roughness,
          metalness: returnMatProps.metalness, 
        });

        const invisibleMaterial = new THREE.MeshBasicMaterial({ visible: false });
        const canMaterial = [invisibleMaterial, returnMaterial];

        let faceMaterial: THREE.MeshStandardMaterial;

        if (!isFrontLit) {
            // Halo Only or Non-Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: isHalo ? returnColorHex : faceColorHex, 
              roughness: returnMatProps.roughness,
              metalness: returnMatProps.metalness,
            });
        } else {
            // Front Lit or Dual Lit
            faceMaterial = new THREE.MeshStandardMaterial({
              color: faceColorHex,
              roughness: 0.1, 
              metalness: 0.0,
              envMapIntensity: 1.5,
              emissive: finalEmissiveColor,
              emissiveIntensity: finalIntensity,
              toneMapped: false, 
              transparent: false,
              opacity: 1.0, 
            });
        }

        const trimCapMaterial = new THREE.MeshStandardMaterial({
          color: trimCapColorHex,
          roughness: 0.5,
          metalness: 0.1,
        });

        const haloBackerMaterial = new THREE.MeshStandardMaterial({
          color: '#ffffff',
          emissive: ledHex,
          emissiveIntensity: ledIntensity * 3,
          toneMapped: false, 
          roughness: 0.2,
          metalness: 0.0,
          side: THREE.DoubleSide,
          transparent: true,
          opacity: 0.9
        });

        const mountingBackerMaterial = new THREE.MeshStandardMaterial({
            color: backerColorHex,
            roughness: 0.6,
            metalness: 0.1,
        });

        // Shadow Materials
        const wallShadowBase = { color: '#000000', transparent: true, side: THREE.FrontSide, depthWrite: false };

        // Clipped (Raceway) Materials - Uses Stencil Ref 5
        const clippedBase = { 
            stencilWrite: true,
            stencilRef: 5,
            stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, 
            stencilZFail: THREE.KeepStencilOp, 
            stencilZPass: THREE.KeepStencilOp,
        };

        const clippedShadowBase = { 
            ...wallShadowBase,
            ...clippedBase
        };

        const shadowMats = {
          raceway: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity }),

          wallCore: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.6 }),
          wallMid: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.3 }),
          wallOuter: new THREE.MeshBasicMaterial({ ...wallShadowBase, opacity: shadowIntensity * 0.2 }),

          clippedCore: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.6 }),
          clippedMid: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.3 }),
          clippedOuter: new THREE.MeshBasicMaterial({ ...clippedShadowBase, opacity: shadowIntensity * 0.2 }),
        };

        const baseGlowOpacity = (ledIntensity / 5) * 2.5;

        // Glow Mats Helper
        const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
            const stencilProps = useStencil ? clippedBase : {};

            return {
                core: new THREE.MeshBasicMaterial({ color: ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
                mid: new THREE.MeshBasicMaterial({ color: ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
                outer: new THREE.MeshBasicMaterial({ color: ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
            };
        };

        const mats = {
            mats1: createGlowMats(1.0, config.mount === MountType.RACEWAY), // Mats1 is Primary (can be clipped)
            mats2: createGlowMats(1.0, false) // Mats2 is always Wall (never clipped)
        };

        return { 
            faceMaterial, returnMaterial, canMaterial, 
            trimCapMaterial, invisibleMaterial,
            haloBackerMaterial, mountingBackerMaterial, 
            shadowMats, ledHex,
            ...mats
        };

    }, [config.colors, config.ledColor, config.illumination, ledIntensity, shadowIntensity, config.mount]); // Added config.mount dependency
};

import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  // New Logic: If lights are active and it involves Halo lighting, disable shadows to prevent visual conflict.
  const lightsOn = ledIntensity > 0.1;
  const effectiveShadowIntensity = (isHalo && lightsOn) ? 0 : shadowIntensity;

  const materials = useSignMaterials(config, ledIntensity, effectiveShadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  const WALL_Z = -0.5;
  const BACKER_THICK = 0.125;

  let mountZ = 0; 
  let targetSurfaceZ = WALL_Z; 

  if (config.mount === MountType.RACEWAY) {
      mountZ = racewayD; 
      targetSurfaceZ = racewayD; 
  } 
  else if (config.mount === MountType.BACKER) {
      const mStandoff = config.dimensions.standoff || 0;
      const lStandoff = config.dimensions.letterStandoff || 0;

      const backerFaceZ = WALL_Z + mStandoff + BACKER_THICK;
      mountZ = backerFaceZ + lStandoff;
      targetSurfaceZ = backerFaceZ;
  } 
  else {
      const standoff = config.dimensions.standoff || 0;
      mountZ = WALL_Z + standoff;
      targetSurfaceZ = WALL_Z; 
  }

  const zOffset1 = (targetSurfaceZ - mountZ) + 0.05; 
  const zOffset2 = (WALL_Z - mountZ) + 0.05; 

  // Glow Logic - Intensity Boosted for visibility
  const baseGlowOpacity = (ledIntensity / 5) * 2.5;

  // Distance from Light Source (Letter Back) to Target Surface
  const distToTarget1 = Math.abs(mountZ - targetSurfaceZ);

  // Distance from Light Source to Wall (For secondary glow in Raceway mode)
  const distToTarget2 = Math.abs(mountZ - WALL_Z);

  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  // Params 1: Primary Surface (Raceway or Backer or Wall)
  const params1 = getGlowParams(distToTarget1);
  // Params 2: Wall (Used for Secondary Glow in Raceway mode)
  const params2 = getGlowParams(distToTarget2);

  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, 
            stencilRef: 5, // Corrected to match Raceway ID
            stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, 
            stencilZFail: THREE.KeepStencilOp, 
            stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            mountingBackerMaterial={materials.mountingBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={WALL_Z}
            isHalo={isHalo}
            isFrontLit={isFrontLit}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            isBackerMount={config.mount === MountType.BACKER}
            backerLit={config.backerLit}
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={effectiveShadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};

import { SignConfig, IlluminationType, MountType } from '../types';
import { FONT_LIBRARY } from '../constants';

export interface PricingItem {
  id: string;
  category: string;
  description: string;
  qty: number;
  unit: string;
  unitPrice: number;
  total: number;
}

export interface PricingQuote {
  items: PricingItem[];
  subtotal: number;
  tax: number;
  total: number;
  requiresQuote: boolean; // New flag
}

export const calculateRetailPrice = (config: SignConfig): PricingQuote => {
  const items: PricingItem[] = [];
  let requiresQuote = false;

  // 1. Determine Pricing Tier based on Illumination and Font Style
  const fontData = FONT_LIBRARY[config.fontFamily] || Object.values(FONT_LIBRARY)[0];
  const isSerif = fontData.style === 'serif';

  let baseRate = 0;
  let tierName = "";

  if (config.illumination === IlluminationType.FRONT_LIT) {
    baseRate = isSerif ? 18.00 : 16.00;
    tierName = `Front Lighted (${isSerif ? 'Serif' : 'Block'})`;
  } else if (config.illumination === IlluminationType.HALO_LIT) {
    baseRate = isSerif ? 35.00 : 32.00;
    tierName = `Reverse Halo (Lit) (${isSerif ? 'Serif' : 'Block'})`;
  } else if (config.illumination === IlluminationType.DUAL_LIT) {
    // Custom logic for Dual Lit (Premium)
    baseRate = isSerif ? 48.00 : 45.00; 
    tierName = `Dual Lit (Front + Halo) (${isSerif ? 'Serif' : 'Block'})`;
  } else {
    // Non-Illuminated
    baseRate = isSerif ? 31.00 : 28.00;
    tierName = `Reverse Halo (Non-Lit) (${isSerif ? 'Serif' : 'Block'})`;
  }

  // 2. Calculate Letters
  // Pricing is Per Inch of Height
  const letterHeight = config.dimensions.height;

  config.lines.forEach((line, idx) => {
    if (!line) return;
    const charCount = line.replace(/\s/g, '').length; // Count non-whitespace
    const totalInches = charCount * letterHeight;

    items.push({
      id: `LINE-${idx + 1}`,
      category: 'Channel Letters',
      description: `Line ${idx + 1}: "${line}" (${charCount} chars @ ${letterHeight}") - ${tierName}`,
      qty: totalInches,
      unit: 'inch',
      unitPrice: baseRate,
      total: totalInches * baseRate
    });
  });

  // 3. Raceway Pricing
  if (config.mount === MountType.RACEWAY) {
    let totalLengthFt = 0;
    const widthFactor = fontData.widthFactor;

    config.lines.forEach((line, idx) => {
      if(!line) return;
      // Get length in inches, convert to feet
      const lenInches = config.dimensions.racewayLengths[idx] || (line.length * letterHeight * widthFactor);
      totalLengthFt += (lenInches / 12);
    });

    const billableFt = Math.ceil(totalLengthFt);

    items.push({
      id: 'RACEWAY',
      category: 'Mounting',
      description: 'Raceway Mount (Includes Paint & Safety Switch)',
      qty: billableFt,
      unit: 'ft',
      unitPrice: 95.00,
      total: billableFt * 95.00
    });
  }

  // 4. Backer Pricing (If Backer Panel Selected)
  if (config.mount === MountType.BACKER) {
      // Calculate Total Area
      // Width = calculatedWidth, Height = (lines * height) + gaps
      const w = config.dimensions.calculatedWidth;
      const h = (config.lines.length * config.dimensions.height) + ((config.lines.length - 1) * (config.dimensions.lineSpacing || 5));

      // Add margin for "Cloud" or Panel (e.g., 3 inches all around)
      const areaSqFt = ((w + 6) * (h + 6)) / 144;
      const billableSqFt = Math.ceil(areaSqFt);

      // Base Backer Price (Includes Paint & Routing)
      items.push({
          id: 'BACKER',
          category: 'Mounting',
          description: `ACM Backer - Routed, Painted (${config.colors.backer})`,
          qty: billableSqFt,
          unit: 'sqft',
          unitPrice: 25.00,
          total: billableSqFt * 25.00
      });

      // Add-on for Backer Halo Illumination (If specifically requested as a feature separate from letter halo)
      if (config.backerLit) {
          items.push({
             id: 'BACKER-LED',
             category: 'Illumination',
             description: 'Backer Panel Halo Illumination (Add-on)',
             qty: billableSqFt,
             unit: 'sqft',
             unitPrice: 15.00,
             total: billableSqFt * 15.00
          });
      }
  }

  // Check for complex combinations requiring custom quote
  if (config.illumination === IlluminationType.DUAL_LIT) {
      items.push({
          id: 'NOTE-1',
          category: 'Notice',
          description: 'Pricing for Dual Lit is an estimate. Sales Quote Required.',
          qty: 1,
          unit: 'ea',
          unitPrice: 0,
          total: 0
      });
      requiresQuote = true;
  }

  // Calculate Totals
  const subtotal = items.reduce((acc, item) => acc + item.total, 0);
  const tax = subtotal * 0.0825; // 8.25% generic tax
  const total = subtotal + tax;

  return { items, subtotal, tax, total, requiresQuote };
};

import {
  SignConfig,
  ManufacturingPacket,
  Department,
  SignType,
  MountType,
  BOMItem,
  IlluminationType,
  BackerMaterial
} from '../types';
import { 
  calculatePerimeter, 
  generateBenderPath, 
  calculateTotalWidth,
  calculateSheetsNeeded,
  calculateLEDModules
} from './vectorUtils';
import { FONT_LIBRARY } from '../constants';

export const calculateSignRequirements = (config: SignConfig): ManufacturingPacket => {
  const tasks = [];
  const bom: BOMItem[] = [];
  const warnings = [];

  // Robust Fallback for Engine
  const fontData = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];

  // Update calculated width if not present (although UI usually handles this, we double check here)
  const calcWidth = calculateTotalWidth(config.lines, config.dimensions.height, config.fontFamily);
  const effectiveConfig = { ...config, dimensions: { ...config.dimensions, calculatedWidth: calcWidth }};

  // 1. Engineering Checks
  // Raceway Splicing Check - Check if ANY section exceeds 120"
  if (effectiveConfig.mount === MountType.RACEWAY) {
    let spliceNeeded = false;
    const widthFactor = fontData.widthFactor;

    config.lines.forEach((line, idx) => {
      // Use the accurate length stored in config (which comes from 3D measure), fallback to estimation
      const len = config.dimensions.racewayLengths[idx] || (line.length * (config.dimensions.height * widthFactor));

      if(len > 120) spliceNeeded = true;
    });

    if (spliceNeeded) {
      warnings.push(`Raceway length exceeds 10ft on one or more lines. Will be built in sections with splice plates.`);
    }
  }

  // 2. Core Logic Branching (Strategy Pattern)
  if (effectiveConfig.type === SignType.CHANNEL_LETTER) {

    // --- CNC Router Logic ---
    const facesNeeded = calculateSheetsNeeded(config.lines, config.dimensions.height);
    const backsNeeded = facesNeeded; // Usually same amount for backs

    // Face Material BOM
    const faceMatName = `${config.faceMaterial} ${config.faceThickness}" - Translucent White`;
    bom.push({ sku: `SHEET-${config.faceMaterial.substring(0,3).toUpperCase()}`, name: faceMatName, quantity: facesNeeded, unit: 'sheet', department: Department.ROUTER });

    // Backer Material BOM
    let backMatName = "3mm ACM - White";
    let backSku = "ACM-WHT";

    if (config.illumination === IlluminationType.HALO_LIT) {
        // Use user selected backer for Halo
        const bThickness = config.backerThickness || 0.1875;
        backMatName = `${config.backerMaterial} ${bThickness}"`;
        backSku = `SHEET-${config.backerMaterial.substring(0,3).toUpperCase()}`;
    } else {
        // Force ACM for front lit usually, unless overridden, but here we respect config if user selected
        // In Controls we enforce BackerMaterial.ACM for Front Lit, so this is safe
        backMatName = `${config.backerMaterial}`;
    }

    bom.push({ sku: backSku, name: backMatName, quantity: backsNeeded, unit: 'sheet', department: Department.ROUTER });

    tasks.push({ department: Department.ROUTER, description: `Route ${facesNeeded} sheets of Faces`, status: 'Pending', estimatedHours: facesNeeded * 0.75 });
    tasks.push({ department: Department.ROUTER, description: `Route ${backsNeeded} sheets of Backers`, status: 'Pending', estimatedHours: backsNeeded * 0.5 });

    // --- Vinyl Logic ---
    // User selected Series + Color. In production, we assume we wrap the face.
    tasks.push({ department: Department.VINYL, description: `Apply ${config.colors.vinylSeries} (${config.colors.face}) to faces`, status: 'Pending', estimatedHours: 1.5 });
    bom.push({ sku: 'VNY-TRN', name: `${config.colors.vinylSeries} - ${config.colors.face}`, quantity: facesNeeded * 32, unit: 'sqft', department: Department.VINYL });

    // --- Coil & Trim Logic ---
    const totalPerimeterInches = calculatePerimeter(config.lines, config.dimensions.height);
    bom.push({ sku: 'COIL-5', name: `Return Coil 5" - ${config.colors.return}`, quantity: Math.ceil(totalPerimeterInches / 12), unit: 'ft', department: Department.CHANNEL_BENDER });
    bom.push({ sku: 'TRIM-1', name: `Trim Cap 1" - ${config.colors.trimCap}`, quantity: Math.ceil(totalPerimeterInches / 12), unit: 'ft', department: Department.ASSEMBLY });

    tasks.push({ department: Department.CHANNEL_BENDER, description: `Bend Returns (Total: ${Math.ceil(totalPerimeterInches/12)} ft)`, status: 'Pending', estimatedHours: 2 });
    tasks.push({ department: Department.ASSEMBLY, description: `Bond Trim Cap to Faces`, status: 'Pending', estimatedHours: 2.5 });

    // --- Illumination Logic (LED & PSU) ---
    if (config.illumination !== IlluminationType.NON_ILLUMINATED) {
      const totalModules = calculateLEDModules(config.lines, config.dimensions.height);
      const totalWatts = totalModules * 0.45;

      bom.push({ sku: `LED-${config.ledColor.toUpperCase()}`, name: `LED Module (${config.ledColor})`, quantity: totalModules, unit: 'module', department: Department.ASSEMBLY });

      // PSU Calculation
      if (totalWatts <= 60) {
        bom.push({ sku: 'PSU-60W', name: 'Power Supply 60W 12V', quantity: 1, unit: 'ea', department: Department.ASSEMBLY });
      } else if (totalWatts <= 120) {
        bom.push({ sku: 'PSU-120W', name: 'Power Supply 120W 12V', quantity: 1, unit: 'ea', department: Department.ASSEMBLY });
      } else {
        const psuCount = Math.ceil(totalWatts / 120);
        bom.push({ sku: 'PSU-120W', name: 'Power Supply 120W 12V', quantity: psuCount, unit: 'ea', department: Department.ASSEMBLY });
      }

      tasks.push({ department: Department.ASSEMBLY, description: `Install ${totalModules} LEDs & Wiring`, status: 'Pending', estimatedHours: 2 });
    }

    // --- Mounting Logic (Raceway vs Direct) ---
    if (config.mount === MountType.RACEWAY) {
      // Calculate total raceway length by summing individual line widths based on configuration
      let totalRwLen = 0;
      const widthFactor = fontData.widthFactor;

      config.lines.forEach((line, idx) => {
         if(line.length > 0) {
            // Priority: Config Value (Synced from 3D) > Estimation
            const len = config.dimensions.racewayLengths[idx] || (line.length * (config.dimensions.height * widthFactor));
            totalRwLen += len;
         }
      });

      const numLines = config.lines.filter(l => l.length > 0).length;

      // Metal Fab
      tasks.push({ department: Department.METAL_FAB, description: `Fabricate ${numLines}x Raceway Runs (Total: ${Math.ceil(totalRwLen)}") w/ End Caps & Clips`, status: 'Pending', estimatedHours: 3 });
      // STRICT: 6x4 Extrusion
      bom.push({ sku: 'RAC-EXT-64', name: `Raceway Extrusion 6"x4" - ${Math.ceil(totalRwLen)}" total`, quantity: Math.ceil(totalRwLen / 120), unit: 'ea', department: Department.METAL_FAB });
      bom.push({ sku: 'RAC-CLIP', name: 'Mounting Clips', quantity: (Math.ceil(totalRwLen / 48) + 1) * numLines, unit: 'ea', department: Department.METAL_FAB });
      bom.push({ sku: 'RAC-CAP', name: 'Raceway End Caps', quantity: 2 * numLines, unit: 'ea', department: Department.METAL_FAB });

      // Paint
      tasks.push({ department: Department.PAINT, description: `Paint Raceways (${config.colors.raceway})`, status: 'Pending', estimatedHours: 3 });
      bom.push({ sku: 'PNT-EXT', name: `Paint - ${config.colors.raceway}`, quantity: 1, unit: 'ea', department: Department.PAINT });

      // Assembly (Install + Switch)
      tasks.push({ department: Department.ASSEMBLY, description: 'Mount Letters to Raceway & Install Switch', status: 'Pending', estimatedHours: 2 });
      bom.push({ sku: 'SW-TOGGLE', name: 'Safety Disconnect Switch (UL)', quantity: 1, unit: 'ea', department: Department.ASSEMBLY });
    } else {
      // Direct Mount
      tasks.push({ department: Department.DESIGN, description: 'Plot Installation Pattern', status: 'Pending', estimatedHours: 0.5 });
      bom.push({ sku: 'PAT-PAPER', name: 'Pattern Paper', quantity: Math.ceil(calcWidth / 12), unit: 'ft', department: Department.DESIGN });
    }

  } else if (config.type === SignType.CABINET) {
    // Cabinet Logic (Simplified for this update, maintaining basic calculation)
    tasks.push({ department: Department.METAL_FAB, description: "Weld Cabinet Frame", status: 'Pending', estimatedHours: 4 });
    bom.push({ sku: 'ALU-EXT-CAB', name: 'Cabinet Extrusion', quantity: (config.dimensions.height + calcWidth) * 2 / 12, unit: 'ft', department: Department.METAL_FAB });
  }

  return {
    id: `WO-${Math.floor(Math.random() * 90000) + 10000}`,
    generatedAt: new Date().toISOString(),
    config: effectiveConfig,
    warnings,
    tasks,
    bom,
    vectorFiles: {
      routerFace: `face_cut_file.svg`,
      routerBack: `back_cut_file.svg`,
      benderPath: `bender_data.dxf`,
      pattern: config.mount === MountType.DIRECT ? `install_pattern.svg` : 'N/A',
    }
  };
};

