                </button>
                <button 
                  onClick={() => setFitTrigger(prev => prev + 1)}
                  className="bg-slate-800/80 hover:bg-slate-700 text-white p-2 rounded-lg border border-slate-600 shadow-lg backdrop-blur"
                  title="Fit Sign to View"
                >
                  <Maximize size={20} />
                </button>
              </div>

              <Canvas 
                shadows 
                dpr={[1, 2]} 
                camera={{ position: [0, 0, 120], fov: 45 }}
                gl={{ preserveDrawingBuffer: true, stencil: true }} 
              >
                <color attach="background" args={['#0f172a']} />

                <StatsReporter active={showDebug} statsRef={statsRef} />

                <CameraController 
                  triggerFit={fitTrigger} 
                  onFitComplete={handleFitComplete} 
                  signWidth={Math.max(config.dimensions.calculatedWidth, 48)} 
                  signHeight={config.dimensions.height * config.lines.length}
                />

                <CinematicController 
                   active={isCinematic} 
                   speed={cinematicSpeed}
                   signWidth={Math.max(config.dimensions.calculatedWidth, 60)} 
                   signHeight={config.dimensions.height * config.lines.length} 
                />

                <ScreenshotManager trigger={screenshotTrigger} />

                {/* Environment & Ambient Light */}
                <Environment 
                  preset="city" 
                  background 
                  blur={0.6}
                  environmentIntensity={ambientIntensity} 
                />
                <ambientLight intensity={0.3 * ambientIntensity} />

                {/* Directional Light for Shine (No Shadows) */}
                <directionalLight 
                  position={[20, 50, 50]} 
                  intensity={1.5 * ambientIntensity} 
                  castShadow={false} 
                />

                {/* THE WALL (Z = 0) */}
                <mesh position={[0, 0, -0.5]} receiveShadow={false}>
                   <planeGeometry args={[1200, 600]} />
                   <meshStandardMaterial 
                     color={config.wallTexture === WallTexture.NONE ? config.wallColor : '#ffffff'} 
                     map={wallTextures.map}
                     normalMap={wallTextures.normalMap}
                     roughness={0.8} 
                     metalness={0.0}
                   />
                </mesh>

                {/* SIGN GEOMETRY */}
                <SignRenderer 
                   config={config} 
                   ledIntensity={lightsActive ? ledIntensity : 0} 
                   shadowIntensity={shadowIntensity}
                   partVisibility={partVisibility}
                   onUpdateLength={handleRacewayLengthUpdate}
                />

                {/* Camera Controls */}
                <OrbitControls 
                  makeDefault
                  target={[0, 0, 0]}
                  minPolarAngle={0} 
                  maxPolarAngle={Math.PI}
                  minAzimuthAngle={cameraLocked ? -Math.PI / 2 : -Infinity}
                  maxAzimuthAngle={cameraLocked ? Math.PI / 2 : Infinity}
                  minDistance={20}
                  maxDistance={1200}
                  enableRotate={!isCinematic} 
                />

                <EffectComposer enableNormalPass={false} stencilBuffer={true}>
                  <Bloom luminanceThreshold={1.0} mipmapBlur intensity={lightsActive ? 0.8 : 0} radius={0.6} levels={9} />
                </EffectComposer>
              </Canvas>
            </>
          )}

          {activeTab === 'blueprint' && (
             <div className="w-full h-full bg-slate-200">
                <BlueprintView config={config} />
             </div>
          )}

          {activeTab === 'quote' && (
             <div className="w-full h-full bg-slate-200">
                <QuoteView config={config} />
             </div>
          )}

          {activeTab === 'fabrication' && (
            <div className="w-full h-full p-8 pt-24 overflow-hidden">
               <div className="max-w-6xl mx-auto h-full flex flex-col gap-6">

                 {/* Header Stats */}
                 <div className="flex items-center justify-between">
                   <div>
                      <h1 className="text-3xl font-bold text-white tracking-tight">Production Order #{manufacturingPacket.id.replace('WO-', '')}</h1>
                      <p className="text-slate-400 mt-1">Status: <span className="text-yellow-500 font-medium">Pre-Production Analysis</span></p>
                   </div>
                   <div className="flex gap-4">
                     <div className="bg-slate-800/50 border border-slate-700 px-6 py-3 rounded-lg flex flex-col items-center justify-center">
                       <span className="text-2xl font-bold text-white leading-none">{manufacturingPacket.tasks.length}</span>
                       <span className="text-xs text-slate-500 uppercase mt-1">Tasks</span>
                     </div>
                     <div className="bg-slate-800/50 border border-slate-700 px-6 py-3 rounded-lg flex flex-col items-center justify-center">
                       <span className="text-2xl font-bold text-white leading-none">{manufacturingPacket.bom.length}</span>
                       <span className="text-xs text-slate-500 uppercase mt-1">SKUs</span>
                     </div>
                   </div>
                 </div>

                 {/* Main Content */}
                 <div className="flex-1 min-h-0 bg-slate-900 rounded-xl border border-slate-800 overflow-hidden shadow-2xl">
                   <ManufacturingView packet={manufacturingPacket} survey={survey} />
                 </div>

               </div>
            </div>
          )}

        </div>
      </main>
    </div>
  );
}

// Enums for Categorization
export enum SignType {
  CHANNEL_LETTER = 'Channel Letter',
  CABINET = 'Light Box / Cabinet',
}

export enum IlluminationType {
  FRONT_LIT = 'Front Lit',
  HALO_LIT = 'Halo Lit',
  DUAL_LIT = 'Front & Halo Lit', // Added
  NON_ILLUMINATED = 'Non-Illuminated',
}

export enum MountType {
  DIRECT = 'Direct / Flush Mount',
  RACEWAY = 'Raceway',
  BACKER = 'Backer Panel',
}

export enum BackerShape {
  RECTANGLE = 'Rectangle',
  CONTOUR = 'Contour / Cloud',
}

export enum TextAlignment {
  LEFT = 'Left',
  CENTER = 'Center',
  RIGHT = 'Right',
}

export enum LEDColor {
  WHITE = 'White (6500K)',
  RED = 'Red',
  BLUE = 'Blue',
  GREEN = 'Green',
  YELLOW = 'Yellow',
}

export enum WallTexture {
  NONE = 'Smooth / Drywall',
  BRICK = 'Brick',
  STUCCO = 'Stucco',
  WOOD = 'Wood Siding',
  CORRUGATED = 'Corrugated Metal',
}

export enum Department {
  SALES = 'Sales',
  DESIGN = 'Design',
  ROUTER = 'CNC Router',
  METAL_FAB = 'Metal Fabrication',
  CHANNEL_BENDER = 'Channel Bender',
  PAINT = 'Paint',
  VINYL = 'Vinyl & Print',
  ASSEMBLY = 'Assembly',
  QC = 'Quality Control',
  INSTALL = 'Installation',
}

export enum FaceMaterial {
  ACRYLIC = 'Acrylic',
  POLYCARBONATE = 'Polycarbonate',
}

export type Thickness = 0.1875 | 0.25; // 3/16" or 1/4"

export enum BackerMaterial {
  ACM = '3mm ACM', // Standard for Front Lit
  ACRYLIC = 'Acrylic',
  POLYCARBONATE = 'Polycarbonate',
}

// 1. The Sign Configuration (Master Input)
export interface SignConfig {
  type: SignType;
  lines: string[]; // [Line1, Line2, Line3]
  alignment: TextAlignment;
  dimensions: {
    height: number; // inches (Input)
    depth: number; // inches (Input)
    calculatedWidth: number; // inches (Derived)
    racewayOffset: number; // inches (Vertical adjustment)
    racewayLengths: number[]; // inches (Manual override per line)
    racewayLengthsAuto: boolean[]; // toggle per line
    standoff: number; // inches (Backer to Wall OR Letter to Wall)
    letterStandoff: number; // inches (Letter to Backer) -- NEW
    lineSpacing: number; // inches (Gap between lines)
  };
  illumination: IlluminationType;
  ledColor: LEDColor;
  mount: MountType;
  wallTexture: WallTexture;
  wallColor: string;

  backerLit: boolean; // NEW: Does the backer panel itself have halo LEDs?
  backerShape: BackerShape; // NEW
  backerPadding: number; // NEW: Offset/Margin in inches

  colors: {
    vinylSeries: string; // e.g. "Oracal 8800"
    face: string; // Specific Color Name
    return: string; // References RETURN_COLORS name
    trimCap: string; // References TRIM_CAP_COLORS name
    raceway: string; // References PAINT_COLORS name
    backer: string; // References PAINT_COLORS name -- NEW
  };
  fontFamily: string; // Now references keys in FONT_LIBRARY

  // New Engineering Props
  faceMaterial: FaceMaterial;
  faceThickness: Thickness;
  backerMaterial: BackerMaterial; // For Halo or as general backer
  backerThickness: Thickness;
}

// 2. Site Survey Data (Install Conditions)
export interface SiteSurveyData {
  installHeight: number; // feet
  wallType: 'Brick' | 'Dryvit' | 'Wood' | 'Glass' | 'Steel';
  accessType: 'Ladder' | 'Bucket Truck' | 'Crane' | 'Scaffold';
  powerAccess: 'Behind Wall' | 'Remote' | 'Existing J-Box';
  permitRequired: boolean;
  notes: string;
}

// 3. BOM Item
export interface BOMItem {
  sku: string;
  name: string;
  quantity: number;
  unit: 'ft' | 'sqft' | 'ea' | 'sheet' | 'module' | 'set';
  department: Department;
  cost?: number;
}

// 4. Manufacturing Packet (Work Orders)
export interface ManufacturingPacket {
  id: string;
  generatedAt: string;
  config: SignConfig;
  warnings: string[];
  tasks: {
    department: Department;
    description: string;
    status: 'Pending' | 'In Progress' | 'Complete';
    estimatedHours: number;
  }[];
  bom: BOMItem[];
  vectorFiles: {
    routerFace: string; // SVG path
    routerBack: string;
    benderPath: string; // Simplified centerline for bender
    pattern: string;
  };
}

