import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType, BackerShape } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  // New Logic: If lights are active and it involves Halo lighting, disable shadows to prevent visual conflict.
  const lightsOn = ledIntensity > 0.1;
  const effectiveShadowIntensity = (isHalo && lightsOn) ? 0 : shadowIntensity;

  const materials = useSignMaterials(config, ledIntensity, effectiveShadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  const WALL_Z = -0.5;
  const BACKER_THICK = 0.125;

  let mountZ = 0; 
  let targetSurfaceZ = WALL_Z; 
  let backerFaceZ = WALL_Z;

  if (config.mount === MountType.RACEWAY) {
      mountZ = racewayD; 
      targetSurfaceZ = racewayD; 
  } 
  else if (config.mount === MountType.BACKER) {
      const mStandoff = config.dimensions.standoff || 0;
      const lStandoff = config.dimensions.letterStandoff || 0;

      backerFaceZ = WALL_Z + mStandoff + BACKER_THICK;
      mountZ = backerFaceZ + lStandoff;
      targetSurfaceZ = backerFaceZ;
  } 
  else {
      const standoff = config.dimensions.standoff || 0;
      mountZ = WALL_Z + standoff;
      targetSurfaceZ = WALL_Z; 
  }

  const zOffset1 = (targetSurfaceZ - mountZ) + 0.05; 
  const zOffset2 = (WALL_Z - mountZ) + 0.05; 

  // Glow Logic - Intensity Boosted for visibility
  const baseGlowOpacity = (ledIntensity / 5) * 2.5;

  // Distance from Light Source (Letter Back) to Target Surface
  const distToTarget1 = Math.abs(mountZ - targetSurfaceZ);

  // Distance from Light Source to Wall (For secondary glow in Raceway mode)
  const distToTarget2 = Math.abs(mountZ - WALL_Z);

  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  // Params 1: Primary Surface (Raceway or Backer or Wall)
  const params1 = getGlowParams(distToTarget1);
  // Params 2: Wall (Used for Secondary Glow in Raceway mode)
  const params2 = getGlowParams(distToTarget2);

  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, 
            stencilRef: 5, // Corrected to match Raceway ID
            stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, 
            stencilZFail: THREE.KeepStencilOp, 
            stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  // Rectangle Backer Geometry Calculation
  const isRectBacker = config.mount === MountType.BACKER && config.backerShape === BackerShape.RECTANGLE;
  const rectWidth = config.dimensions.calculatedWidth + ((config.backerPadding || 0) * 2);
  const numActiveLines = activeIndices.length || 1;
  // Approximated total height of text block + padding
  const rectHeight = (numActiveLines * letterHeight) + ((numActiveLines - 1) * rowGap) + ((config.backerPadding || 0) * 2);

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {/* Rectangular Backer Panel */}
      {isRectBacker && (
          <group position={[0, 0, backerFaceZ - (BACKER_THICK/2)]} visible={vis.backers}>
              {/* Panel Body */}
              <mesh>
                  <boxGeometry args={[rectWidth, rectHeight, BACKER_THICK]} />
                  <primitive object={materials.mountingBackerMaterial} />
              </mesh>

              {/* Panel Shadow on Wall */}
              <mesh position={[0.2, -0.3, -((config.dimensions.standoff || 0) + 0.05)]}>
                  <planeGeometry args={[rectWidth, rectHeight]} />
                  <meshBasicMaterial color="black" transparent opacity={shadowIntensity * 0.5} />
              </mesh>

              {/* Halo Glow Behind Rectangle */}
              {config.backerLit && lightsOn && (
                  <group position={[0, 0, -BACKER_THICK/2 - 0.1]}>
                     <mesh>
                         <planeGeometry args={[rectWidth * 1.05, rectHeight * 1.05]} />
                         <primitive object={mats2.core} />
                     </mesh>
                     <mesh position={[0,0,-0.1]}>
                         <planeGeometry args={[rectWidth * 1.2, rectHeight * 1.2]} />
                         <primitive object={mats2.mid} />
                     </mesh>
                     <mesh position={[0,0,-0.2]}>
                         <planeGeometry args={[rectWidth * 1.5, rectHeight * 1.5]} />
                         <primitive object={mats2.outer} />
                     </mesh>
                  </group>
              )}
          </group>
      )}

      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            mountingBackerMaterial={materials.mountingBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={WALL_Z}
            isHalo={isHalo}
            isFrontLit={isFrontLit}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            isBackerMount={config.mount === MountType.BACKER}
            backerLit={config.backerLit}
            backerShape={config.backerShape} // Pass new props
            backerPadding={config.backerPadding} // Pass new props
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={effectiveShadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};

import React, { useState, useEffect } from 'react';
import { Center } from '@react-three/drei';
import * as THREE from 'three';
import { SignConfig, MountType, BackerShape } from '../../types';
import { calculateRacewayTuckLength } from '../../services/vectorUtils';
import { LetterGroup } from './LetterGroup';
import { PartVisibility } from './utils';

interface SignLineProps {
    line: string;
    index: number;
    config: SignConfig;
    yPosition: number;
    fontUrl: string;
    letterHeight: number;
    widthFactor: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number;
    backerZ: number;
    backerThickness: number;
    racewayFaceZ: number;
    wallFaceZ: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    backerShape?: BackerShape;
    backerPadding?: number;
    racewayColor: string;
    racewayOffset: number;
    racewayH: number;
    racewayD: number;
    shadowIntensity: number;
    visibility: PartVisibility;
    onUpdateLength?: (index: number, length: number) => void;
}

export const SignLine: React.FC<SignLineProps> = ({ 
    line, index, config, yPosition, letterHeight, widthFactor, 
    racewayOffset, racewayH, racewayD, racewayColor, shadowIntensity,
    visibility,
    wallFaceZ,
    onUpdateLength,
    backerShape,
    backerPadding,
    ...props 
}) => {

    const [measuredWidth, setMeasuredWidth] = useState(0);
    const preciseRacewayLength = calculateRacewayTuckLength(line, letterHeight, config.fontFamily);

    useEffect(() => {
        if (config.dimensions.racewayLengthsAuto[index] && onUpdateLength) {
            if (Math.abs(config.dimensions.racewayLengths[index] - preciseRacewayLength) > 0.1) {
                onUpdateLength(index, preciseRacewayLength);
            }
        }
    }, [preciseRacewayLength, config.dimensions.racewayLengthsAuto, config.dimensions.racewayLengths, index, onUpdateLength]);

    const rwLength = config.dimensions.racewayLengthsAuto[index] 
      ? preciseRacewayLength
      : config.dimensions.racewayLengths[index];

    const racewayXPos = 0;
    const racewayYPos = (letterHeight * 0.5) + racewayOffset;
    const componentKey = `${line}-${config.fontFamily}-${letterHeight}`;
    const SHADOW_OFFSET_X = 0.3;
    const SHADOW_OFFSET_Y = -1.5;

    // Raceway Shadow on Wall
    const racewayShadowZ = wallFaceZ + 0.05;

    return (
        <group position={[0, yPosition, 0]}>
             <Center top disableY disableZ cacheKey={componentKey}>
                <LetterGroup 
                    line={line} 
                    letterHeight={letterHeight} 
                    visibility={visibility}
                    wallFaceZ={wallFaceZ}
                    backerShape={backerShape}
                    backerPadding={backerPadding}
                    onMeasure={(w) => {
                        if (Math.abs(w - measuredWidth) > 0.05) setMeasuredWidth(w);
                    }}
                    {...props} 
                />
             </Center>

             {config.mount === MountType.RACEWAY && (
                <>
                  {/* Raceway Box - Writes Stencil Ref 5 */}
                  <mesh 
                      position={[racewayXPos, racewayYPos, racewayD / 2]}
                      visible={visibility.raceway}
                      renderOrder={-1} 
                  > 
                      <boxGeometry args={[rwLength, racewayH, racewayD]} /> 
                      <meshStandardMaterial 
                        color={racewayColor} 
                        roughness={0.6} 
                        metalness={0.05} 
                        stencilWrite={true}
                        stencilRef={5}
                        stencilFunc={THREE.AlwaysStencilFunc}
                        stencilZPass={THREE.ReplaceStencilOp}
                      />
                  </mesh>

                  {/* Raceway Drop Shadow on Wall */}
                  <group position={[racewayXPos + SHADOW_OFFSET_X, racewayYPos + SHADOW_OFFSET_Y, racewayShadowZ]}>
                      <mesh renderOrder={-2}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.5} depthWrite={false} />
                      </mesh>
                      <mesh position={[0,0,-0.001]} scale={[1.01, 1.1, 1]} renderOrder={-2}>
                        <planeGeometry args={[rwLength, racewayH]} />
                        <meshBasicMaterial color="#000000" transparent opacity={shadowIntensity * 0.25} depthWrite={false} />
                      </mesh>
                  </group>
                </>
              )}
        </group>
    );
};

import React, { useRef, useLayoutEffect } from 'react';
import { Text3D } from '@react-three/drei';
import * as THREE from 'three';
import { PartVisibility } from './utils';
import { BackerShape } from '../../types';

interface LetterGroupProps {
    line: string;
    fontUrl: string;
    letterHeight: number;
    depth: number;
    faceThickness: number;
    trimDepth: number;
    returnMaterial: THREE.Material;
    faceMaterial: THREE.Material;
    trimCapMaterial: THREE.Material;
    haloBackerMaterial: THREE.Material;
    mountingBackerMaterial: THREE.Material;
    canMaterial: THREE.Material[];
    invisibleMaterial: THREE.Material;
    glowMats1: any;
    glowMats2: any;
    glowParams1: any;
    glowParams2: any;
    shadowMats: any;
    zOffset1: number;
    zOffset2: number;
    mountZ: number; 
    backerZ: number;
    backerThickness: number;
    isHalo: boolean;
    isFrontLit: boolean;
    isLit: boolean;
    isRaceway: boolean;
    isBackerMount: boolean;
    backerLit: boolean;
    backerShape?: BackerShape;
    backerPadding?: number;
    racewayFaceZ: number;
    wallFaceZ: number;
    visibility: PartVisibility;
    onMeasure?: (width: number) => void;
}

export const LetterGroup: React.FC<LetterGroupProps> = ({ 
    line, fontUrl, letterHeight, depth, faceThickness, trimDepth, 
    returnMaterial, faceMaterial, trimCapMaterial, haloBackerMaterial, mountingBackerMaterial, canMaterial,
    invisibleMaterial,
    glowMats1, glowMats2, glowParams1, glowParams2, shadowMats,
    zOffset1, zOffset2, mountZ, backerZ, backerThickness,
    isHalo, isFrontLit, isLit, isRaceway, isBackerMount, backerLit, backerShape, backerPadding, racewayFaceZ, wallFaceZ,
    visibility,
    onMeasure
}) => {

    const meshRef = useRef<THREE.Mesh>(null);

    useLayoutEffect(() => {
        if (meshRef.current && onMeasure) {
            meshRef.current.geometry.computeBoundingBox();
            const box = meshRef.current.geometry.boundingBox;
            if (box) {
                const width = box.max.x - box.min.x;
                onMeasure(width);
            }
        }
    }, [line, fontUrl, letterHeight, onMeasure]);

    const faceRecess = 0.05;
    const faceZ = depth - faceThickness - faceRecess; 
    const canHeight = Math.max(0.1, depth - faceThickness - faceRecess); 
    const trimLipZ = depth; 
    const trimSideZ = depth - 0.75; 

    const trimStrokeWidth = 0.25; 
    const trimInwardSize = -trimStrokeWidth;
    const trimSideExpansion = 0.03; 

    const LOW_RES_SEGMENTS = 24;

    // Dynamic backer offset logic
    // Default 12.5% if not provided, otherwise use explicit backerPadding
    const backerOffset = backerPadding !== undefined ? backerPadding : (letterHeight * 0.125); 

    const backerPanelThickness = 0.125; 
    const SHADOW_X = 0.2;
    const SHADOW_Y = -0.3;

    // High render order for glows to ensure they draw after raceway writes stencil
    const GLOW_RENDER_ORDER = 100;
    const SHADOW_RENDER_ORDER = 90;

    // Check if we should render the CONTOUR backer here
    // If shape is RECTANGLE, we skip rendering the contour backer + its shadow/glow
    const showContourBacker = isBackerMount && (backerShape === BackerShape.CONTOUR || !backerShape);

    return (
        <group position={[0, 0, mountZ]} castShadow>

            {/* 0. MOUNTING BACKER PANEL (Cloud Shape) & ITS SHADOW */}
            {showContourBacker && (
                <>
                    {/* Backer Shadow on Wall */}
                    <group position={[SHADOW_X, SHADOW_Y, zOffset2]}>
                        <Text3D 
                            font={fontUrl} 
                            size={letterHeight} 
                            height={0} 
                            curveSegments={LOW_RES_SEGMENTS} 
                            bevelEnabled 
                            bevelThickness={0} 
                            bevelSize={backerOffset} 
                            material={shadowMats.wallCore} 
                            renderOrder={SHADOW_RENDER_ORDER - 10} 
                        >
                            {line}
                        </Text3D>
                        <Text3D 
                            font={fontUrl} 
                            size={letterHeight} 
                            height={0} 
                            curveSegments={LOW_RES_SEGMENTS} 
                            bevelEnabled 
                            bevelThickness={0} 
                            bevelSize={backerOffset + 0.3} 
                            material={shadowMats.wallMid} 
                            renderOrder={SHADOW_RENDER_ORDER - 10}
                        >
                            {line}
                        </Text3D>
                        <Text3D 
                            font={fontUrl} 
                            size={letterHeight} 
                            height={0} 
                            curveSegments={LOW_RES_SEGMENTS} 
                            bevelEnabled 
                            bevelThickness={0} 
                            bevelSize={backerOffset + 0.8} 
                            material={shadowMats.wallOuter} 
                            renderOrder={SHADOW_RENDER_ORDER - 10}
                        >
                            {line}
                        </Text3D>
                    </group>

                    <group position={[0, 0, -0.5]}> 
                         <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={backerPanelThickness}
                            position={[0, 0, -0.25]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0} 
                            bevelSize={backerOffset} 
                            material={mountingBackerMaterial} 
                            visible={visibility.backers}
                            renderOrder={5}
                         >
                            {line}
                         </Text3D>

                         {backerLit && (
                            <group position={[0, 0, zOffset2 - (-0.5)]}> 
                                <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 0.5} material={glowMats2.core} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                                <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 2.0} material={glowMats2.mid} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                                <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={backerOffset + 6.0} material={glowMats2.outer} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                            </group>
                         )}
                    </group>
                </>
            )}

            {/* 1. CAST SHADOWS (Letters) */}
            {/* Primary Shadow (Clipped if Raceway, Normal if Wall or Backer) */}
            <group position={[SHADOW_X, SHADOW_Y, zOffset1]}>
               <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0} material={isRaceway ? shadowMats.clippedCore : shadowMats.wallCore} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
               <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.2} material={isRaceway ? shadowMats.clippedMid : shadowMats.wallMid} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
               <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.5} material={isRaceway ? shadowMats.clippedOuter : shadowMats.wallOuter} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
            </group>

            {/* Secondary Wall Shadow (Only if Raceway, to catch ascenders/descenders) */}
            {isRaceway && (
               <group position={[SHADOW_X, SHADOW_Y, zOffset2]}>
                  <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0} material={shadowMats.wallCore} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
                  <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.2} material={shadowMats.wallMid} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
                  <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={0.5} material={shadowMats.wallOuter} renderOrder={SHADOW_RENDER_ORDER}>{line}</Text3D>
               </group>
            )}

            {/* 2. THE CAN (Returns) */}
            <Text3D
              ref={meshRef}
              font={fontUrl}
              size={letterHeight}
              height={canHeight}
              curveSegments={12}
              bevelEnabled={true}
              bevelThickness={0} 
              bevelSize={0}
              material={canMaterial}
              visible={visibility.returns}
              renderOrder={10}
            >
              {line}
            </Text3D>

            {/* 3. FACE ASSEMBLY */}
            <Text3D
                font={fontUrl}
                size={letterHeight}
                height={faceThickness}
                position={[0, 0, faceZ]} 
                curveSegments={12}
                bevelEnabled={true}
                bevelThickness={0} 
                bevelSize={isFrontLit ? -0.23 : 0} 
                material={faceMaterial} 
                visible={visibility.faces}
                renderOrder={15}
            >
                {line}
            </Text3D>

            {/* 4. TRIM CAP */}
            {isFrontLit && (
                <group>
                    <group visible={visibility.trimCapFaces}>
                        <Text3D
                            font={fontUrl}
                            size={letterHeight}
                            height={0.04} 
                            position={[0, 0, trimLipZ]}
                            curveSegments={12}
                            bevelEnabled={true}
                            bevelThickness={0.001} 
                            bevelSize={trimInwardSize}
                            material={[invisibleMaterial, trimCapMaterial]}
                            renderOrder={20}
                        >
                            {line}
                        </Text3D>
                    </group>
                    <Text3D
                        font={fontUrl}
                        size={letterHeight}
                        height={0.75} 
                        position={[0, 0, trimSideZ]} 
                        curveSegments={12}
                        bevelEnabled={true}
                        bevelThickness={0}
                        bevelSize={trimSideExpansion}
                        material={[invisibleMaterial, trimCapMaterial]}
                        visible={visibility.trimCapSides}
                        renderOrder={25}
                    >
                        {line}
                    </Text3D>
                </group>
            )}

            {/* 5. HALO LIT FACE (Rear Poly) & GLOW */}
            {isHalo && (
            <group>
                <Text3D
                  font={fontUrl}
                  size={letterHeight}
                  height={backerThickness}
                  position={[0, 0, backerZ]} 
                  curveSegments={12}
                  bevelEnabled={true} 
                  bevelThickness={0}
                  bevelSize={-0.05} 
                  material={haloBackerMaterial}
                  visible={visibility.backers}
                >
                  {line}
                </Text3D>

                {isLit && (
                  <>
                    {/* Primary Glow (Raceway Clipped or Wall) */}
                    <group position={[0, 0, zOffset1 + 0.01]}>
                        <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.core} material={glowMats1.core} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.mid} material={glowMats1.mid} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                        <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams1.sizes.outer} material={glowMats1.outer} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                    </group>

                    {/* Secondary Wall Glow (If Raceway) */}
                    {isRaceway && (
                        <group position={[0, 0, zOffset2]}>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.core} material={glowMats2.core} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.mid} material={glowMats2.mid} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                            <Text3D font={fontUrl} size={letterHeight} height={0} curveSegments={LOW_RES_SEGMENTS} bevelEnabled bevelThickness={0} bevelSize={glowParams2.sizes.outer} material={glowMats2.outer} renderOrder={GLOW_RENDER_ORDER}>{line}</Text3D>
                        </group>
                    )}
                  </>
                )}
            </group>
            )}
        </group>
    )
}

import React, { useRef, useMemo } from 'react';
import * as THREE from 'three';
import { SignConfig, MountType, IlluminationType, BackerShape } from '../../types';
import { FONT_LIBRARY } from '../../constants';
import { SignLine } from './SignLine';
import { useSignMaterials } from './useSignMaterials';
import { PartVisibility } from './utils';

interface ChannelLetterRendererProps {
  config: SignConfig;
  ledIntensity: number;
  shadowIntensity: number;
  partVisibility?: PartVisibility;
  onUpdateLength?: (index: number, length: number) => void;
}

export const ChannelLetterRenderer: React.FC<ChannelLetterRendererProps> = ({ config, ledIntensity, shadowIntensity, partVisibility, onUpdateLength }) => {

  const selectedFont = FONT_LIBRARY[config.fontFamily as keyof typeof FONT_LIBRARY] || Object.values(FONT_LIBRARY)[0];
  const fontSource = selectedFont.font; 
  const widthFactor = selectedFont.widthFactor;

  const isHalo = config.illumination === IlluminationType.HALO_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isFrontLit = config.illumination === IlluminationType.FRONT_LIT || config.illumination === IlluminationType.DUAL_LIT;
  const isLit = config.illumination !== IlluminationType.NON_ILLUMINATED;

  // New Logic: If lights are active and it involves Halo lighting, disable shadows to prevent visual conflict.
  const lightsOn = ledIntensity > 0.1;
  const effectiveShadowIntensity = (isHalo && lightsOn) ? 0 : shadowIntensity;

  const materials = useSignMaterials(config, ledIntensity, effectiveShadowIntensity);

  const letterHeight = config.dimensions.height;
  const rowGap = config.dimensions.lineSpacing !== undefined ? config.dimensions.lineSpacing : (letterHeight * 0.2);
  const lineHeight = letterHeight + rowGap;

  const depth = config.dimensions.depth;
  const trimDepth = 0.75; 
  const racewayH = 6;
  const racewayD = 4;
  const racewayOffset = config.dimensions.racewayOffset || 0;

  const WALL_Z = -0.5;
  const BACKER_THICK = 0.125;

  let mountZ = 0; 
  let targetSurfaceZ = WALL_Z; 
  let backerFaceZ = WALL_Z;

  if (config.mount === MountType.RACEWAY) {
      mountZ = racewayD; 
      targetSurfaceZ = racewayD; 
  } 
  else if (config.mount === MountType.BACKER) {
      const mStandoff = config.dimensions.standoff || 0;
      const lStandoff = config.dimensions.letterStandoff || 0;

      backerFaceZ = WALL_Z + mStandoff + BACKER_THICK;
      mountZ = backerFaceZ + lStandoff;
      targetSurfaceZ = backerFaceZ;
  } 
  else {
      const standoff = config.dimensions.standoff || 0;
      mountZ = WALL_Z + standoff;
      targetSurfaceZ = WALL_Z; 
  }

  const zOffset1 = (targetSurfaceZ - mountZ) + 0.05; 
  const zOffset2 = (WALL_Z - mountZ) + 0.05; 

  // Glow Logic - Intensity Boosted for visibility
  const baseGlowOpacity = (ledIntensity / 5) * 2.5;

  // Distance from Light Source (Letter Back) to Target Surface
  const distToTarget1 = Math.abs(mountZ - targetSurfaceZ);

  // Distance from Light Source to Wall (For secondary glow in Raceway mode)
  const distToTarget2 = Math.abs(mountZ - WALL_Z);

  const getGlowParams = (distance: number) => {
    const d = Math.max(0.1, distance);
    const spread = 1 + (d * 0.6);
    const sizes = { core: 0.05 * spread, mid: 0.25 * spread, outer: 0.8 * spread };
    const opacityFactor = 1 / (1 + (d * 0.15));
    return { sizes, opacityFactor };
  };

  // Params 1: Primary Surface (Raceway or Backer or Wall)
  const params1 = getGlowParams(distToTarget1);
  // Params 2: Wall (Used for Secondary Glow in Raceway mode)
  const params2 = getGlowParams(distToTarget2);

  const { mats1, mats2 } = useMemo(() => {
    const createGlowMats = (opacityFactor: number, useStencil: boolean = false) => {
        const stencilProps = useStencil ? {
            stencilWrite: true, 
            stencilRef: 5, // Corrected to match Raceway ID
            stencilFunc: THREE.EqualStencilFunc,
            stencilFail: THREE.KeepStencilOp, 
            stencilZFail: THREE.KeepStencilOp, 
            stencilZPass: THREE.KeepStencilOp,
        } : {};
        return {
            core: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            mid: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.5 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps }),
            outer: new THREE.MeshBasicMaterial({ color: materials.ledHex, transparent: true, opacity: baseGlowOpacity * 0.2 * opacityFactor, blending: THREE.AdditiveBlending, side: THREE.FrontSide, depthWrite: false, ...stencilProps })
        };
    };
    return { 
        mats1: createGlowMats(params1.opacityFactor, config.mount === MountType.RACEWAY),
        mats2: createGlowMats(params2.opacityFactor, false)
    };
  }, [materials.ledHex, baseGlowOpacity, params1.opacityFactor, params2.opacityFactor, config.mount]);

  const backerZ = isHalo ? 0.1 : 0; 
  const backerThickness = config.backerThickness; 

  const activeIndices = config.lines.map((l, i) => l ? i : -1).filter(i => i !== -1);
  const minIdx = activeIndices.length > 0 ? Math.min(...activeIndices) : 0;
  const maxIdx = activeIndices.length > 0 ? Math.max(...activeIndices) : 0;
  const centerLineIndex = (minIdx + maxIdx) / 2;

  const vis = partVisibility || { faces: true, trimCapSides: true, trimCapFaces: true, returns: true, backers: true, raceway: true };
  const meshRef = useRef<THREE.Group>(null);

  // Rectangle Backer Geometry Calculation
  const isRectBacker = config.mount === MountType.BACKER && config.backerShape === BackerShape.RECTANGLE;

  // Requirement: Taller/Wider than letters by 12.5%
  // Scale factor = 1.125
  const SCALE_FACTOR = 1.125;
  const rectWidth = config.dimensions.calculatedWidth * SCALE_FACTOR;

  const numActiveLines = activeIndices.length || 1;
  const textBlockHeight = (numActiveLines * letterHeight) + ((numActiveLines - 1) * rowGap);
  const rectHeight = textBlockHeight * SCALE_FACTOR;

  // Vertical Centering: Text block is centered around letterHeight/2 in the Group local space
  // See: yPosition logic aligns baseline such that average center is letterHeight/2.
  const rectY = letterHeight / 2;

  return (
    <group ref={meshRef} position={[0, 0, 0]}>
      {/* Rectangular Backer Panel */}
      {isRectBacker && (
          <group position={[0, rectY, backerFaceZ - (BACKER_THICK/2)]} visible={vis.backers}>
              {/* Panel Body */}
              <mesh>
                  <boxGeometry args={[rectWidth, rectHeight, BACKER_THICK]} />
                  <primitive object={materials.mountingBackerMaterial} />
              </mesh>

              {/* Panel Shadow on Wall */}
              <mesh position={[0.2, -0.3, -((config.dimensions.standoff || 0) + 0.05)]}>
                  <planeGeometry args={[rectWidth, rectHeight]} />
                  <meshBasicMaterial color="black" transparent opacity={shadowIntensity * 0.5} />
              </mesh>

              {/* Halo Glow Behind Rectangle */}
              {config.backerLit && lightsOn && (
                  <group position={[0, 0, -BACKER_THICK/2 - 0.1]}>
                     <mesh>
                         <planeGeometry args={[rectWidth * 1.05, rectHeight * 1.05]} />
                         <primitive object={mats2.core} />
                     </mesh>
                     <mesh position={[0,0,-0.1]}>
                         <planeGeometry args={[rectWidth * 1.2, rectHeight * 1.2]} />
                         <primitive object={mats2.mid} />
                     </mesh>
                     <mesh position={[0,0,-0.2]}>
                         <planeGeometry args={[rectWidth * 1.5, rectHeight * 1.5]} />
                         <primitive object={mats2.outer} />
                     </mesh>
                  </group>
              )}
          </group>
      )}

      {config.lines.map((line, i) => {
        if (!line) return null;
        const yPosition = (centerLineIndex - i) * lineHeight;
        return (
          <SignLine
            key={i}
            line={line}
            index={i}
            config={config}
            yPosition={yPosition}
            fontUrl={fontSource as string} 
            letterHeight={letterHeight}
            widthFactor={widthFactor}
            depth={depth}
            faceThickness={config.faceThickness}
            trimDepth={trimDepth}
            returnMaterial={materials.returnMaterial}
            faceMaterial={materials.faceMaterial}
            trimCapMaterial={materials.trimCapMaterial}
            haloBackerMaterial={materials.haloBackerMaterial}
            mountingBackerMaterial={materials.mountingBackerMaterial}
            canMaterial={materials.canMaterial}
            invisibleMaterial={materials.invisibleMaterial}
            glowMats1={mats1}
            glowMats2={mats2}
            glowParams1={params1}
            glowParams2={params2}
            shadowMats={materials.shadowMats}
            zOffset1={zOffset1}
            zOffset2={zOffset2}
            mountZ={mountZ}
            backerZ={backerZ}
            backerThickness={backerThickness}
            racewayFaceZ={racewayD}
            wallFaceZ={WALL_Z}
            isHalo={isHalo}
            isFrontLit={isFrontLit}
            isLit={isLit}
            isRaceway={config.mount === MountType.RACEWAY}
            isBackerMount={config.mount === MountType.BACKER}
            backerLit={config.backerLit}
            backerShape={config.backerShape} // Pass new props
            backerPadding={config.backerPadding} // Pass new props
            racewayColor={config.colors.raceway.startsWith('#') ? config.colors.raceway : '#333333'} 
            racewayOffset={racewayOffset}
            racewayH={racewayH}
            racewayD={racewayD}
            shadowIntensity={effectiveShadowIntensity}
            visibility={vis}
            onUpdateLength={onUpdateLength}
          />
        );
      })}
    </group>
  );
};
